const cfg = loadConfig();
const program = new Command();
const CONTROL_PLANE_PROVIDER_HELP = `control-plane provider: ${SERVE_CONTROL_PLANE_PROVIDERS.join("|")}`;
const CONTROL_PLANE_GIT_TRANSPORT_SAMPLE_REPO = "team/smoke";
const DEFAULT_GITEA_TOKEN_ENV = "LOOM_GITEA_TOKEN";
const AGENT_GIT_SERVICE_URL_ENV = "LOOM_AGENT_GIT_SERVICE_URL";
const DEFAULT_AGENT_GIT_SERVICE_TOKEN_ENV = "LOOM_AGENT_GIT_SERVICE_TOKEN";
const DEFAULT_AGENT_GIT_SERVICE_STAGING_ISSUE = "team/loom-smoke#17";
const PLATFORM_CONCURRENCY_ADMISSION_SCHEMA_VERSION = "loom-concurrency-admission/v1";
const PLATFORM_CONCURRENCY_ADMISSION_BLOCKED_REASONS = ["tenant_active_run_limit", "project_active_workspace", "persisted_running_run"];
const HARNESS_PLATFORM_STAGING_TARGET_INPUT_FIELD_NAMES = [
  "modelGatewayBaseUrl",
  "agentGitServiceBaseUrl",
  "agentGitServiceIssue",
  "agentGitServiceRepo",
  "agentGitServiceNativeWriteAttachmentUrl",
] as const;

type HarnessPlatformStagingTargetsInputFieldName = typeof HARNESS_PLATFORM_STAGING_TARGET_INPUT_FIELD_NAMES[number];

program
  .name("loom")
  .description(
    "Operator CLI for a v3 cloud agentic dev platform.\n" +
      "Runs a first-party harness loop, keeps a native /goal adapter,\n" +
      "and feeds the skill-evolution brain.",
  )
  .version("0.1.0");

// --- outer infra ---
const ws = program.command("workspace").description("per-dev persistent workspace");
ws.command("create <name>").description("create a workspace container + persistent volume").action(
  (n: string) => workspaceCreate(cfg, n),
);

const pj = program.command("project").description("projects inside a workspace");
pj.command("add <repo>").description("clone a Gitea repo into the workspace").action(
  (r: string) => projectAdd(cfg, r),
);

// --- the loop: delegated to native /goal ---
program
  .command("goal <condition>")
  .description("run a NATIVE /goal in a project worktree (the loop is delegated, not reimplemented)")
  .requiredOption("-p, --project <name>")
  .option("-w, --worktree <id>", "task worktree id", "main")
  .option("-t, --tier <tier>", "model tier: default|reasoning|cheap", "default")
  .option("--issue <owner/repo#number>", "Gitea/Forgejo issue to link in native goal context")
  .option("--skill <name>", "skill active in this native goal run; repeatable", collect, [] as string[])
  .action(async (condition: string, opts: { project: string; worktree: string; tier: string; issue?: string; skill: string[] }) => {
    const code = await runGoal(cfg, {
      condition,
      project: opts.project,
      worktree: opts.worktree,
      issue: opts.issue ? cliIssueRef(opts.issue, "--issue") : undefined,
      skills: opts.skill,
      modelTier: opts.tier as "default" | "reasoning" | "cheap",
    });
    process.exit(code);
  });

// --- the brain: compounding skill improvement ---
const brain = program.command("brain").description("skill-evolution brain (git-backed)");
brain
  .command("ingest")
  .description("record a run signal (JSON on stdin)")
  .action(async () => {
    const raw = await readStdin();
    ingest(cfg, JSON.parse(raw) as RunSignal);
  });
brain
  .command("score")
  .description("aggregate signals → per-skill success rate")
  .action(() => console.log(JSON.stringify(score(cfg), null, 2)));
brain
  .command("propose")
  .option("--threshold <n>", "min success rate", "0.6")
  .option("--min-runs <n>", "minimum runs before proposing", "5")
  .option("--gitea-pr", "push proposal branches and open Gitea/Forgejo PRs", false)
  .option("--gitea-repo <owner/repo>", "skills repository for Gitea/Forgejo PRs")
  .option("--gitea-base <branch>", "base branch for Gitea/Forgejo PRs", "main")
  .option("--git-remote <name>", "git remote used when --gitea-pr pushes proposal branches", "origin")
  .option("--gitea-url <url>", "Gitea/Forgejo base URL", cfg.giteaUrl)
  .option("--gitea-token-env <name>", "env var containing the Gitea/Forgejo token", "LOOM_GITEA_TOKEN")
  .description("open git-backed improvement PRs for weak skills")
  .action(async (o: { threshold: string; minRuns: string; giteaPr: boolean; giteaRepo?: string; giteaBase: string; gitRemote: string; giteaUrl: string; giteaTokenEnv: string }) => {
    const threshold = parsePositiveNumberFlag(o.threshold, "--threshold");
    const minRuns = parsePositiveIntFlag(o.minRuns, "--min-runs");
    const pullRequests: Array<{ branch: string; index?: number; url?: string }> = [];
    if (o.giteaPr && !o.giteaRepo?.trim()) {
      console.error("--gitea-pr requires --gitea-repo.");
      process.exit(2);
    }
    const token = o.giteaPr ? process.env[o.giteaTokenEnv] : undefined;
    if (o.giteaPr && !token) {
      console.error(`--gitea-token-env ${o.giteaTokenEnv} is required when --gitea-pr is used.`);
      process.exit(2);
    }
    const proposalPrProvider = controlPlaneProviderAdapter("gitea-forgejo");
    if (!proposalPrProvider) throw new Error("unsupported control-plane provider: gitea-forgejo");
    const branches = await propose(cfg, {
      threshold,
      minRuns,
      pushRemote: o.giteaPr ? o.gitRemote : undefined,
      publish: o.giteaPr
        ? async (proposal) => {
            const pullRequest = await proposalPrProvider.createPullRequest({
              baseUrl: o.giteaUrl,
              token: token as string,
              repo: o.giteaRepo as string,
              head: proposal.branch,
              base: o.giteaBase,
              title: proposal.pullRequestTitle,
              body: proposal.pullRequestBody,
            });
            pullRequests.push({ branch: proposal.branch, ...pullRequest });
            return pullRequest;
          }
        : undefined,
    });
    if (!branches.length) {
      console.log("No weak skills past threshold.");
      return;
    }
    if (pullRequests.length) {
      console.log(`Opened:\n${pullRequests.map((pr) => `${pr.branch}${pr.url ? ` -> ${pr.url}` : ""}`).join("\n")}`);
      return;
    }
    console.log(`Opened:\n${branches.join("\n")}`);
  });

program
  .command("hooks-install")
  .description("install the Claude Code Stop hook → brain")
  .action(() => hooksInstall());

// --- first-party OpenHands-lite harness loop ---
const harness = program.command("harness").description("first-party auditable harness loop");
harness
  .command("run <goal>")
  .description("run the OpenHands-lite event loop with tool execution and verification gate")
  .option("--cwd <path>", "workspace directory", process.cwd())
  .option("--run-root <path>", "run artifact root; defaults to <cwd>/.loom/runs")
  .option("--script <path>", "scripted agent steps JSON")
  .option("--agent-command <command>", "external agent command that reads JSON on stdin and returns one AgentStep JSON")
  .option("--model <name>", "OpenAI-compatible model name routed through LiteLLM")
  .option("--model-base-url <url>", "OpenAI-compatible base URL", cfg.gatewayUrl)
  .option("--model-key-env <name>", "env var containing the model API key", cfg.gatewayKeyEnv)
  .option("--model-protocol <protocol>", "model agent protocol: json|tool-call", "json")
  .option("--executor <kind>", "workspace executor: local|docker|coder", "local")
  .option("--executor-image <image>", "Docker image when --executor docker is used")
  .option("--executor-network <mode>", "Docker network mode for --executor docker")
  .option("--executor-cpus <count>", "Docker CPU limit, or Coder cpus template parameter")
  .option("--executor-memory <size>", "Docker memory limit, or Coder memory_gb template parameter")
  .option("--executor-pids-limit <count>", "Docker pids limit, or Coder pids_limit template parameter")
  .option("--executor-home-root <path>", "persistent Docker home root; mounts <path>/<tenant> at /home/dev")
  .option("--executor-workspace <name>", "Coder workspace name or template when --executor coder is used")
  .option("--executor-remote-cwd <path>", "remote cwd or template for --executor coder", "/home/dev/projects/{project}")
  .option("--executor-worktree-cwd <path>", "remote run worktree cwd template for --executor coder")
  .option("--executor-template <name>", "Coder template to create a missing workspace")
  .option("--executor-template-param <name=value>", "Coder template parameter for missing workspace creation; repeatable", collect, [] as string[])
  .option("--executor-ide-url <url>", "browser IDE URL template for --executor coder")
  .option("--executor-preview-url <url>", "browser preview URL template for apps running in --executor coder")
  .option("--repo <url>", "repository URL to sync before the run")
  .option("--branch <name>", "git branch to check out after syncing --repo")
  .option("--base-branch <name>", "base git branch used when creating --branch", "origin/main")
  .option("--public-url <url>", "public harness server URL used in run metadata links")
  .option("--issue <owner/repo#number>", "Gitea/Forgejo issue to link in run metadata")
  .option("--require-review", "hold successful verification at review_required until a human reviews it", false)
  .option("--require-deployment", "hold successful verification at deployment_required until an admin approves deployment", false)
  .option("--gitea-pr", "create a Gitea/Forgejo pull request for --issue and --branch", false)
  .option("--gitea-comment", "post the final run summary to --issue as a Gitea/Forgejo comment", false)
  .option("--gitea-url <url>", "Gitea/Forgejo base URL", cfg.giteaUrl)
  .option("--gitea-token-env <name>", "env var containing the Gitea/Forgejo token", "LOOM_GITEA_TOKEN")
  .option("--verify <command>", "verification command; repeatable", collect, [] as string[])
  .option("--evaluate <command>", "independent evaluator command after verification; repeatable", collect, [] as string[])
  .option("--reviewer <command>", "non-gating reviewer command after verification/evaluation; repeatable", collect, [] as string[])
  .option("--skill <name>", "skill active in this run; repeatable", collect, [] as string[])
  .option("--max-iterations <n>", "maximum loop iterations", "20")
  .option("--ingest-brain", "append this run outcome to the git-backed brain", false)
  .action(
    async (
      goal: string,
      opts: {
        cwd: string;
        runRoot?: string;
        script?: string;
        agentCommand?: string;
        model?: string;
        modelBaseUrl: string;
        modelKeyEnv: string;
        modelProtocol: string;
        executor: string;
        executorImage?: string;
        executorNetwork?: string;
        executorCpus?: string;
        executorMemory?: string;
        executorPidsLimit?: string;
        executorWorkspace?: string;
        executorRemoteCwd: string;
        executorWorktreeCwd?: string;
        executorTemplate?: string;
        executorTemplateParam: string[];
        executorIdeUrl?: string;
        executorPreviewUrl?: string;
        repo?: string;
        branch?: string;
        baseBranch: string;
        publicUrl?: string;
        issue?: string;
        requireReview: boolean;
        requireDeployment: boolean;
        giteaPr: boolean;
        giteaComment: boolean;
        giteaUrl: string;
        giteaTokenEnv: string;
        verify: string[];
        evaluate: string[];
        reviewer: string[];
        skill: string[];
        maxIterations: string;
        ingestBrain: boolean;
      },
    ) => {
      if (!opts.script && !opts.agentCommand && !opts.model) {
        console.error("Either --script, --agent-command, or --model is required for harness run.");
        process.exit(2);
      }
      if (opts.giteaPr && (!opts.issue || !opts.branch)) {
        console.error("--gitea-pr requires --issue and --branch.");
        process.exit(2);
      }

      const source = parseHarnessRunSourceOptions(opts);
      const createExecutor = executorFactoryFromOptions(opts);
      const runId = makeRunId();
      const project = basename(opts.cwd);
      const agentMode = opts.script ? "script" : opts.agentCommand ? "command" : "model";
      const modelProtocol = parseModelProtocolFlag(opts.modelProtocol, "--model-protocol");
      const metadata = runMetadata({
        tenant: "local",
        project,
        repo: source.repo,
        branch: source.branch,
        baseBranch: source.baseBranch,
        issue: source.issue,
        issueUrl: source.issue ? giteaIssueUrl(opts.giteaUrl, source.issue) : undefined,
        dashboardUrl: opts.publicUrl ? runDashboardUrl(opts.publicUrl, "local", project, runId) : undefined,
        summaryUrl: opts.publicUrl ? runUrl(opts.publicUrl, "local", project, runId) : undefined,
        agentMode,
        model: agentMode === "model" ? opts.model : undefined,
        modelProtocol: agentMode === "model" && modelProtocol !== "json" ? modelProtocol : undefined,
      });
      const agent = opts.script
        ? await createScriptedAgent(opts.script)
        : opts.agentCommand
          ? createCommandAgent(opts.agentCommand, opts.cwd)
          : createOpenAiCompatibleAgent({
              baseUrl: opts.modelBaseUrl,
              model: opts.model as string,
              protocol: modelProtocol,
              apiKey: process.env[opts.modelKeyEnv],
            });
      const summary = await runHarness({
        runId,
        goal,
        cwd: opts.cwd,
        runRoot: opts.runRoot ?? join(opts.cwd, ".loom", "runs"),
        verifyCommands: opts.verify,
        evaluationCommands: opts.evaluate,
        reviewerCommands: opts.reviewer,
        agent,
        skills: opts.skill,
        metadata,
        reviewRequired: opts.requireReview,
        deploymentRequired: opts.requireDeployment,
        maxIterations: Number(opts.maxIterations),
        executor: createExecutor?.(opts.cwd, {
          tenant: "local",
          project,
          runId,
          cwd: opts.cwd,
          repo: source.repo,
          branch: source.branch,
          baseBranch: source.baseBranch,
        }),
      });
      const reported = await finalizeSummary(summary, maybePullRequestReporter(opts), maybeIssueReporter(opts));

      if (opts.ingestBrain) {
        ingest(cfg, runSignalFromSummary(reported, basename(opts.cwd)));
      }

      console.log(JSON.stringify(reported, null, 2));
      process.exit(reported.status === "failed" || reported.status === "error" ? 1 : 0);
    },
  );
harness
  .command("provision-agent-git-service")
  .description("call the harness admin API to provision an agent-git-service project agent")
  .option("--url <url>", "harness server base URL", "http://127.0.0.1:8787")
  .requiredOption("--tenant <tenant>", "tenant that owns the project")
  .requiredOption("--project <project>", "project to provision")
  .requiredOption("--repo <owner/repo>", "agent-git-service repository to grant")
  .option("--admin-token <token>", "tenant admin API token; prefer --admin-token-env for shared shells")
  .option("--admin-token-env <name>", "env var containing the tenant admin API token")
  .option("--permission <permission>", "repo permission: read|write|admin")
  .option("--agent-prefix-login <name>", "agent login prefix sent to AGS")
  .option("--default-repo-name <name>", "default AGS workspace repository name")
  .option("--token-env-name <name>", "non-secret env name where operators will store the returned agent token")
  .option("--identity-actor <actor>", "tenant actor to map the new AGS agent login to")
  .option("--identity-role <role>", "tenant role for the mapped AGS agent login: viewer|developer|admin")
  .option("--store-agent-token", "ask the harness server to store the generated agent token in its configured secret root", false)
  .option("--force", "re-provision even when a receipt already exists", false)
  .option("--client-id <id>", "client id for audit evidence", "cli")
  .action(async (opts: HarnessAgentGitServiceProvisionCliOptions) => {
    try {
      const result = await provisionAgentGitServiceProjectAgentViaHarness(opts);
      console.log(JSON.stringify(result, null, 2));
    } catch (error) {
      console.error(error instanceof Error ? error.message : String(error));
      process.exitCode = 1;
    }
  });
harness
  .command("agent-git-service-provisioning-plan")
  .description("read the tenant agent-git-service provisioning plan from the harness admin API")
  .option("--url <url>", "harness server base URL", "http://127.0.0.1:8787")
  .requiredOption("--tenant <tenant>", "tenant to inspect")
  .option("--admin-token <token>", "tenant admin API token; prefer --admin-token-env for shared shells")
  .option("--admin-token-env <name>", "env var containing the tenant admin API token")
  .action(async (opts: HarnessAgentGitServiceProvisioningPlanCliOptions) => {
    try {
      const result = await readAgentGitServiceProvisioningPlanViaHarness(opts);
      console.log(JSON.stringify(result, null, 2));
    } catch (error) {
      console.error(error instanceof Error ? error.message : String(error));
      process.exitCode = 1;
    }
  });
harness
  .command("apply-agent-git-service-provisioning-plan")
  .description("apply the tenant agent-git-service provisioning plan through the harness admin API")
  .option("--url <url>", "harness server base URL", "http://127.0.0.1:8787")
  .requiredOption("--tenant <tenant>", "tenant to apply")
  .option("--admin-token <token>", "tenant admin API token; prefer --admin-token-env for shared shells")
  .option("--admin-token-env <name>", "env var containing the tenant admin API token")
  .option("--projects <projects>", "comma-separated project names to apply; defaults to every eligible project")
  .option("--eligible-only", "send only plan-eligible projects instead of including ready/skipped projects in the result", false)
  .option("--dry-run", "show projects that would be provisioned without calling AGS", false)
  .option("--client-id <id>", "client id for audit evidence", "cli")
  .action(async (opts: HarnessAgentGitServiceProvisioningPlanApplyCliOptions) => {
    try {
      const result = await applyAgentGitServiceProvisioningPlanViaHarness(opts);
      console.log(JSON.stringify(result, null, 2));
    } catch (error) {
      console.error(error instanceof Error ? error.message : String(error));
      process.exitCode = 1;
    }
  });
harness
  .command("coder-preflight")
  .description("probe a real Coder workspace path before running the full platform smoke")
  .option("--workspace-root <path>", "tenant workspace root used for template context", process.cwd())
  .requiredOption("--tenant <tenant>", "tenant used to render executor templates")
  .requiredOption("--project <project>", "project used to render executor templates")
  .requiredOption("--executor-workspace <name>", "Coder workspace name or template")
  .option("--executor-remote-cwd <path>", "remote project cwd template", "/home/dev/projects/{project}")
  .option("--executor-worktree-cwd <path>", "remote run worktree cwd template")
  .option("--executor-template <name>", "Coder template to create missing tenant workspaces")
