function platformCutoverExternalEnvironment(
  options: HarnessServeCliOptions,
  context: {
    tenant: string;
    isolationTenant?: string;
    tokenEnv?: string;
    viewerTokenEnv?: string;
    adminTokenEnv?: string;
    agentGitServiceStaging?: HarnessPlatformCutoverExternalEnvironment["systems"]["agentGitServiceStaging"];
  },
): HarnessPlatformCutoverExternalEnvironment {
  const provider = parseControlPlaneProviderFlag(options.controlPlaneProvider, "--control-plane-provider");
  const requiredVariables = new Map<string, HarnessPlatformCutoverEnvironmentVariable>();
  const tenant = context.tenant;
  const isolationTenant = context.isolationTenant === undefined
    ? undefined
    : parseSafeNameFlag(context.isolationTenant, "--isolation-tenant");
  const tenantControlPlaneTokenEnvNames = [
    ...platformCutoverTenantEnvRefs(options.tenantControlPlaneTokenEnv ?? [], "--tenant-control-plane-token-env"),
    ...(provider === "gitea-forgejo"
      ? platformCutoverTenantEnvRefs(options.tenantGiteaTokenEnv ?? [], "--tenant-gitea-token-env")
      : []),
  ];
  const controlPlaneTokenEnv = controlPlanePreflightTokenEnv({
    controlPlaneProvider: provider,
    controlPlaneTokenEnv: options.controlPlaneTokenEnv,
  }, provider);
  const controlPlaneWebhookSecretEnv = options.controlPlaneWebhookSecretEnv ?? options.giteaWebhookSecretEnv;
  const controlPlaneWebhookSecretFlag = options.controlPlaneWebhookSecretEnv
    ? "--control-plane-webhook-secret-env"
    : "--gitea-webhook-secret-env";

  addPlatformCutoverRequiredEnv(requiredVariables, options.modelKeyEnv, ["platform-preflight", "serve", "smoke"], {
    sourceFlag: "--model-key-env",
    purpose: "OpenAI-compatible model gateway API key",
  });
  addPlatformCutoverRequiredEnv(requiredVariables, context.tokenEnv, ["cutover-report", "smoke"], {
    sourceFlag: "--token-env",
    purpose: "developer tenant API token",
    tenant,
  });
  addPlatformCutoverRequiredEnv(requiredVariables, context.viewerTokenEnv, ["smoke"], {
    sourceFlag: "--viewer-token-env",
    purpose: "viewer tenant API token",
    tenant,
  });
  addPlatformCutoverRequiredEnv(
    requiredVariables,
    context.adminTokenEnv,
    provider === "agent-git-service"
      ? ["cutover-report", "agent-git-service-provisioning", "smoke"]
      : ["cutover-report", "smoke"],
    {
      sourceFlag: "--admin-token-env",
      purpose: "admin tenant API token",
      tenant,
    },
  );
  addPlatformCutoverRequiredEnv(requiredVariables, controlPlaneWebhookSecretEnv, ["platform-preflight", "serve", "smoke"], {
    sourceFlag: controlPlaneWebhookSecretFlag,
    purpose: "signed control-plane issue-comment webhook secret",
  });
  addPlatformCutoverRequiredEnv(
    requiredVariables,
    controlPlaneTokenEnv,
    provider === "agent-git-service"
      ? [
          "platform-preflight",
          "agent-git-service-compat-rehearsal",
          "agent-git-service-staging-readiness",
          "serve",
          "agent-git-service-native-write-check",
        ]
      : ["platform-preflight", "serve"],
    {
    sourceFlag: provider === "gitea-forgejo" && !options.controlPlaneTokenEnv ? "--gitea-token-env" : "--control-plane-token-env",
    purpose: `${provider} control-plane token`,
    },
  );
  for (const ref of tenantControlPlaneTokenEnvNames) {
    addPlatformCutoverRequiredEnv(requiredVariables, ref.envName, ["platform-preflight", "serve"], {
      sourceFlag: ref.sourceFlag,
      purpose: "tenant-scoped control-plane agent token",
      tenant: ref.tenant,
    });
  }
  for (const key of platformCutoverTenantApiKeyEnvRefs(options.tenantKeyEnv ?? [])) {
    addPlatformCutoverRequiredEnv(requiredVariables, key.envName, ["platform-preflight", "serve"], {
      sourceFlag: "--tenant-key-env",
      purpose: "tenant API key",
      tenant: key.tenant,
      actor: key.actor,
      role: key.role,
    });
  }
  for (const key of platformCutoverTenantEnvRefs(options.tenantModelKey ?? [], "--tenant-model-key")) {
    addPlatformCutoverRequiredEnv(requiredVariables, key.envName, ["serve", "smoke"], {
      sourceFlag: "--tenant-model-key",
      purpose: "tenant-scoped model gateway API key",
      tenant: key.tenant,
    });
  }

  return {
    tokenFree: true,
    systems: {
      modelGateway: {
        baseUrl: normalizeHttpBaseUrl(options.modelBaseUrl, "--model-base-url"),
        keyEnv: parseEnvNameFlag(options.modelKeyEnv, "--model-key-env"),
        defaultModel: options.defaultModel,
        protocol: parseModelProtocolFlag(options.modelProtocol, "--model-protocol"),
      },
      executor: compactObject({
        kind: options.executor,
        image: options.executorImage,
        network: options.executorNetwork,
        homeRoot: options.executorHomeRoot,
        workspaceTemplate: options.executorWorkspace,
        remoteCwdTemplate: options.executorRemoteCwd,
        worktreeCwdTemplate: options.executorWorktreeCwd,
        template: options.executorTemplate,
        ideUrlTemplate: options.executorIdeUrl,
        previewUrlTemplate: options.executorPreviewUrl,
      }),
      controlPlane: compactObject({
        provider,
        baseUrl: controlPlanePreflightBaseUrl({
          controlPlaneProvider: provider,
          controlPlaneUrl: options.controlPlaneUrl,
          controlPlaneTokenEnv: options.controlPlaneTokenEnv,
        }, provider),
        tokenEnv: controlPlaneTokenEnv,
        tenantTokenEnvNames: tenantControlPlaneTokenEnvNames.map(({ tenant, envName }) => ({ tenant, envName })),
        webhookSecretEnv: controlPlaneWebhookSecretEnv,
        agentGitServiceTokenSecretRoot: provider === "agent-git-service" ? options.agentGitServiceTokenSecretRoot : undefined,
      }),
      ...(context.agentGitServiceStaging ? { agentGitServiceStaging: context.agentGitServiceStaging } : {}),
      tenants: compactObject({
        primary: tenant,
        isolation: isolationTenant,
      }),
    },
    requiredVariables: Array.from(requiredVariables.values()),
  };
}

function addPlatformCutoverRequiredEnv(
  variables: Map<string, HarnessPlatformCutoverEnvironmentVariable>,
  envName: string | undefined,
  requiredFor: string[],
  use: HarnessPlatformCutoverEnvironmentVariableUse,
): void {
  if (!envName) return;
  const name = parseEnvNameFlag(envName, use.sourceFlag);
  const existing = variables.get(name) ?? { name, requiredFor: [], uses: [] };
  for (const value of requiredFor) {
    if (!existing.requiredFor.includes(value)) existing.requiredFor.push(value);
  }
  if (!existing.uses.some((entry) => JSON.stringify(entry) === JSON.stringify(use))) {
    existing.uses.push(use);
  }
  variables.set(name, existing);
}

function platformCutoverTenantEnvRefs(values: string[], flag: string): { tenant: string; envName: string; sourceFlag: string }[] {
  return values.map((value) => {
    const index = value.indexOf("=");
    if (index <= 0 || index === value.length - 1) {
      console.error(`${flag} must be formatted as tenant=env`);
      process.exit(2);
    }
    return {
      tenant: parseTenantFlagName(value.slice(0, index)),
      envName: parseEnvNameFlag(value.slice(index + 1), flag),
      sourceFlag: flag,
    };
  });
}

function platformCutoverTenantApiKeyEnvRefs(values: string[]): {
  tenant: string;
  envName: string;
  actor: string;
  role: "admin" | "developer" | "viewer";
}[] {
  return values.map((value) => {
    const tenantSeparator = value.indexOf("=");
    if (tenantSeparator <= 0 || tenantSeparator === value.length - 1) {
      console.error("--tenant-key-env must be formatted as tenant=env:actor:role");
      process.exit(2);
    }
    const parts = value.slice(tenantSeparator + 1).split(":");
    if (parts.length !== 3 || parts.some((part) => !part.trim())) {
      console.error("--tenant-key-env must be formatted as tenant=env:actor:role");
      process.exit(2);
    }
    const [envName, actor, role] = parts;
    return {
      tenant: parseTenantFlagName(value.slice(0, tenantSeparator)),
      envName: parseEnvNameFlag(envName, "--tenant-key-env"),
      actor,
      role: parseTenantRoleFlag(role, "--tenant-key-env"),
    };
  });
}

