function platformCutoverSensitiveInputsOmitted(options: HarnessPlatformCutoverPlanCliOptions): string[] {
  return [
    options.tenantToken?.length ? "tenantToken" : undefined,
    options.tenantKey?.length ? "tenantKey" : undefined,
  ].filter((value): value is string => Boolean(value));
}

function appendCommandArg(args: string[], flag: string, value: string | undefined): void {
  if (value === undefined || value === "") return;
  args.push(flag, value);
}

function appendRepeatedCommandArgs(args: string[], flag: string, values: string[] | undefined): void {
  for (const value of values ?? []) appendCommandArg(args, flag, value);
}

function appendBooleanCommandArg(args: string[], flag: string, value: boolean | undefined): void {
  if (value) args.push(flag);
}

async function runHarnessPlatformCutoverPlan(options: HarnessPlatformCutoverRunCliOptions): Promise<HarnessPlatformCutoverRunResult> {
  const planText = await readHarnessPlatformCutoverPlanText(options);
  const planCwd = harnessPlatformCutoverPlanCwd(options);
  const stages = parseHarnessPlatformCutoverPlanStages(planText);
  const environmentVariables = options.checkEnv ? parseHarnessPlatformCutoverRequiredVariables(planText) : [];
  const requestedStageIds = options.stage ?? [];
  const requestedStageSet = new Set(requestedStageIds);
  const explicitSelection = requestedStageSet.size > 0;
  const approvedGateIds = options.approve ?? [];
  const approvalSet = new Set(approvedGateIds);
  const satisfiedRequirementSet = new Set(options.satisfy ?? []);
  const selectedStages = explicitSelection
    ? stages.filter((stage) => requestedStageSet.has(stage.id))
    : stages;
  const executed: HarnessPlatformCutoverRunExecutedStage[] = [];
  const skipped: HarnessPlatformCutoverRunSkippedStage[] = [];
  const failed: HarnessPlatformCutoverRunFailedStage[] = [];
  const environmentCheckedStageIds: string[] = [];
  const environmentPresent = new Map<string, HarnessPlatformCutoverEnvironmentVariable>();
  const environmentMissing = new Map<string, HarnessPlatformCutoverEnvironmentVariable>();

  for (const id of requestedStageIds.filter((id) => !stages.some((stage) => stage.id === id))) {
    skipped.push({ id, reason: "stageNotFound", blocking: true });
  }

  for (const stage of selectedStages) {
    const missingRequirements = (stage.requires ?? []).filter((requirement) => !satisfiedRequirementSet.has(requirement));
    if (missingRequirements.length > 0) {
      skipped.push({
        id: stage.id,
        command: stage.command,
        reason: "unmetRequirement",
        blocking: true,
        missingRequirements,
      });
      continue;
    }
    const approvalGate = stage.operatorGate;
    if (stage.approvalRequired && (!approvalGate || !approvalSet.has(approvalGate.id))) {
      skipped.push({
        id: stage.id,
        command: stage.command,
        reason: "approvalRequired",
        blocking: explicitSelection,
        ...(approvalGate ? { operatorGate: approvalGate } : {}),
      });
      continue;
    }
    if (stage.executionMode === "long-running") {
      skipped.push({
        id: stage.id,
        command: stage.command,
        reason: "longRunningManual",
        blocking: true,
        ...(approvalGate ? { operatorGate: approvalGate } : {}),
      });
      continue;
    }
    if (!stage.commandArgs?.length) {
      skipped.push({
        id: stage.id,
        command: stage.command,
        reason: "missingCommandArgs",
        blocking: true,
      });
      if (!options.continueOnError) break;
      continue;
    }
    if (options.checkEnv) {
      const stageVariables = environmentVariables.filter((variable) => variable.requiredFor.includes(stage.id));
      if (stageVariables.length > 0) {
        environmentCheckedStageIds.push(stage.id);
      }
      const missingEnvironmentVariables: HarnessPlatformCutoverEnvironmentVariable[] = [];
      for (const variable of stageVariables) {
        if (process.env[variable.name]?.trim()) {
          environmentPresent.set(variable.name, variable);
        } else {
          environmentMissing.set(variable.name, variable);
          missingEnvironmentVariables.push(variable);
        }
      }
      if (missingEnvironmentVariables.length > 0) {
        skipped.push({
          id: stage.id,
          command: stage.command,
          reason: "missingEnvironment",
          blocking: true,
          missingEnvironmentVariables,
        });
        if (!options.continueOnError) break;
        continue;
      }
    }
    const result = await runPlatformCutoverStageCommand(stage.commandArgs, planCwd);
    const artifactSummary = result.exitCode === 0
      ? platformCutoverStageArtifactSummary(stage, planCwd)
      : undefined;
    executed.push({
      id: stage.id,
      command: stage.command,
      exitCode: result.exitCode,
      ok: result.exitCode === 0,
      stdoutBytes: result.stdoutBytes,
      stderrBytes: result.stderrBytes,
      ...(artifactSummary ? { artifactSummary } : {}),
    });
    if (result.exitCode !== 0) {
      failed.push({
        id: stage.id,
        command: stage.command,
        exitCode: result.exitCode,
        stdoutBytes: result.stdoutBytes,
        stderrBytes: result.stderrBytes,
      });
      if (!options.continueOnError) break;
    }
    if (result.exitCode === 0) satisfiedRequirementSet.add(stage.id);
  }

  const result: HarnessPlatformCutoverRunResult = {
    ok: failed.length === 0 && !skipped.some((stage) => stage.blocking),
    ...(options.report ? { reportPath: resolve(options.report) } : {}),
    selectedStageIds: explicitSelection ? requestedStageIds : selectedStages.map((stage) => stage.id),
    approvedGateIds,
    satisfiedRequirements: Array.from(satisfiedRequirementSet),
    ...(options.checkEnv
      ? {
          environment: {
            ok: environmentMissing.size === 0,
            tokenFree: true,
            checkedStageIds: environmentCheckedStageIds,
            checkedVariableNames: [
              ...Array.from(environmentPresent.keys()),
              ...Array.from(environmentMissing.keys()).filter((name) => !environmentPresent.has(name)),
            ],
            present: Array.from(environmentPresent.values()),
            missing: Array.from(environmentMissing.values()),
          },
        }
      : {}),
    executed,
    skipped,
    failed,
  };
  if (options.report) {
    const reportPath = resolve(options.report);
    mkdirSync(dirname(reportPath), { recursive: true });
    await writeFile(reportPath, `${JSON.stringify(result, null, 2)}\n`, "utf8");
  }
  return result;
}

async function runHarnessPlatformCutoverEnvCheck(
  options: HarnessPlatformCutoverEnvCheckCliOptions,
): Promise<HarnessPlatformCutoverEnvCheckResult> {
  const variables = parseHarnessPlatformCutoverRequiredVariables(await readHarnessPlatformCutoverPlanText(options));
  const checkedStageIds = options.stage ?? [];
  const checkedStageSet = new Set(checkedStageIds);
  const selectedVariables = checkedStageSet.size > 0
    ? variables.filter((variable) => variable.requiredFor.some((stageId) => checkedStageSet.has(stageId)))
    : variables;
  const present = selectedVariables.filter((variable) => Boolean(process.env[variable.name]?.trim()));
  const missing = selectedVariables.filter((variable) => !process.env[variable.name]?.trim());
  const result: HarnessPlatformCutoverEnvCheckResult = {
    ok: missing.length === 0,
    tokenFree: true,
    ...(options.report ? { reportPath: resolve(options.report) } : {}),
    checkedStageIds,
    checkedVariableNames: selectedVariables.map((variable) => variable.name),
    present,
    missing,
  };
  if (options.report) {
    const reportPath = resolve(options.report);
    mkdirSync(dirname(reportPath), { recursive: true });
    await writeFile(reportPath, `${JSON.stringify(result, null, 2)}\n`, "utf8");
  }
  return result;
}

async function writeHarnessPlatformCutoverBundle(
  options: HarnessPlatformCutoverBundleCliOptions,
): Promise<HarnessPlatformCutoverBundleResult> {
  const planText = await readHarnessPlatformCutoverPlanText(options);
  return writeHarnessPlatformCutoverBundleFromPlanText(planText, options.out);
}

async function writeHarnessPlatformCutoverBundleFromPlanText(
  planText: string,
  out: string,
): Promise<HarnessPlatformCutoverBundleResult> {
  const parsedPlan = parseHarnessPlatformCutoverPlanObject(planText);
  const stages = parseHarnessPlatformCutoverPlanStages(planText);
  const plan = platformCutoverPlanWithDerivedExternalTargets(parsedPlan, stages);
  const requiredVariables = parseHarnessPlatformCutoverRequiredVariables(planText);
  const outDir = resolve(out);
  const planJson = `${JSON.stringify(plan, null, 2)}\n`;
  const envMarkdown = platformCutoverBundleEnvMarkdown(requiredVariables);
  const envShell = platformCutoverBundleEnvShell(requiredVariables);
  const externalSecrets = `${JSON.stringify(platformCutoverBundleExternalSecrets(requiredVariables), null, 2)}\n`;
  const githubActions = platformCutoverBundleGithubActionsStagingWorkflow(requiredVariables);
  const commands = platformCutoverBundleCommands(stages, requiredVariables);
  const stagingCi = `${JSON.stringify(platformCutoverBundleStagingCi(plan, stages, requiredVariables), null, 2)}\n`;
  const upstreamAgentGitService = platformCutoverBundleUpstreamAgentGitServiceGuide(plan, stages, requiredVariables);
  const upstreamAgentGitServiceJson = upstreamAgentGitService
    ? `${JSON.stringify(upstreamAgentGitService, null, 2)}\n`
    : undefined;
  const files = platformCutoverBundleFiles(stages);
  const fileSha256: Record<string, string> = {
    "plan.json": sha256Hex(planJson),
    "env.md": sha256Hex(envMarkdown),
    "env.sh": sha256Hex(envShell),
    "external-secrets.json": sha256Hex(externalSecrets),
    "github-actions-staging.yml": sha256Hex(githubActions),
    "commands.sh": sha256Hex(commands),
    "staging-ci.json": sha256Hex(stagingCi),
  };
  if (upstreamAgentGitServiceJson) {
    fileSha256["upstream-agent-git-service.json"] = sha256Hex(upstreamAgentGitServiceJson);
  }
  const manifest = {
    schemaVersion: 1,
    tokenFree: true,
    source: "loom harness platform-cutover-plan",
    stageIds: stages.map((stage) => stage.id),
    commandOrder: Array.isArray(plan.commandOrder) ? stringsOnly(plan.commandOrder) : [],
    sensitiveInputsOmitted: Array.isArray(plan.sensitiveInputsOmitted) ? stringsOnly(plan.sensitiveInputsOmitted) : [],
    files,
    fileSha256,
  };
  mkdirSync(outDir, { recursive: true });
  await writeFile(join(outDir, "plan.json"), planJson, "utf8");
  await writeFile(join(outDir, "manifest.json"), `${JSON.stringify(manifest, null, 2)}\n`, "utf8");
  await writeFile(join(outDir, "env.md"), envMarkdown, "utf8");
  await writeFile(join(outDir, "env.sh"), envShell, "utf8");
  await writeFile(join(outDir, "external-secrets.json"), externalSecrets, "utf8");
  await writeFile(join(outDir, "github-actions-staging.yml"), githubActions, "utf8");
  const commandsPath = join(outDir, "commands.sh");
  await writeFile(commandsPath, commands, "utf8");
  await chmod(commandsPath, 0o755);
  await writeFile(join(outDir, "staging-ci.json"), stagingCi, "utf8");
  if (upstreamAgentGitServiceJson) {
    await writeFile(join(outDir, "upstream-agent-git-service.json"), upstreamAgentGitServiceJson, "utf8");
  }
  return {
    ok: true,
    tokenFree: true,
    outDir,
    files,
    stageIds: stages.map((stage) => stage.id),
    fileSha256,
  };
}

function verifyHarnessPlatformCutoverBundle(
  options: HarnessPlatformCutoverBundleVerifyCliOptions,
): HarnessPlatformCutoverBundleVerifyResult {
  const dir = resolve(options.dir);
  const forbiddenValues = [
    ...(options.forbid ?? []),
    ...platformCutoverBundleForbiddenEnvValues(options.forbidEnv ?? []),
  ].filter((value) => value.length > 0);
  const manifestText = readBundleFileIfPresent(dir, "manifest.json");
  const manifest = manifestText === undefined ? undefined : parseBundleManifest(manifestText);
  const planText = readBundleFileIfPresent(dir, "plan.json");
  const plan = planText === undefined
    ? undefined
    : parseHarnessPlatformCutoverPlanObject(planText);
  const stages = planText === undefined
    ? []
    : parseHarnessPlatformCutoverPlanStages(planText);
  const requiredVariables = planText === undefined
    ? []
    : parseHarnessPlatformCutoverRequiredVariables(planText);
  const requiredFiles = platformCutoverBundleFiles(stages);
  const manifestFiles = manifest && Array.isArray(manifest.files)
    ? stringsOnly(manifest.files).filter(isSafeBundleFileName)
    : [];
  const filesChecked = manifestFiles.length > 0
    ? manifestFiles
    : requiredFiles;
  const manifestFileMismatches = platformCutoverBundleManifestFileMismatches(manifest, requiredFiles);
  const expectedFileSha256 = bundleManifestFileSha256(manifest);
  const manifestHashMissingFiles = platformCutoverBundleManifestHashMissingFiles(expectedFileSha256, requiredFiles);
  const missingFiles: string[] = [];
  const hashCheckedFiles: string[] = [];
  const hashMismatchedFiles: string[] = [];
  const forbiddenValueHitFiles: string[] = [];
  for (const file of filesChecked) {
    const text = readBundleFileIfPresent(dir, file);
    if (text === undefined) {
      missingFiles.push(file);
      continue;
    }
    const expectedHash = expectedFileSha256[file];
    if (expectedHash) {
      hashCheckedFiles.push(file);
      if (sha256Hex(text) !== expectedHash) {
        hashMismatchedFiles.push(file);
      }
    }
    if (forbiddenValues.some((value) => text.includes(value))) {
      forbiddenValueHitFiles.push(file);
    }
  }
  const stageIds = stages.map((stage) => stage.id);
  const manifestStageIdMismatches = platformCutoverBundleManifestStageIdMismatches(manifest, stageIds);
  const stagingCiExpectedReportMissing = platformCutoverBundleStagingCiExpectedReportMissing(
    readBundleFileIfPresent(dir, "staging-ci.json"),
    stages,
  );
  const stagingCiOperatorApprovalMismatches = platformCutoverBundleStagingCiOperatorApprovalMismatches(
    readBundleFileIfPresent(dir, "staging-ci.json"),
    stages,
  );
  const stagingCiCheckMissing = platformCutoverBundleStagingCiCheckMissing(
    readBundleFileIfPresent(dir, "staging-ci.json"),
    stages,
  );
  const agentGitServiceCompatTargetMismatches = platformCutoverBundleAgentGitServiceCompatTargetMismatches(
    plan,
    stages,
  );
  const upstreamAgentGitServiceHandoffMismatches = platformCutoverBundleUpstreamAgentGitServiceHandoffMismatches(
    readBundleFileIfPresent(dir, "upstream-agent-git-service.json"),
    plan,
    stages,
    requiredVariables,
  );
  const stagingCiStrictCommandMissing = platformCutoverBundleStagingCiStrictCommandMissing(
    readBundleFileIfPresent(dir, "staging-ci.json"),
  );
  const commandsShStrictCheckMissing = platformCutoverBundleCommandsShStrictCheckMissing(
    readBundleFileIfPresent(dir, "commands.sh"),
    stages,
  );
  const manifestTokenFree = isRecord(manifest) && manifest.tokenFree === true;
  const reportPath = options.report ? resolve(options.report) : undefined;
  const result: HarnessPlatformCutoverBundleVerifyResult = {
    ok: missingFiles.length === 0 &&
      manifestTokenFree &&
      manifestFileMismatches.length === 0 &&
      manifestHashMissingFiles.length === 0 &&
      manifestStageIdMismatches.length === 0 &&
      stagingCiExpectedReportMissing.length === 0 &&
      stagingCiOperatorApprovalMismatches.length === 0 &&
      stagingCiCheckMissing.length === 0 &&
      agentGitServiceCompatTargetMismatches.length === 0 &&
      upstreamAgentGitServiceHandoffMismatches.length === 0 &&
      hashMismatchedFiles.length === 0 &&
      stagingCiStrictCommandMissing.length === 0 &&
      commandsShStrictCheckMissing.length === 0 &&
      forbiddenValueHitFiles.length === 0,
    tokenFree: true,
    dir,
    ...(reportPath ? { reportPath } : {}),
    filesChecked,
    missingFiles,
    manifestTokenFree,
    manifestFileMismatches,
    manifestHashMissingFiles,
    stageIds,
    manifestStageIdMismatches,
    stagingCiExpectedReportMissing,
    stagingCiOperatorApprovalMismatches,
    stagingCiCheckMissing,
    agentGitServiceCompatTargetMismatches,
    upstreamAgentGitServiceHandoffMismatches,
    hashCheckedFiles,
    hashMismatchedFiles,
    stagingCiStrictCommandMissing,
    commandsShStrictCheckMissing,
    forbiddenValueHitFiles,
    forbiddenValueHitCount: forbiddenValueHitFiles.length,
  };
  if (reportPath) {
    mkdirSync(dirname(reportPath), { recursive: true });
    writeFileSync(reportPath, `${JSON.stringify(result, null, 2)}\n`, "utf8");
  }
  return result;
}

function platformCutoverBundleManifestHashMissingFiles(
  expectedFileSha256: Record<string, string>,
  requiredFiles: string[],
): string[] {
  return requiredFiles.filter((file) => file !== "manifest.json" && expectedFileSha256[file] === undefined);
}

function platformCutoverBundleFiles(stages: HarnessPlatformCutoverPlanStage[] = []): string[] {
  return [
    "plan.json",
    "manifest.json",
    "env.md",
    "env.sh",
    "external-secrets.json",
    "github-actions-staging.yml",
    "commands.sh",
    "staging-ci.json",
    ...(platformCutoverBundleUsesAgentGitService(stages) ? ["upstream-agent-git-service.json"] : []),
  ];
}

function platformCutoverBundleManifestFileMismatches(
  manifest: Record<string, unknown> | undefined,
  requiredFiles: string[],
): string[] {
  if (!Array.isArray(manifest?.files)) return ["manifest.files"];
  const manifestFiles = stringsOnly(manifest.files);
  if (manifestFiles.length !== manifest.files.length) return ["manifest.files"];
  const missing = requiredFiles
    .filter((file) => !manifestFiles.includes(file))
    .map((file) => `manifest.files.missing.${file}`);
  const extra = manifestFiles
    .filter((file) => !requiredFiles.includes(file))
    .map((file) => `manifest.files.extra.${file}`);
  const order = missing.length === 0 &&
    extra.length === 0 &&
    requiredFiles.some((file, index) => manifestFiles[index] !== file)
    ? ["manifest.files.order"]
    : [];
  return [...missing, ...extra, ...order];
}

function platformCutoverBundleUsesAgentGitService(stages: HarnessPlatformCutoverPlanStage[]): boolean {
  return stages.some((stage) => stage.id.startsWith("agent-git-service-"));
}

function platformCutoverRequiresUpstreamAgentGitServiceHandoff(stages: HarnessPlatformCutoverPlanStage[]): boolean {
  return stages.some((stage) =>
    stage.id === "agent-git-service-compat-rehearsal" ||
    stage.id === "agent-git-service-staging-readiness"
  );
}

function platformCutoverBundleUpstreamAgentGitServiceGuide(
  plan: Record<string, unknown>,
  stages: HarnessPlatformCutoverPlanStage[],
  requiredVariables: HarnessPlatformCutoverEnvironmentVariable[],
): HarnessUpstreamAgentGitServiceStagingGuide | undefined {
  const targets = platformCutoverBundleExternalTargets(plan);
  const controlPlane = isRecord(targets.controlPlane) ? targets.controlPlane : undefined;
  if (!platformCutoverBundleUsesAgentGitService(stages) && controlPlane?.provider !== "agent-git-service") {
    return undefined;
  }
  const agentGitServiceStaging = isRecord(targets.agentGitServiceStaging)
    ? targets.agentGitServiceStaging
    : undefined;
  return {
    schemaVersion: "upstream-agent-git-service-staging-guide/v1",
    tokenFree: true,
    upstream: {
      repository: "https://github.com/ngaut/agent-git-service",
      developmentBinary: "gh-server",
      apiBasePath: "/api/v3",
      metadataDatabaseEnv: "DB_DSN",
    },
    requiredServerEnv: [
      {
        name: "DB_DSN",
        purpose: "upstream agent-git-service metadata database DSN for gh-server",
      },
    ],
    requiredLoomEnv: Array.from(new Set(requiredVariables.map((variable) => variable.name))),
    targets: compactObject({
      controlPlane,
      agentGitServiceStaging,
    }),
    operatorOrder: [
      "start upstream gh-server with DB_DSN outside this bundle",
      "set Loom control-plane URL/token envs from CI secrets",
      "run strict pre-serve commands.sh",
      "start Loom serve manually",
      "run approved AGS write stage and strict post-serve commands.sh",
    ],
    operatorChecklist: platformCutoverBundleUpstreamAgentGitServiceOperatorChecklist(requiredVariables),
  };
}

function platformCutoverBundleUpstreamAgentGitServiceOperatorChecklist(
  requiredVariables: HarnessPlatformCutoverEnvironmentVariable[],
): HarnessUpstreamAgentGitServiceOperatorChecklistItem[] {
  return [
    {
      id: "start-upstream-gh-server",
      phase: "upstream-server",
      action: "Start upstream gh-server with DB_DSN configured outside Loom.",
      requiresEnv: ["DB_DSN"],
      evidence: "external AGS /readyz is reachable and reports ready",
    },
    {
      id: "set-loom-control-plane-secrets",
      phase: "loom-env",
      action: "Populate Loom control-plane, tenant, and model env names from CI secrets.",
      requiresEnv: Array.from(new Set(requiredVariables.map((variable) => variable.name))),
      evidence: "platform-staging-prerequisites reports required env names present",
    },
    {
      id: "run-strict-pre-serve",
      phase: "pre-serve",
      command: "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 LOOM_CUTOVER_PHASE=pre-serve ./commands.sh",
      evidence: "staging-prerequisites, staging-run, staging-evidence, staging-verdict, and external-staging-audit reports pass",
    },
    {
      id: "start-loom-serve",
      phase: "serve",
      command: "loom harness serve",
      evidence: "serve-ready report proves /healthz, /readyz, and /status",
    },
    {
      id: "run-approved-ags-post-serve",
      phase: "post-serve",
      command: "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 LOOM_CUTOVER_PHASE=post-serve ./commands.sh",
      evidence: "operator-approvals, native write, operator-artifacts, staging-proof, and goal-audit pass",
    },
  ];
}

function platformCutoverBundleUpstreamAgentGitServiceHandoffMismatches(
  text: string | undefined,
  plan: Record<string, unknown> | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
  requiredVariables: HarnessPlatformCutoverEnvironmentVariable[],
): string[] {
  if (!platformCutoverBundleUsesAgentGitService(stages)) return [];
  if (text === undefined) return ["upstream-agent-git-service.json"];
  let value: unknown;
  try {
    value = JSON.parse(text);
  } catch {
    return ["upstream-agent-git-service.json"];
  }
  if (!isRecord(value)) return ["upstream-agent-git-service.json"];
  const mismatches: string[] = [];
  const upstream = isRecord(value.upstream) ? value.upstream : undefined;
  if (value.schemaVersion !== "upstream-agent-git-service-staging-guide/v1") {
    mismatches.push("upstream-agent-git-service.schemaVersion");
  }
  if (value.tokenFree !== true) {
    mismatches.push("upstream-agent-git-service.tokenFree");
  }
  if (upstream?.repository !== "https://github.com/ngaut/agent-git-service") {
    mismatches.push("upstream-agent-git-service.upstream.repository");
  }
  if (upstream?.developmentBinary !== "gh-server") {
    mismatches.push("upstream-agent-git-service.upstream.developmentBinary");
  }
  if (upstream?.apiBasePath !== "/api/v3") {
    mismatches.push("upstream-agent-git-service.upstream.apiBasePath");
  }
  if (upstream?.metadataDatabaseEnv !== "DB_DSN") {
    mismatches.push("upstream-agent-git-service.upstream.metadataDatabaseEnv");
  }
  const requiredServerEnv = Array.isArray(value.requiredServerEnv)
    ? value.requiredServerEnv.filter(isRecord)
    : [];
  if (!requiredServerEnv.some((item) => item.name === "DB_DSN")) {
    mismatches.push("upstream-agent-git-service.requiredServerEnv.DB_DSN");
  }
  const requiredLoomEnv = Array.isArray(value.requiredLoomEnv) ? stringsOnly(value.requiredLoomEnv) : [];
  for (const envName of Array.from(new Set(requiredVariables.map((variable) => variable.name)))) {
    if (!requiredLoomEnv.includes(envName)) {
      mismatches.push(`upstream-agent-git-service.requiredLoomEnv.${envName}`);
    }
  }
  const targets = isRecord(value.targets) ? value.targets : undefined;
  const guideControlPlane = targets && isRecord(targets.controlPlane) ? targets.controlPlane : undefined;
  const guideAgentGitServiceStaging = targets && isRecord(targets.agentGitServiceStaging)
    ? targets.agentGitServiceStaging
    : undefined;
  const expectedTargets = plan ? platformCutoverBundleExternalTargets(plan) : {};
  const expectedControlPlane = isRecord(expectedTargets.controlPlane) ? expectedTargets.controlPlane : undefined;
  if (expectedControlPlane?.provider === "agent-git-service") {
    if (guideControlPlane?.provider !== "agent-git-service") {
      mismatches.push("upstream-agent-git-service.targets.controlPlane.provider");
    }
    const guideBaseUrl = nonEmptyString(guideControlPlane?.baseUrl);
    const expectedBaseUrl = nonEmptyString(expectedControlPlane.baseUrl);
    if (!guideBaseUrl || !expectedBaseUrl || !platformCutoverSameAgentGitServiceApiBaseUrl(guideBaseUrl, expectedBaseUrl)) {
      mismatches.push("upstream-agent-git-service.targets.controlPlane.baseUrl");
    }
    if (guideControlPlane?.tokenEnv !== expectedControlPlane.tokenEnv) {
      mismatches.push("upstream-agent-git-service.targets.controlPlane.tokenEnv");
    }
    if (JSON.stringify(guideControlPlane?.tenantTokenEnvNames ?? []) !== JSON.stringify(expectedControlPlane.tenantTokenEnvNames ?? [])) {
      mismatches.push("upstream-agent-git-service.targets.controlPlane.tenantTokenEnvNames");
    }
  }
  const expectedAgentGitServiceStaging = isRecord(expectedTargets.agentGitServiceStaging)
    ? expectedTargets.agentGitServiceStaging
    : undefined;
  if (
    expectedAgentGitServiceStaging &&
    JSON.stringify(guideAgentGitServiceStaging ?? {}) !== JSON.stringify(expectedAgentGitServiceStaging)
  ) {
    mismatches.push("upstream-agent-git-service.targets.agentGitServiceStaging");
  }
  if (!Array.isArray(value.operatorOrder) || stringsOnly(value.operatorOrder).length === 0) {
    mismatches.push("upstream-agent-git-service.operatorOrder");
  }
  mismatches.push(...platformCutoverBundleUpstreamAgentGitServiceChecklistMismatches(value, requiredVariables));
  return mismatches;
}

function platformCutoverBundleUpstreamAgentGitServiceChecklistMismatches(
  value: Record<string, unknown>,
  requiredVariables: HarnessPlatformCutoverEnvironmentVariable[],
): string[] {
  if (!Array.isArray(value.operatorChecklist)) return ["upstream-agent-git-service.operatorChecklist"];
  const actual = value.operatorChecklist.filter(isRecord);
  const expected = platformCutoverBundleUpstreamAgentGitServiceOperatorChecklist(requiredVariables);
  return expected.flatMap((expectedItem) => {
    const actualItem = actual.find((item) => item.id === expectedItem.id);
    if (!actualItem) return [`upstream-agent-git-service.operatorChecklist.${expectedItem.id}`];
    const expectedRequiresEnv = expectedItem.requiresEnv ?? [];
    const actualRequiresEnv = Array.isArray(actualItem.requiresEnv) ? stringsOnly(actualItem.requiresEnv) : [];
    const mismatch =
      actualItem.phase !== expectedItem.phase ||
      actualItem.action !== expectedItem.action ||
      actualItem.command !== expectedItem.command ||
      actualItem.evidence !== expectedItem.evidence ||
      JSON.stringify(actualRequiresEnv) !== JSON.stringify(expectedRequiresEnv);
    return mismatch ? [`upstream-agent-git-service.operatorChecklist.${expectedItem.id}`] : [];
  });
}

function platformCutoverBundleStagingCiCheckMissing(
  text: string | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
): string[] {
  if (text === undefined) return ["staging-ci.checks"];
  let value: unknown;
  try {
    value = JSON.parse(text);
  } catch {
    return ["staging-ci.checks"];
  }
  if (!isRecord(value) || !isRecord(value.checks)) return ["staging-ci.checks"];
  const actualPreServe = value.checks.preServe;
  const actualPostServe = value.checks.postServe;
  if (!Array.isArray(actualPreServe) || !Array.isArray(actualPostServe)) return ["staging-ci.checks"];
  const preServeChecks = stringsOnly(actualPreServe);
  const postServeChecks = stringsOnly(actualPostServe);
  if (preServeChecks.length !== actualPreServe.length || postServeChecks.length !== actualPostServe.length) {
    return ["staging-ci.checks"];
  }
  const expected = platformCutoverBundleStagingCiChecks(stages);
  return [
    ...expected.preServe
      .flatMap((check, index) => preServeChecks.includes(check) ? [] : [`staging-ci.checks.preServe.${index}`]),
    ...expected.postServe
      .flatMap((check, index) => postServeChecks.includes(check) ? [] : [`staging-ci.checks.postServe.${index}`]),
  ];
}

function platformCutoverBundleAgentGitServiceCompatTargetMismatches(
  plan: Record<string, unknown> | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
): string[] {
  const expectedBaseUrl = platformCutoverBundleAgentGitServiceControlPlaneBaseUrl(plan);
  if (!expectedBaseUrl) return [];
  const compatStage = stages.find((stage) => stage.id === "agent-git-service-compat-rehearsal");
  if (!compatStage) return [];
  const candidateUrl = platformCutoverStageCommandArg(compatStage, "--candidate-url");
  if (!candidateUrl) return [];
  return platformCutoverSameAgentGitServiceApiBaseUrl(candidateUrl, expectedBaseUrl)
    ? []
    : ["agent-git-service-compat-rehearsal.candidate-url"];
}

function platformCutoverBundleAgentGitServiceControlPlaneBaseUrl(
  plan: Record<string, unknown> | undefined,
): string | undefined {
  const externalEnvironment = plan && isRecord(plan.externalEnvironment) ? plan.externalEnvironment : undefined;
  const systems = externalEnvironment && isRecord(externalEnvironment.systems) ? externalEnvironment.systems : undefined;
  const controlPlane = systems && isRecord(systems.controlPlane) ? systems.controlPlane : undefined;
  if (!controlPlane || controlPlane.provider !== "agent-git-service") return undefined;
  return nonEmptyString(controlPlane.baseUrl);
}

function platformCutoverStageCommandArg(
  stage: HarnessPlatformCutoverPlanStage,
  flag: string,
): string | undefined {
  const commandArgs = stage.commandArgs ?? [];
  const index = commandArgs.indexOf(flag);
  return index >= 0 ? nonEmptyString(commandArgs[index + 1]) : undefined;
}

function platformCutoverBundleStagingCiOperatorApprovalMismatches(
  text: string | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
): string[] {
  if (text === undefined) return ["staging-ci.operatorApprovals"];
  let value: unknown;
  try {
    value = JSON.parse(text);
  } catch {
    return ["staging-ci.operatorApprovals"];
  }
  if (!isRecord(value) || !Array.isArray(value.operatorApprovals)) return ["staging-ci.operatorApprovals"];
  const actual = value.operatorApprovals.filter(isRecord);
  if (actual.length !== value.operatorApprovals.length) return ["staging-ci.operatorApprovals"];
  const expected = platformCutoverBundleStagingCiOperatorApprovals(stages);
  const mismatches: string[] = [];
  for (const approval of expected) {
    const actualApproval = actual.find((candidate) => candidate.stageId === approval.stageId);
    if (!actualApproval) {
      mismatches.push(`staging-ci.operatorApprovals.${approval.stageId}`);
      continue;
    }
    const fields: Array<keyof typeof approval> = ["executionMode", "gateId", "evidence", "report", "command"];
    for (const field of fields) {
      if (actualApproval[field] !== approval[field]) {
        mismatches.push(`staging-ci.operatorApprovals.${approval.stageId}.${field}`);
      }
    }
    const actualRequires = Array.isArray(actualApproval.requires) ? stringsOnly(actualApproval.requires) : [];
    const expectedRequires = approval.requires ?? [];
    if (
      !Array.isArray(actualApproval.requires) ||
      actualRequires.length !== actualApproval.requires.length ||
      actualRequires.length !== expectedRequires.length ||
      actualRequires.some((requirement, index) => requirement !== expectedRequires[index])
    ) {
      mismatches.push(`staging-ci.operatorApprovals.${approval.stageId}.requires`);
    }
  }
  for (const approval of actual) {
    if (typeof approval.stageId === "string" && !expected.some((candidate) => candidate.stageId === approval.stageId)) {
      mismatches.push(`staging-ci.operatorApprovals.${approval.stageId}.extra`);
    }
  }
  return mismatches;
}

function platformCutoverBundleStagingCiExpectedReportMissing(
  text: string | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
): string[] {
  if (text === undefined) return ["staging-ci.expectedReports"];
  let value: unknown;
  try {
    value = JSON.parse(text);
  } catch {
    return ["staging-ci.expectedReports"];
  }
  if (!isRecord(value) || !isRecord(value.expectedReports)) return ["staging-ci.expectedReports"];
  const preServe = value.expectedReports.preServe;
  const postServe = value.expectedReports.postServe;
  if (!Array.isArray(preServe) || !Array.isArray(postServe)) return ["staging-ci.expectedReports"];
  const preServeReports = stringsOnly(preServe);
  const postServeReports = stringsOnly(postServe);
  if (preServeReports.length !== preServe.length || postServeReports.length !== postServe.length) {
    return ["staging-ci.expectedReports"];
  }
  return [
    ...platformCutoverBundleStagingCiPreServeReports(stages)
      .filter((name) => !preServeReports.includes(name))
      .map((name) => `staging-ci.expectedReports.preServe.${name}`),
    ...platformCutoverBundleStagingCiPostServeReports(stages)
      .filter((name) => !postServeReports.includes(name))
      .map((name) => `staging-ci.expectedReports.postServe.${name}`),
  ];
}

function platformCutoverBundleManifestStageIdMismatches(
  manifest: Record<string, unknown> | undefined,
  stageIds: string[],
): string[] {
  if (!Array.isArray(manifest?.stageIds)) return ["manifest.stageIds"];
  const manifestStageIds = stringsOnly(manifest.stageIds);
  if (manifestStageIds.length !== manifest.stageIds.length) return ["manifest.stageIds"];
  const missing = stageIds
    .filter((stageId) => !manifestStageIds.includes(stageId))
    .map((stageId) => `manifest.stageIds.missing.${stageId}`);
  const extra = manifestStageIds
    .filter((stageId) => !stageIds.includes(stageId))
    .map((stageId) => `manifest.stageIds.extra.${stageId}`);
  const order = missing.length === 0 &&
    extra.length === 0 &&
    stageIds.some((stageId, index) => manifestStageIds[index] !== stageId)
    ? ["manifest.stageIds.order"]
    : [];
  return [...missing, ...extra, ...order];
}

function platformCutoverBundleCommandsShStrictCheckMissing(
  text: string | undefined,
  stages: HarnessPlatformCutoverPlanStage[],
): string[] {
  if (text === undefined) return ["commands.sh"];
  const required: Array<[string, string]> = [
    ["commands.sh.shebang", "#!/usr/bin/env bash"],
    ["commands.sh.strictMode", "set -euo pipefail"],
    ["commands.sh.LOOM_BIN.wrapperFallback", 'if [[ -z "${LOOM_BIN:-}" && -x "$SCRIPT_DIR/loom-wrapper" ]]; then'],
    ["commands.sh.LOOM_BIN.wrapperPath", 'LOOM_BIN="$SCRIPT_DIR/loom-wrapper"'],
    ["commands.sh.LOOM_BIN", 'LOOM_BIN="${LOOM_BIN:-loom}"'],
    ["commands.sh.LOOM_CUTOVER_PHASE", 'LOOM_CUTOVER_PHASE="${LOOM_CUTOVER_PHASE:-all}"'],
    ["commands.sh.LOOM_REQUIRE_EXTERNAL_STAGING", 'LOOM_REQUIRE_EXTERNAL_STAGING="${LOOM_REQUIRE_EXTERNAL_STAGING:-0}"'],
    ["commands.sh.LOOM_REQUIRE_OPERATOR_APPROVALS", 'LOOM_REQUIRE_OPERATOR_APPROVALS="${LOOM_REQUIRE_OPERATOR_APPROVALS:-0}"'],
    ["commands.sh.LOOM_RUN_STAGING_CI_CHECKS", 'LOOM_RUN_STAGING_CI_CHECKS="${LOOM_RUN_STAGING_CI_CHECKS:-0}"'],
    ["commands.sh.phaseValidation", "all|pre-serve|post-serve"],
    ["commands.sh.LOOM_BIN.executableGate", 'if ! command -v "$LOOM_BIN" >/dev/null 2>&1; then'],
    ["commands.sh.runStagingCiChecks.earlyJq", 'if [[ "$LOOM_RUN_STAGING_CI_CHECKS" == "1" ]]; then'],
    ["commands.sh.runStagingCiChecks.function", "run_staging_ci_checks()"],
    ["commands.sh.runStagingCiChecks.flagGate", 'if [[ "$LOOM_RUN_STAGING_CI_CHECKS" != "1" ]]; then'],
    ["commands.sh.runStagingCiChecks.jq", 'command -v jq >/dev/null 2>&1 || { echo "jq is required when LOOM_RUN_STAGING_CI_CHECKS=1" >&2; exit 2; }'],
    ["commands.sh.runStagingCiChecks.preServe", 'run_staging_ci_checks "preServe"'],
    ["commands.sh.runStagingCiChecks.postServe", 'run_staging_ci_checks "postServe"'],
    ["commands.sh.recordStagingCiRunProof.function", "record_staging_ci_run_proof()"],
    ["commands.sh.recordStagingCiRunProof.command", "platform-ci-run-proof --dir . --phase"],
    ["commands.sh.bundleVerify", "platform-cutover-bundle-verify --dir ."],
    ["commands.sh.stagingPrerequisites", "platform-staging-prerequisites --dir . --plan plan.json --report reports/staging-prerequisites.json"],
    ["commands.sh.stagingRun", "platform-staging-run --dir . --plan plan.json --report reports/staging-run.json"],
    ["commands.sh.externalStagingAudit", "platform-external-staging-audit --dir . --plan plan.json --report reports/external-staging-audit.json"],
    ["commands.sh.operatorApprovals", "platform-operator-approvals --dir . --report reports/operator-approvals.json"],
    ["commands.sh.artifactVerifyExternalArg", "ARTIFACT_VERIFY_EXTRA_ARGS+=(--require-external-staging)"],
    ["commands.sh.artifactVerifyApprovalArg", "ARTIFACT_VERIFY_EXTRA_ARGS+=(--require-operator-approvals)"],
    ["commands.sh.stagingProofExternalArg", "STAGING_PROOF_EXTRA_ARGS+=(--require-external-staging)"],
    ["commands.sh.stagingProofApprovalArg", "STAGING_PROOF_EXTRA_ARGS+=(--require-operator-approvals)"],
    ["commands.sh.goalAuditExternalArg", "GOAL_AUDIT_EXTRA_ARGS+=(--require-external-staging)"],
    ["commands.sh.goalAuditApprovalArg", "GOAL_AUDIT_EXTRA_ARGS+=(--require-operator-approvals)"],
    ["commands.sh.artifactVerifyStrictArgs", "${ARTIFACT_VERIFY_EXTRA_ARGS[@]}"],
    ["commands.sh.stagingProofStrictArgs", "${STAGING_PROOF_EXTRA_ARGS[@]}"],
    ["commands.sh.goalAuditStrictArgs", "${GOAL_AUDIT_EXTRA_ARGS[@]}"],
    ["commands.sh.artifactVerify", "platform-cutover-artifacts-verify --dir ."],
    ["commands.sh.artifactVerifyRunnerExecuteArg", "--require-operator-cockpit-runner-execute"],
    ["commands.sh.stagingProof", "platform-staging-proof --dir ."],
    ["commands.sh.goalAudit", "platform-goal-audit --dir . --report reports/goal-audit.json"],
    ["commands.sh.operatorStatus", "platform-operator-status --dir . --report reports/operator-status.json"],
    ["commands.sh.operatorCockpitPlan", "platform-operator-cockpit-plan --dir . --report reports/operator-cockpit-plan.json"],
    ["commands.sh.operatorCockpitNext", "platform-operator-cockpit-next --dir . --report reports/operator-cockpit-next.json"],
    ["commands.sh.operatorHandoffPacket", "platform-operator-handoff-packet --dir . --report reports/operator-handoff-packet.json"],
    ["commands.sh.operatorCockpitRunnerExecute", "platform-operator-cockpit-runner --dir . --execute --report reports/operator-cockpit-runner-execute.json"],
  ];
  const longRunningIndex = stages.findIndex((stage) => stage.executionMode === "long-running");
  const postServeStages = longRunningIndex >= 0 ? stages.slice(longRunningIndex + 1) : [];
  if (postServeStages.some((stage) => !stage.approvalRequired && stage.executionMode !== "long-running")) {
    required.push(["commands.sh.serveReady", "platform-serve-ready --plan plan.json --report reports/serve-ready.json"]);
  }
  if (platformCutoverRequiresUpstreamAgentGitServiceHandoff(stages)) {
    required.push(["commands.sh.upstreamAgentGitServiceServerEnvPlan", "upstream-agent-git-service-server-env-plan --dir . --report reports/upstream-agent-git-service-server-env-plan.json"]);
    required.push(["commands.sh.upstreamAgentGitServiceHandoff", "upstream-agent-git-service-handoff --dir . --plan plan.json --report reports/upstream-agent-git-service-handoff.json"]);
  }
  if (stages.some((stage) => stage.id === "cutover-report") && stages.some((stage) => stage.id === "smoke")) {
    required.push(["commands.sh.concurrencyAudit", "platform-concurrency-audit --cutover-report reports/cutover-report.json --smoke-report reports/smoke.json"]);
  }
  return required
    .filter(([, token]) => !text.includes(token))
    .map(([label]) => label);
}

function platformCutoverBundleStagingCiStrictCommandMissing(text: string | undefined): string[] {
  if (text === undefined) return ["staging-ci.json"];
  let value: unknown;
  try {
    value = JSON.parse(text);
  } catch {
    return ["staging-ci.json"];
  }
  if (!isRecord(value) || value.schemaVersion !== "platform-staging-ci/v1" || !isRecord(value.commands)) {
    return ["staging-ci.commands"];
  }
  const commands = value.commands;
  const commandSpecs: Array<{ key: string; required: Array<[string, string]> }> = [
    {
      key: "preServe",
      required: [
        ["LOOM_REQUIRE_EXTERNAL_STAGING", "LOOM_REQUIRE_EXTERNAL_STAGING=1"],
        ["LOOM_REQUIRE_OPERATOR_APPROVALS", "LOOM_REQUIRE_OPERATOR_APPROVALS=1"],
        ["LOOM_RUN_STAGING_CI_CHECKS", "LOOM_RUN_STAGING_CI_CHECKS=1"],
        ["LOOM_CUTOVER_PHASE", "LOOM_CUTOVER_PHASE=pre-serve"],
        ["script", "./commands.sh"],
      ],
    },
    {
      key: "postServe",
      required: [
        ["LOOM_REQUIRE_EXTERNAL_STAGING", "LOOM_REQUIRE_EXTERNAL_STAGING=1"],
        ["LOOM_REQUIRE_OPERATOR_APPROVALS", "LOOM_REQUIRE_OPERATOR_APPROVALS=1"],
        ["LOOM_RUN_STAGING_CI_CHECKS", "LOOM_RUN_STAGING_CI_CHECKS=1"],
        ["LOOM_CUTOVER_PHASE", "LOOM_CUTOVER_PHASE=post-serve"],
        ["script", "./commands.sh"],
      ],
    },
    {
      key: "all",
      required: [
        ["LOOM_REQUIRE_EXTERNAL_STAGING", "LOOM_REQUIRE_EXTERNAL_STAGING=1"],
        ["LOOM_REQUIRE_OPERATOR_APPROVALS", "LOOM_REQUIRE_OPERATOR_APPROVALS=1"],
        ["LOOM_RUN_STAGING_CI_CHECKS", "LOOM_RUN_STAGING_CI_CHECKS=1"],
        ["script", "./commands.sh"],
      ],
    },
  ];
  return commandSpecs.flatMap(({ key, required }) => {
    const command = commands[key];
    if (typeof command !== "string") return [`staging-ci.commands.${key}`];
    return required
      .filter(([, token]) => !command.includes(token))
      .map(([label]) => `staging-ci.commands.${key}.${label}`);
  });
}

function platformCutoverBundleStagingCi(
  plan: Record<string, unknown>,
  stages: HarnessPlatformCutoverPlanStage[],
  requiredVariables: HarnessPlatformCutoverEnvironmentVariable[],
): HarnessPlatformStagingCiManifest {
  return {
    schemaVersion: "platform-staging-ci/v1",
    tokenFree: true,
    commands: {
      preServe: "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 LOOM_CUTOVER_PHASE=pre-serve ./commands.sh",
      postServe: "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 LOOM_CUTOVER_PHASE=post-serve ./commands.sh",
      all: "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 ./commands.sh",
    },
    requiredEnv: requiredVariables,
    externalTargets: platformCutoverBundleExternalTargets(plan),
    expectedReports: {
      preServe: platformCutoverBundleStagingCiPreServeReports(stages),
      postServe: platformCutoverBundleStagingCiPostServeReports(stages),
    },
    operatorApprovals: platformCutoverBundleStagingCiOperatorApprovals(stages),
    checks: platformCutoverBundleStagingCiChecks(stages),
  };
}

