function loomShellCommand(args: string[]): string {
  return ["\"${LOOM_BIN}\"", ...args.map(shellQuote)].join(" ");
}

function loomFallbackShellCommand(args: string[]): string {
  return ["\"${LOOM_BIN:-loom}\"", ...args.map(shellQuote)].join(" ");
}

function shellCommand(args: string[]): string {
  return args.map(shellQuote).join(" ");
}

function shellQuote(value: string): string {
  if (/^\$\{[A-Za-z_][A-Za-z0-9_]*\[@\]\}$/.test(value)) return `"${value}"`;
  if (/^[A-Za-z0-9_@%+=:,./-]+$/.test(value)) return value;
  return `'${value.replace(/'/g, "'\\''")}'`;
}

function parseHarnessPlatformCutoverPlanStage(value: unknown, index: number): HarnessPlatformCutoverPlanStage {
  if (!isRecord(value)) throw new Error(`platform cutover stage ${index} must be an object.`);
  const id = stringFromPlanStage(value, "id", index);
  const command = stringFromPlanStage(value, "command", index);
  const executionMode = stringFromPlanStage(value, "executionMode", index);
  if (!isPlatformCutoverExecutionMode(executionMode)) {
    throw new Error(`platform cutover stage ${id} has unsupported executionMode ${executionMode}.`);
  }
  const commandArgs = Array.isArray(value.commandArgs)
    ? value.commandArgs.map((item, argIndex) => {
        if (typeof item === "string") return item;
        throw new Error(`platform cutover stage ${id} commandArgs[${argIndex}] must be a string.`);
      })
    : undefined;
  const approvalRequired = value.approvalRequired === true;
  const tokenFree = value.tokenFree === true;
  const requires = value.requires === undefined
    ? undefined
    : parseHarnessPlatformCutoverPlanStringArray(value.requires, id, "requires");
  const operatorGate = value.operatorGate === undefined
    ? undefined
    : parseHarnessPlatformCutoverOperatorGate(value.operatorGate, id);
  return {
    id,
    command,
    ...(commandArgs ? { commandArgs } : {}),
    executionMode,
    approvalRequired,
    tokenFree,
    ...(requires ? { requires } : {}),
    ...(operatorGate ? { operatorGate } : {}),
  };
}

function parseHarnessPlatformCutoverPlanStringArray(value: unknown, stageId: string, field: string): string[] {
  if (!Array.isArray(value)) throw new Error(`platform cutover stage ${stageId} ${field} must be an array.`);
  return value.map((item, index) => {
    if (typeof item === "string" && item.length > 0) return item;
    throw new Error(`platform cutover stage ${stageId} ${field}[${index}] must be a non-empty string.`);
  });
}

function stringFromPlanStage(value: Record<string, unknown>, field: string, index: number): string {
  if (typeof value[field] === "string" && value[field].length > 0) return value[field];
  throw new Error(`platform cutover stage ${index} must include ${field}.`);
}

function isPlatformCutoverExecutionMode(value: string): value is HarnessPlatformCutoverPlanStage["executionMode"] {
  return value === "read-only" ||
    value === "long-running" ||
    value === "dry-run" ||
    value === "mutating" ||
    value === "verification";
}

function parseHarnessPlatformCutoverOperatorGate(value: unknown, stageId: string): HarnessPlatformCutoverPlanStage["operatorGate"] {
  if (!isRecord(value)) throw new Error(`platform cutover stage ${stageId} operatorGate must be an object.`);
  if (typeof value.id !== "string" || !value.id) {
    throw new Error(`platform cutover stage ${stageId} operatorGate.id is required.`);
  }
  if (typeof value.evidence !== "string" || !value.evidence) {
    throw new Error(`platform cutover stage ${stageId} operatorGate.evidence is required.`);
  }
  return { id: value.id, evidence: value.evidence };
}

function runPlatformCutoverStageCommand(
  commandArgs: string[],
  cwd: string,
): Promise<{ exitCode: number; stdoutBytes: number; stderrBytes: number }> {
  const [command, ...args] = commandArgs;
  if (!command) throw new Error("platform cutover stage commandArgs must include a command.");
  return new Promise((resolve) => {
    const child = spawn(command, args, {
      cwd,
      env: process.env,
      stdio: ["ignore", "pipe", "pipe"],
    });
    let stdoutBytes = 0;
    let stderrBytes = 0;
    child.stdout.on("data", (chunk: Buffer) => {
      stdoutBytes += chunk.byteLength;
    });
    child.stderr.on("data", (chunk: Buffer) => {
      stderrBytes += chunk.byteLength;
    });
    child.on("error", () => {
      resolve({ exitCode: 127, stdoutBytes, stderrBytes });
    });
    child.on("close", (code) => {
      resolve({ exitCode: code ?? 1, stdoutBytes, stderrBytes });
    });
  });
}

function platformPreflightServerUrl(options: HarnessServeCliOptions): string {
  if (options.publicUrl?.trim()) return normalizeHttpBaseUrl(options.publicUrl, "--public-url");
  const host = (options.host ?? "127.0.0.1").trim();
  const connectHost = host === "0.0.0.0" ? "127.0.0.1" : host === "::" ? "::1" : host;
  const urlHost = connectHost.includes(":") && !connectHost.startsWith("[") ? `[${connectHost}]` : connectHost;
  return normalizeHttpBaseUrl(`http://${urlHost}:${options.port ?? "8787"}`, "--host/--port");
}

function platformPreflightNextCommands(
  options: HarnessPlatformPreflightCliOptions,
  context: { baseUrl: string; tenant: string; project: string; provider: ControlPlaneProviderName },
): {
  ready: boolean;
  missingInputs: string[];
  cutoverReportArgs?: string[];
  smokeArgs?: string[];
} {
  const cutover = platformPreflightCutoverReportCommand(options, context);
  const smoke = cutoverSmokeCommand({
    url: context.baseUrl,
    tenant: context.tenant,
    tokenEnv: options.tokenEnv,
    adminTokenEnv: options.adminTokenEnv,
    controlPlaneProvider: context.provider,
    project: context.project,
    template: options.template,
    isolationTenant: options.isolationTenant,
    viewerTokenEnv: options.viewerTokenEnv,
    controlPlaneWebhookSecretEnv: options.controlPlaneWebhookSecretEnv ?? options.giteaWebhookSecretEnv,
  }, {
    baseUrl: context.baseUrl,
    tenant: context.tenant,
    provider: context.provider,
  });
  return {
    ready: cutover.ready && smoke.ready,
    missingInputs: Array.from(new Set([...cutover.missingInputs, ...smoke.missingInputs])),
    ...(cutover.args ? { cutoverReportArgs: cutover.args } : {}),
    ...(smoke.args ? { smokeArgs: smoke.args } : {}),
  };
}

function platformPreflightCutoverReportCommand(
  options: HarnessPlatformPreflightCliOptions,
  context: { baseUrl: string; tenant: string; project: string; provider: ControlPlaneProviderName },
): { ready: boolean; missingInputs: string[]; args?: string[] } {
  const missingInputs: string[] = [];
  const webhookSecretEnvOption = options.controlPlaneWebhookSecretEnv ?? options.giteaWebhookSecretEnv;
  const tokenEnv = options.tokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.tokenEnv, "--token-env");
  const adminTokenEnv = options.adminTokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.adminTokenEnv, "--admin-token-env");
  const template = parseProjectTemplateFlag(options.template ?? "vas-lite", "--template");
  const isolationTenant = options.isolationTenant === undefined
    ? undefined
    : parseSafeNameFlag(options.isolationTenant, "--isolation-tenant");
  const viewerTokenEnv = options.viewerTokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.viewerTokenEnv, "--viewer-token-env");
  const webhookSecretEnv = webhookSecretEnvOption === undefined
    ? undefined
    : parseEnvNameFlag(webhookSecretEnvOption, "--control-plane-webhook-secret-env");

  if (!tokenEnv) missingInputs.push("tokenEnv");
  if (!adminTokenEnv) missingInputs.push("adminTokenEnv");
  if (!isolationTenant) missingInputs.push("isolationTenant");
  if (!viewerTokenEnv) missingInputs.push("viewerTokenEnv");
  if (!webhookSecretEnv) missingInputs.push("controlPlaneWebhookSecretEnv");
  if (missingInputs.length) return { ready: false, missingInputs };

  return {
    ready: true,
    missingInputs: [],
    args: [
      "loom",
      "harness",
      "cutover-report",
      "--url",
      context.baseUrl,
      "--tenant",
      context.tenant,
      "--token-env",
      tokenEnv as string,
      "--admin-token-env",
      adminTokenEnv as string,
      "--control-plane-provider",
      context.provider,
      "--project",
      context.project,
      "--template",
      template,
      "--isolation-tenant",
      isolationTenant as string,
      "--viewer-token-env",
      viewerTokenEnv as string,
      "--control-plane-webhook-secret-env",
      webhookSecretEnv as string,
      "--report",
      "reports/cutover-report.json",
    ],
  };
}

function platformPreflightOutputSecrets(
  options: HarnessPlatformPreflightCliOptions,
  serveOptions: HarnessServeCliOptions,
  controlPlaneOptions: HarnessServeCliOptions,
): string[] {
  return Array.from(new Set([
    ...tenantTokenValues(options.tenantToken ?? []),
    ...tenantKeyTokenValues(options.tenantKey ?? []),
    ...tenantKeyEnvTokenValues(options.tenantKeyEnv ?? []),
    envSecretValue(serveOptions.modelKeyEnv),
    envSecretValue(controlPlaneOptions.giteaTokenEnv),
    envSecretValue(serveOptions.controlPlaneWebhookSecretEnv),
    envSecretValue(serveOptions.giteaWebhookSecretEnv),
  ].filter((value): value is string => typeof value === "string" && value.length > 0)));
}

function tenantTokenValues(values: string[]): string[] {
  return values.flatMap((value) => {
    const index = value.indexOf("=");
    return index > 0 && index < value.length - 1 ? [value.slice(index + 1)] : [];
  });
}

function tenantKeyTokenValues(values: string[]): string[] {
  return values.flatMap((value) => {
    const tenantSeparator = value.indexOf("=");
    if (tenantSeparator <= 0 || tenantSeparator === value.length - 1) return [];
    const tokenSeparator = value.indexOf(":", tenantSeparator + 1);
    return tokenSeparator > tenantSeparator + 1 ? [value.slice(tenantSeparator + 1, tokenSeparator)] : [];
  });
}

function tenantKeyEnvTokenValues(values: string[]): string[] {
  return values.flatMap((value) => {
    const tenantSeparator = value.indexOf("=");
    if (tenantSeparator <= 0 || tenantSeparator === value.length - 1) return [];
    const tokenSeparator = value.indexOf(":", tenantSeparator + 1);
    if (tokenSeparator <= tenantSeparator + 1) return [];
    const envName = value.slice(tenantSeparator + 1, tokenSeparator);
    const token = process.env[envName];
    return token ? [token] : [];
  });
}

function envSecretValue(envName: string | undefined): string | undefined {
  return envName ? process.env[envName] : undefined;
}

function redactJsonValue(value: unknown, secrets: string[]): unknown {
  if (typeof value === "string") {
    return secrets.reduce((text, secret) => text.split(secret).join("[redacted]"), value);
  }
  if (Array.isArray(value)) return value.map((item) => redactJsonValue(item, secrets));
  if (isRecord(value)) {
    return Object.fromEntries(Object.entries(value).map(([key, item]) => [key, redactJsonValue(item, secrets)]));
  }
  return value;
}

