async function verifySmokeRunCommentReplay(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  runId: string,
): Promise<Pick<HarnessSmokeOnlineResult, "onlineRunCommentAdded" | "onlineRunCommentReplayChecked" | "onlineRunCommentText">> {
  const onlineRunCommentText = "loom smoke online steering is durable";
  const clientId = "loom-smoke-workbench-a";
  const runUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runId)}`;
  const projectQuery = `project=${encodeURIComponent(project)}`;
  const commentResponse = await smokeJson(
    `${runUrl}/comments?${projectQuery}`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({ message: onlineRunCommentText, clientId }),
    },
    [201],
    "POST smoke run comment",
  );
  const commentType = stringFieldFromResponse(commentResponse.body, "type", "smoke run comment");
  if (commentType !== "user_message") throw new Error(`smoke run comment wrote ${JSON.stringify(commentType)}`);
  const commentSeq = numberFieldFromResponse(commentResponse.body, "seq", "smoke run comment");
  const commentData = recordFieldFromResponse(commentResponse.body, "data", "smoke run comment");
  const commentKind = stringFieldFromResponse(commentData, "kind", "smoke run comment data");
  const commentContent = stringFieldFromResponse(commentData, "content", "smoke run comment data");
  const commentClientId = stringFieldFromResponse(commentData, "clientId", "smoke run comment data");
  if (commentKind !== "comment" || commentContent !== onlineRunCommentText || commentClientId !== clientId) {
    throw new Error("smoke run comment did not preserve the expected collaborative steering payload");
  }

  const replayResponse = await smokeJson(`${runUrl}/replay?${projectQuery}`, { headers }, [200], "GET smoke run replay");
  const timeline = arrayFieldFromResponse(replayResponse.body, "timeline", "smoke run replay");
  const replayEntry = timeline.find((entry) => isRecord(entry) && entry.seq === commentSeq && entry.type === "user_message");
  if (!isRecord(replayEntry)) throw new Error("smoke run replay did not include the run comment");
  const replayTitle = stringFieldFromResponse(replayEntry, "title", "smoke run replay comment");
  const replayDetail = stringFieldFromResponse(replayEntry, "detail", "smoke run replay comment");
  if (!replayTitle.includes(onlineRunCommentText) || !replayDetail.includes(onlineRunCommentText)) {
    throw new Error("smoke run replay did not preserve the run comment details");
  }

  return {
    onlineRunCommentAdded: true,
    onlineRunCommentReplayChecked: true,
    onlineRunCommentText,
  };
}

async function verifySmokeFileCollab(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
): Promise<HarnessSmokeFileCollabResult> {
  const runFileCollabResult = await verifySmokeRunFileCollab(url, headers, tenant, project);
  const fileCollabPath = "loom-collab.txt";
  const staleClientId = "loom-smoke-collab-a";
  const activeEditorClientId = "loom-smoke-collab-b";
  const activeEditorLabel = "Loom Smoke Collab B";
  const freshContent = "fresh edit\n";
  const filesUrl = `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/files`;
  const fileUrl = `${filesUrl}?path=${encodeURIComponent(fileCollabPath)}`;

  await smokeJson(
    filesUrl,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({ path: fileCollabPath, content: "base edit\n", clientId: staleClientId }),
    },
    [200],
    "POST smoke collab base file",
  );

  const loaded = await smokeJson(fileUrl, { headers }, [200], "GET smoke collab base file");
  const loadedKind = stringFieldFromResponse(loaded.body, "kind", "smoke collab base file");
  if (loadedKind !== "file") throw new Error(`smoke collab base path was ${JSON.stringify(loadedKind)}`);
  const baseUpdatedAt = stringFieldFromResponse(loaded.body, "updatedAt", "smoke collab base file");

  await verifySmokePresence(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/presence`,
    headers,
    [{ clientId: activeEditorClientId, label: activeEditorLabel, focus: `file:${fileCollabPath}` }],
    "file collab presence",
  );

  let freshUpdatedAt = "";
  for (let attempt = 0; attempt < 3; attempt += 1) {
    await sleep(attempt === 0 ? 25 : 1100);
    const fresh = await smokeJson(
      filesUrl,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({ path: fileCollabPath, content: freshContent, clientId: activeEditorClientId }),
      },
      [200],
      "POST smoke collab fresh file",
    );
    freshUpdatedAt = stringFieldFromResponse(fresh.body, "updatedAt", "smoke collab fresh file");
    if (freshUpdatedAt !== baseUpdatedAt) break;
  }
  if (freshUpdatedAt === baseUpdatedAt) {
    throw new Error("smoke collab fresh save did not advance updatedAt for stale guard");
  }

  const staleSave = await smokeJson(
    filesUrl,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        path: fileCollabPath,
        content: "stale overwrite\n",
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "POST smoke collab stale save",
  );
  requireSmokeFileConflictEditor(staleSave.body, "smoke collab stale save", {
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${fileCollabPath}`,
  });

  const staleMove = await smokeJson(
    `${filesUrl}/move`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        fromPath: fileCollabPath,
        toPath: "loom-collab-moved.txt",
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "POST smoke collab stale move",
  );
  requireSmokeFileConflictEditor(staleMove.body, "smoke collab stale move", {
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${fileCollabPath}`,
  });

  const staleDelete = await smokeJson(
    fileUrl,
    {
      method: "DELETE",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "DELETE smoke collab stale delete",
  );
  requireSmokeFileConflictEditor(staleDelete.body, "smoke collab stale delete", {
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${fileCollabPath}`,
  });

  const latest = await smokeJson(fileUrl, { headers }, [200], "GET smoke collab latest file");
  const fileCollabReloadedContent = stringFieldFromResponse(latest.body, "content", "smoke collab latest file");
  if (fileCollabReloadedContent !== freshContent) {
    throw new Error(`smoke collab latest file was ${JSON.stringify(fileCollabReloadedContent)}`);
  }

  const audit = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/audit?project=${encodeURIComponent(project)}`,
    { headers },
    [200],
    "GET smoke collab audit",
  );
  if (!Array.isArray(audit.body)) throw new Error("smoke collab audit response was not an array");
  const sawFreshWrite = audit.body.some((event) =>
    isRecord(event) &&
    event.type === "workspace_file_written" &&
    isRecord(event.data) &&
    event.data.project === project &&
    event.data.path === fileCollabPath &&
    event.data.clientId === activeEditorClientId
  );
  if (!sawFreshWrite) throw new Error("smoke collab audit did not include the fresh workspace file write");

  return {
    fileCollabChecked: true,
    fileCollabPath,
    fileCollabBaseRead: true,
    fileCollabActiveEditorClientId: activeEditorClientId,
    fileCollabActiveEditorLabel: activeEditorLabel,
    fileCollabStaleSaveDenied: true,
    fileCollabStaleMoveDenied: true,
    fileCollabStaleDeleteDenied: true,
    fileCollabReloadedContent,
    fileCollabAuditChecked: true,
    ...runFileCollabResult,
  };
}

async function verifySmokeRunFileCollab(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
): Promise<Pick<
  HarnessSmokeFileCollabResult,
  | "runFileCollabChecked"
  | "runFileCollabRunId"
  | "runFileCollabPath"
  | "runFileCollabActiveEditorClientId"
  | "runFileCollabActiveEditorLabel"
  | "runFileCollabStaleSaveDenied"
  | "runFileCollabStaleMoveDenied"
  | "runFileCollabStaleDeleteDenied"
  | "runFileCollabReloadedContent"
  | "runFileCollabAuditChecked"
>> {
  const runFileCollabPath = "loom-run-collab.txt";
  const staleClientId = "loom-smoke-run-collab-a";
  const activeEditorClientId = "loom-smoke-run-collab-b";
  const activeEditorLabel = "Loom Smoke Run Collab B";
  const freshContent = "run fresh edit\n";
  const projectQuery = `project=${encodeURIComponent(project)}`;

  const runResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        ...smokeUngatedRunDefaults(),
        goal: "loom smoke run workspace file collaboration",
        script: [
          {
            message: "write run collab base",
            actions: [
              {
                toolName: "file.write",
                input: { path: runFileCollabPath, content: "run base edit\n" },
              },
            ],
          },
          { message: "finish run collab smoke", finish: true },
        ],
        verify: [`test -f ${runFileCollabPath}`],
        skills: ["smoke", "coding"],
        requester: { clientId: staleClientId },
      }),
    },
    [201],
    "POST smoke run collab run",
  );
  const runFileCollabRunId = stringFieldFromResponse(runResponse.body, "runId", "smoke run collab run");
  const runStatus = stringFieldFromResponse(runResponse.body, "status", "smoke run collab run");
  if (runStatus !== "passed") throw new Error(`smoke run collab run finished with status ${runStatus}`);

  const runUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runFileCollabRunId)}`;
  const filesUrl = `${runUrl}/files?${projectQuery}`;
  const fileUrl = `${filesUrl}&path=${encodeURIComponent(runFileCollabPath)}`;
  const loaded = await smokeJson(fileUrl, { headers }, [200], "GET smoke run collab base file");
  const loadedKind = stringFieldFromResponse(loaded.body, "kind", "smoke run collab base file");
  if (loadedKind !== "file") throw new Error(`smoke run collab base path was ${JSON.stringify(loadedKind)}`);
  const baseUpdatedAt = stringFieldFromResponse(loaded.body, "updatedAt", "smoke run collab base file");

  await verifySmokePresence(
    `${runUrl}/presence?${projectQuery}`,
    headers,
    [{ clientId: activeEditorClientId, label: activeEditorLabel, focus: `file:${runFileCollabPath}` }],
    "run file collab presence",
  );

  let freshUpdatedAt = "";
  for (let attempt = 0; attempt < 3; attempt += 1) {
    await sleep(attempt === 0 ? 25 : 1100);
    const fresh = await smokeJson(
      filesUrl,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({ path: runFileCollabPath, content: freshContent, clientId: activeEditorClientId }),
      },
      [200],
      "POST smoke run collab fresh file",
    );
    freshUpdatedAt = stringFieldFromResponse(fresh.body, "updatedAt", "smoke run collab fresh file");
    if (freshUpdatedAt !== baseUpdatedAt) break;
  }
  if (freshUpdatedAt === baseUpdatedAt) {
    throw new Error("smoke run collab fresh save did not advance updatedAt for stale guard");
  }

  const staleSave = await smokeJson(
    filesUrl,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        path: runFileCollabPath,
        content: "run stale overwrite\n",
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "POST smoke run collab stale save",
  );
  requireSmokeFileConflictEditor(staleSave.body, "smoke run collab stale save", {
    runId: runFileCollabRunId,
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${runFileCollabPath}`,
  });

  const staleMove = await smokeJson(
    `${runUrl}/files/move?${projectQuery}`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        fromPath: runFileCollabPath,
        toPath: "loom-run-collab-moved.txt",
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "POST smoke run collab stale move",
  );
  requireSmokeFileConflictEditor(staleMove.body, "smoke run collab stale move", {
    runId: runFileCollabRunId,
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${runFileCollabPath}`,
  });

  const staleDelete = await smokeJson(
    fileUrl,
    {
      method: "DELETE",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        baseUpdatedAt,
        clientId: staleClientId,
      }),
    },
    [409],
    "DELETE smoke run collab stale delete",
  );
  requireSmokeFileConflictEditor(staleDelete.body, "smoke run collab stale delete", {
    runId: runFileCollabRunId,
    clientId: activeEditorClientId,
    label: activeEditorLabel,
    focus: `file:${runFileCollabPath}`,
  });

  const latest = await smokeJson(fileUrl, { headers }, [200], "GET smoke run collab latest file");
  const runFileCollabReloadedContent = stringFieldFromResponse(latest.body, "content", "smoke run collab latest file");
  if (runFileCollabReloadedContent !== freshContent) {
    throw new Error(`smoke run collab latest file was ${JSON.stringify(runFileCollabReloadedContent)}`);
  }

  const audit = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/audit?${projectQuery}`,
    { headers },
    [200],
    "GET smoke run collab audit",
  );
  if (!Array.isArray(audit.body)) throw new Error("smoke run collab audit response was not an array");
  const sawFreshWrite = audit.body.some((event) =>
    isRecord(event) &&
    event.type === "workspace_file_written" &&
    isRecord(event.data) &&
    event.data.project === project &&
    event.data.runId === runFileCollabRunId &&
    event.data.path === runFileCollabPath &&
    event.data.clientId === activeEditorClientId
  );
  if (!sawFreshWrite) throw new Error("smoke run collab audit did not include the fresh run workspace file write");

  return {
    runFileCollabChecked: true,
    runFileCollabRunId,
    runFileCollabPath,
    runFileCollabActiveEditorClientId: activeEditorClientId,
    runFileCollabActiveEditorLabel: activeEditorLabel,
    runFileCollabStaleSaveDenied: true,
    runFileCollabStaleMoveDenied: true,
    runFileCollabStaleDeleteDenied: true,
    runFileCollabReloadedContent,
    runFileCollabAuditChecked: true,
  };
}

function requireSmokeFileConflictEditor(
  body: unknown,
  label: string,
  expected: { runId?: string; clientId: string; label: string; focus: string },
): void {
  const activeEditors = arrayFieldFromResponse(body, "activeEditors", label);
  const activeEditor = activeEditors.find((entry) =>
    isRecord(entry) &&
    (expected.runId === undefined || entry.runId === expected.runId) &&
    entry.clientId === expected.clientId &&
    entry.label === expected.label &&
    entry.focus === expected.focus
  );
  if (!isRecord(activeEditor)) {
    throw new Error(`${label} did not include the active same-file editor`);
  }
}

async function verifySmokeAuthRoles(
  url: string,
  developerHeaders: Record<string, string>,
  options: HarnessSmokeCliOptions,
  tenant: string,
  project: string,
  runId: string,
): Promise<HarnessSmokeAuthRolesResult> {
  const viewerToken = smokeViewerToken(options);
  if (!viewerToken) {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_TOKEN_MISSING",
      "--check-auth-roles requires --viewer-token or --viewer-token-env",
      { scope: "auth-roles", tenant, required: ["--viewer-token", "--viewer-token-env"] },
    );
  }
  const viewerHeaders = smokeHeaders(viewerToken);

  const developerAccess = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/access`,
    { headers: developerHeaders },
    [200],
    "GET smoke developer access",
  );
  const developerAccessActor = stringFieldFromResponse(developerAccess.body, "actor", "smoke developer access");
  const developerRole = stringFieldFromResponse(developerAccess.body, "role", "smoke developer access");
  if (developerRole !== "developer" && developerRole !== "admin") {
    throw new Error(`smoke developer token reported role ${JSON.stringify(developerRole)}`);
  }
  const developerAccessRole: "developer" | "admin" = developerRole;

  const viewerAccess = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/access`,
    { headers: viewerHeaders },
    [200],
    "GET smoke viewer access",
  );
  const viewerAccessActor = stringFieldFromResponse(viewerAccess.body, "actor", "smoke viewer access");
  const viewerAccessRole = stringFieldFromResponse(viewerAccess.body, "role", "smoke viewer access");
  if (viewerAccessRole !== "viewer") {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_ROLE_MISMATCH",
      `smoke viewer token reported role ${JSON.stringify(viewerAccessRole)}`,
      {
        scope: "auth-roles",
        tenant,
        expectedRole: "viewer",
        actualRole: viewerAccessRole,
      },
    );
  }

  const viewerTenantStatus = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/status`,
    { headers: viewerHeaders },
    [200],
    "GET smoke viewer tenant status",
  );
  const viewerReadiness = recordFieldFromResponse(viewerTenantStatus.body, "readiness", "smoke viewer tenant status");
  const viewerTenantReadinessProfile = typeof viewerReadiness.profile === "string" ? viewerReadiness.profile : undefined;
  const viewerTenantReadinessOk = booleanFieldFromResponse(viewerReadiness, "ok", "smoke viewer tenant status readiness");
  const viewerTenantReadinessMissing = arrayFieldFromResponse(viewerReadiness, "missing", "smoke viewer tenant status readiness");
  if (!viewerTenantReadinessMissing.every((item): item is string => typeof item === "string")) {
    throw new Error("smoke viewer tenant status readiness missing must be strings");
  }
  if (!viewerTenantReadinessOk) {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_READINESS_MISSING",
      `smoke viewer tenant status missing readiness: ${viewerTenantReadinessMissing.join(", ")}`,
      {
        scope: "auth-roles",
        tenant,
        profile: viewerTenantReadinessProfile ?? null,
        missing: viewerTenantReadinessMissing,
      },
    );
  }
  const viewerGoldenPath = verifySmokeStatusGoldenPath("auth-roles", viewerTenantReadinessProfile, viewerReadiness, tenant);
  const viewerVisionLock = recordFieldFromResponse(viewerTenantStatus.body, "visionLock", "smoke viewer tenant status");
  const viewerTenantVisionLockTarget = stringFieldFromResponse(viewerVisionLock, "target", "smoke viewer tenant status visionLock");
  const missingViewerTargetMarkers = SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS
    .filter((marker) => !viewerTenantVisionLockTarget.includes(marker));
  if (missingViewerTargetMarkers.length) {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_VISION_LOCK_TARGET_MISMATCH",
      "smoke viewer tenant status reported an unexpected vision lock target",
      {
        scope: "auth-roles",
        tenant,
        actualTarget: viewerTenantVisionLockTarget,
        missingTargetMarkers: missingViewerTargetMarkers,
        requiredTargetMarkers: SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS,
      },
    );
  }
  const viewerTenantVisionLockMvpIsScopeReduction = booleanFieldFromResponse(viewerVisionLock, "mvpIsScopeReduction", "smoke viewer tenant status visionLock");
  if (viewerTenantVisionLockMvpIsScopeReduction !== false) {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_VISION_LOCK_SCOPE_REDUCTION",
      "smoke viewer tenant status reported MVP as a scope reduction",
      {
        scope: "auth-roles",
        tenant,
        mvpIsScopeReduction: viewerTenantVisionLockMvpIsScopeReduction,
      },
    );
  }
  const viewerTenantVisionLockCapabilities = arrayFieldFromResponse(viewerVisionLock, "capabilities", "smoke viewer tenant status visionLock");
  if (!viewerTenantVisionLockCapabilities.every((capability): capability is string => typeof capability === "string")) {
    throw new Error("smoke viewer tenant status visionLock capabilities must be strings");
  }
  const missingViewerVisionCapabilities = SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES
    .filter((capability) => !viewerTenantVisionLockCapabilities.includes(capability));
  if (missingViewerVisionCapabilities.length) {
    throw smokeCheckError(
      "SMOKE_AUTH_VIEWER_VISION_LOCK_CAPABILITIES_MISSING",
      `smoke viewer tenant status missing vision lock capabilities: ${missingViewerVisionCapabilities.join(", ")}`,
      {
        scope: "auth-roles",
        tenant,
        missingCapabilities: missingViewerVisionCapabilities,
        requiredCapabilities: SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES,
      },
    );
  }

  await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...viewerHeaders, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        goal: "viewer must not create smoke runs",
        script: [{ message: "finish", finish: true }],
        requester: { clientId: "loom-smoke-viewer" },
      }),
    },
    [403],
    "POST smoke viewer run create denial",
  );
  await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/files`,
    {
      method: "POST",
      headers: { ...viewerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ path: "viewer-denied.txt", content: "denied\n", clientId: "loom-smoke-viewer" }),
    },
    [403],
    "POST smoke viewer workspace write denial",
  );

  const viewerCommentText = "loom smoke viewer comment is durable";
  const runUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runId)}`;
  const projectQuery = `project=${encodeURIComponent(project)}`;
  const commentResponse = await smokeJson(
    `${runUrl}/comments?${projectQuery}`,
    {
      method: "POST",
      headers: { ...viewerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ message: viewerCommentText, clientId: "loom-smoke-viewer" }),
    },
    [201],
    "POST smoke viewer run comment",
  );
  const commentSeq = numberFieldFromResponse(commentResponse.body, "seq", "smoke viewer run comment");
  const commentData = recordFieldFromResponse(commentResponse.body, "data", "smoke viewer run comment");
  const commentActor = stringFieldFromResponse(commentData, "actor", "smoke viewer run comment data");
  const commentRole = stringFieldFromResponse(commentData, "role", "smoke viewer run comment data");
  const commentContent = stringFieldFromResponse(commentData, "content", "smoke viewer run comment data");
  if (commentActor !== viewerAccessActor || commentRole !== "viewer" || commentContent !== viewerCommentText) {
    throw new Error("smoke viewer run comment did not preserve actor/role/content");
  }

  const replayResponse = await smokeJson(
    `${runUrl}/replay?${projectQuery}`,
    { headers: viewerHeaders },
    [200],
    "GET smoke viewer run replay",
  );
  const timeline = arrayFieldFromResponse(replayResponse.body, "timeline", "smoke viewer run replay");
  const replayEntry = timeline.find((entry) =>
    isRecord(entry) &&
    entry.seq === commentSeq &&
    entry.type === "user_message" &&
    entry.role === "viewer"
  );
  if (!isRecord(replayEntry)) throw new Error("smoke viewer run replay did not include the viewer comment");
  const replayTitle = stringFieldFromResponse(replayEntry, "title", "smoke viewer replay comment");
  const replayDetail = stringFieldFromResponse(replayEntry, "detail", "smoke viewer replay comment");
  if (!replayTitle.includes(viewerCommentText) || !replayDetail.includes(viewerCommentText)) {
    throw new Error("smoke viewer run replay did not preserve the viewer comment details");
  }

  return {
    authRolesChecked: true,
    developerAccessActor,
    developerAccessRole,
    viewerAccessActor,
    viewerAccessRole: "viewer",
    viewerTenantReadinessChecked: true,
    viewerTenantReadinessProfile,
    viewerTenantReadinessOk,
    viewerTenantReadinessMissing,
    viewerTenantGoldenPathChecked: true,
    viewerTenantGoldenPathOk: viewerGoldenPath.ok,
    viewerTenantGoldenPathCapabilities: viewerGoldenPath.capabilities,
    viewerTenantGoldenPathMissingCapabilities: viewerGoldenPath.missingCapabilities,
    viewerTenantVisionLockChecked: true,
    viewerTenantVisionLockTarget,
    viewerTenantVisionLockMvpIsScopeReduction,
    viewerTenantVisionLockCapabilities,
    viewerCreateRunDenied: true,
    viewerWorkspaceWriteDenied: true,
    viewerRunCommentAdded: true,
    viewerRunCommentReplayChecked: true,
  };
}

async function verifySmokeGates(
  url: string,
  developerHeaders: Record<string, string>,
  options: HarnessSmokeCliOptions,
  tenant: string,
  project: string,
): Promise<HarnessSmokeGateResult> {
  const adminToken = smokeAdminToken(options);
  if (!adminToken) throw new Error("--check-gates requires --admin-token or --admin-token-env");
  const adminHeaders = smokeHeaders(adminToken);
  const adminAccess = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/access`,
    { headers: adminHeaders },
    [200],
    "GET smoke admin access",
  );
  const adminRole = stringFieldFromResponse(adminAccess.body, "role", "smoke admin access");
  if (adminRole !== "admin") throw new Error(`smoke admin token reported role ${JSON.stringify(adminRole)}`);

  const gateRunResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        goal: "loom smoke review and deployment gates",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["smoke", "coding"],
        reviewRequired: true,
        deploymentRequired: true,
        requester: { clientId: "loom-smoke-gates" },
      }),
    },
    [201],
    "POST smoke gated run",
  );
  const gateRunId = stringFieldFromResponse(gateRunResponse.body, "runId", "smoke gated run");
  const reviewGateRunStatus = stringFieldFromResponse(gateRunResponse.body, "status", "smoke gated run");
  if (reviewGateRunStatus !== "review_required") {
    throw new Error(`smoke gated run finished with status ${JSON.stringify(reviewGateRunStatus)}`);
  }
  const initialReview = recordFieldFromResponse(gateRunResponse.body, "review", "smoke gated run");
  const initialReviewStatus = stringFieldFromResponse(initialReview, "status", "smoke gated run review");
  if (initialReviewStatus !== "pending") throw new Error("smoke gated run did not open review gate");
  const initialDeployment = recordFieldFromResponse(gateRunResponse.body, "deployment", "smoke gated run");
  const initialDeploymentStatus = stringFieldFromResponse(initialDeployment, "status", "smoke gated run deployment");
  if (initialDeploymentStatus !== "pending") throw new Error("smoke gated run did not preserve deployment gate");

  const reviewGateMetrics = options.checkMetrics
    ? await verifySmokeMetrics(url, adminHeaders, options, tenant, project)
    : undefined;
  if (reviewGateMetrics && reviewGateMetrics.metricsReviewRequiredRuns < 1) {
    throw smokeCheckError(
      "SMOKE_GATE_METRICS_MISSING",
      "smoke metrics did not expose the pending review gate backlog",
      { scope: "metrics", metric: "loom_harness_review_required_runs", actual: reviewGateMetrics.metricsReviewRequiredRuns },
    );
  }

  const gateRunUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(gateRunId)}`;
  const projectQuery = `project=${encodeURIComponent(project)}`;
  const reviewResponse = await smokeJson(
    `${gateRunUrl}/review?${projectQuery}`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved", note: "loom smoke review approved", clientId: "loom-smoke-review" }),
    },
    [200],
    "POST smoke review gate",
  );
  const deploymentGateRunStatus = stringFieldFromResponse(reviewResponse.body, "status", "smoke reviewed gated run");
  if (deploymentGateRunStatus !== "deployment_required") {
    throw new Error(`smoke reviewed gated run finished with status ${JSON.stringify(deploymentGateRunStatus)}`);
  }
  const reviewed = recordFieldFromResponse(reviewResponse.body, "review", "smoke reviewed gated run");
  const reviewDecision = stringFieldFromResponse(reviewed, "status", "smoke reviewed gated run review");
  if (reviewDecision !== "approved") throw new Error("smoke review gate was not approved");

  const deploymentGateMetrics = options.checkMetrics
    ? await verifySmokeMetrics(url, adminHeaders, options, tenant, project)
    : undefined;
  if (deploymentGateMetrics && deploymentGateMetrics.metricsDeploymentRequiredRuns < 1) {
    throw smokeCheckError(
      "SMOKE_GATE_METRICS_MISSING",
      "smoke metrics did not expose the pending deployment gate backlog",
      { scope: "metrics", metric: "loom_harness_deployment_required_runs", actual: deploymentGateMetrics.metricsDeploymentRequiredRuns },
    );
  }

  await smokeJson(
    `${gateRunUrl}/deployment?${projectQuery}`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved", note: "developer cannot deploy", clientId: "loom-smoke-dev-deploy" }),
    },
    [403],
    "POST smoke developer deployment denial",
  );

  const deploymentResponse = await smokeJson(
    `${gateRunUrl}/deployment?${projectQuery}`,
    {
      method: "POST",
      headers: { ...adminHeaders, "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved", note: "loom smoke deployment approved", clientId: "loom-smoke-deploy" }),
    },
    [200],
    "POST smoke deployment gate",
  );
  const gateRunFinalStatus = stringFieldFromResponse(deploymentResponse.body, "status", "smoke deployed gated run");
  if (gateRunFinalStatus !== "passed") throw new Error(`smoke deployed gated run finished with status ${gateRunFinalStatus}`);
  const deployment = recordFieldFromResponse(deploymentResponse.body, "deployment", "smoke deployed gated run");
  const deploymentDecision = stringFieldFromResponse(deployment, "status", "smoke deployed gated run deployment");
  if (deploymentDecision !== "approved") throw new Error("smoke deployment gate was not approved");

  const eventsResponse = await smokeJson(`${gateRunUrl}/events?${projectQuery}`, { headers: developerHeaders }, [200], "GET smoke gated run events");
  if (!Array.isArray(eventsResponse.body)) throw new Error("smoke gated run events response was not an array");
  const reviewEvent = eventsResponse.body.find((event) =>
    isRecord(event) &&
    event.type === "review_gate" &&
    isRecord(event.data) &&
    event.data.status === "approved"
  );
  const deploymentEvent = eventsResponse.body.find((event) =>
    isRecord(event) &&
    event.type === "deployment_gate" &&
    isRecord(event.data) &&
    event.data.status === "approved"
  );
  if (!isRecord(reviewEvent) || !isRecord(reviewEvent.data) || reviewEvent.data.role !== "developer") {
    throw new Error("smoke gated run events did not include the developer review decision");
  }
  if (!isRecord(deploymentEvent) || !isRecord(deploymentEvent.data) || deploymentEvent.data.role !== "admin") {
    throw new Error("smoke gated run events did not include the admin deployment decision");
  }

  return {
    gatesChecked: true,
    gateRunId,
    reviewGateChecked: true,
    reviewGateRunStatus: "review_required",
    reviewGateDecision: "approved",
    reviewGateDecidedRole: "developer",
    reviewGateMetricsChecked: reviewGateMetrics ? true : undefined,
    reviewGateMetricsReviewRequiredRuns: reviewGateMetrics?.metricsReviewRequiredRuns,
    deploymentGateChecked: true,
    deploymentGateDeveloperDenied: true,
    deploymentGateRunStatus: "deployment_required",
    deploymentGateDecision: "approved",
    deploymentGateDecidedRole: "admin",
    deploymentGateMetricsChecked: deploymentGateMetrics ? true : undefined,
    deploymentGateMetricsDeploymentRequiredRuns: deploymentGateMetrics?.metricsDeploymentRequiredRuns,
    gateRunFinalStatus: "passed",
  };
}

async function verifySmokePolicyEscalation(
  url: string,
  developerHeaders: Record<string, string>,
  options: HarnessSmokeCliOptions,
  tenant: string,
  project: string,
): Promise<HarnessSmokePolicyEscalationResult> {
  const adminToken = smokeAdminToken(options);
  if (!adminToken) throw new Error("--check-escalations requires --admin-token or --admin-token-env");
  const adminHeaders = smokeHeaders(adminToken);
  const requestedTool = "shell.exec";
  const workspaceByteWarning = 12_345_678;
  const escalationResponse = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/policy/escalations`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({
        requestedTools: [requestedTool],
        limits: { workspaceByteWarning },
        source: {
          kind: "workspace_pr",
          project,
          detail: "loom smoke validates admin-approved policy escalation",
        },
        reason: "loom smoke needs a temporary shell permission path",
        clientId: "loom-smoke-escalation",
      }),
    },
    [201],
    "POST smoke policy escalation",
  );
  const policyEscalationId = stringFieldFromResponse(escalationResponse.body, "id", "smoke policy escalation");
  const escalationStatus = stringFieldFromResponse(escalationResponse.body, "status", "smoke policy escalation");
  if (escalationStatus !== "pending") throw new Error(`smoke policy escalation status was ${JSON.stringify(escalationStatus)}`);
  const requestedTools = arrayFieldFromResponse(escalationResponse.body, "requestedTools", "smoke policy escalation");
  if (!requestedTools.includes(requestedTool)) throw new Error("smoke policy escalation did not request shell.exec");
  const source = recordFieldFromResponse(escalationResponse.body, "source", "smoke policy escalation");
  const sourceKind = stringFieldFromResponse(source, "kind", "smoke policy escalation source");
  if (sourceKind !== "workspace_pr") throw new Error(`smoke policy escalation source was ${JSON.stringify(sourceKind)}`);

  const listedResponse = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/policy/escalations`,
    { headers: developerHeaders },
    [200],
    "GET smoke policy escalations",
  );
  if (!Array.isArray(listedResponse.body) || !listedResponse.body.some((item) => isRecord(item) && item.id === policyEscalationId)) {
    throw new Error("smoke policy escalation list did not include the requested escalation");
  }

  await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/policy/escalations/${encodeURIComponent(policyEscalationId)}/decision`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved", note: "developer cannot approve escalation", clientId: "loom-smoke-dev-escalation" }),
    },
    [403],
    "POST smoke developer escalation decision denial",
  );

  const decisionResponse = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/policy/escalations/${encodeURIComponent(policyEscalationId)}/decision`,
    {
      method: "POST",
      headers: { ...adminHeaders, "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved", note: "loom smoke approved escalation", clientId: "loom-smoke-admin-escalation" }),
    },
    [200],
    "POST smoke admin escalation decision",
  );
  const policyEscalationStatus = stringFieldFromResponse(decisionResponse.body, "status", "smoke admin escalation decision");
  if (policyEscalationStatus !== "approved") throw new Error(`smoke admin escalation status was ${JSON.stringify(policyEscalationStatus)}`);
  const policyEscalationDecidedRole = stringFieldFromResponse(decisionResponse.body, "decidedRole", "smoke admin escalation decision");
  if (policyEscalationDecidedRole !== "admin") throw new Error(`smoke admin escalation decidedRole was ${JSON.stringify(policyEscalationDecidedRole)}`);
  const policyChange = recordFieldFromResponse(decisionResponse.body, "policyChange", "smoke admin escalation decision");
  const allowedToolsChange = recordFieldFromResponse(policyChange, "allowedTools", "smoke admin escalation policy change");
  const addedTools = arrayFieldFromResponse(allowedToolsChange, "added", "smoke admin escalation allowedTools change");
  if (!addedTools.includes(requestedTool)) throw new Error("smoke admin escalation did not add shell.exec");
  const limitsChange = recordFieldFromResponse(policyChange, "limits", "smoke admin escalation policy change");
  const changedLimits = arrayFieldFromResponse(limitsChange, "changed", "smoke admin escalation limits change");
  if (!changedLimits.includes("workspaceByteWarning")) throw new Error("smoke admin escalation did not change workspaceByteWarning");

  const policyResponse = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/policy`,
    { headers: developerHeaders },
    [200],
    "GET smoke policy after escalation",
  );
  const policyAllowedTools = arrayFieldFromResponse(policyResponse.body, "allowedTools", "smoke policy after escalation");
  if (!policyAllowedTools.includes(requestedTool)) throw new Error("smoke policy did not include shell.exec after escalation");
  const policyLimits = recordFieldFromResponse(policyResponse.body, "limits", "smoke policy after escalation");
  const policyWorkspaceByteWarning = numberFieldFromResponse(policyLimits, "workspaceByteWarning", "smoke policy limits after escalation");
  if (policyWorkspaceByteWarning !== workspaceByteWarning) {
    throw new Error(`smoke policy workspaceByteWarning was ${policyWorkspaceByteWarning}`);
  }

  const auditResponse = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/audit`,
    { headers: developerHeaders },
    [200],
    "GET smoke audit after escalation",
  );
  if (!Array.isArray(auditResponse.body)) throw new Error("smoke audit response was not an array");
  const requested = auditResponse.body.some((event) =>
    isRecord(event) &&
    event.type === "tenant_policy_escalation_requested" &&
    isRecord(event.data) &&
    event.data.escalationId === policyEscalationId &&
    event.data.clientId === "loom-smoke-escalation"
  );
  const decided = auditResponse.body.some((event) =>
    isRecord(event) &&
    event.type === "tenant_policy_escalation_decided" &&
    isRecord(event.data) &&
    event.data.escalationId === policyEscalationId &&
    event.data.decision === "approved" &&
    event.data.clientId === "loom-smoke-admin-escalation"
  );
  const updated = auditResponse.body.some((event) =>
    isRecord(event) &&
    event.type === "tenant_policy_updated" &&
    isRecord(event.data) &&
    event.data.escalationId === policyEscalationId
  );
  if (!requested || !decided || !updated) throw new Error("smoke audit did not include the full policy escalation trail");

  return {
    policyEscalationChecked: true,
    policyEscalationId,
    policyEscalationStatus: "approved",
    policyEscalationRequestedTool: "shell.exec",
    policyEscalationSourceKind: "workspace_pr",
    policyEscalationDeveloperDecisionDenied: true,
    policyEscalationDecidedRole: "admin",
    policyEscalationToolAdded: true,
    policyEscalationLimitChanged: true,
    policyEscalationAuditChecked: true,
  };
}

async function verifySmokeProjectSourceDefaults(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
): Promise<HarnessSmokeSourceDefaults> {
  await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/source-defaults`,
    {
      method: "PUT",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        ...SMOKE_SOURCE_DEFAULTS,
        clientId: "loom-smoke-source-defaults",
      }),
    },
    [200],
    "PUT smoke project source defaults",
  );

  const projectSummary = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}`,
    { headers },
    [200],
    "GET smoke project source defaults",
  );
  const repo = stringFieldFromResponse(projectSummary.body, "repo", "smoke project source defaults");
  const branch = stringFieldFromResponse(projectSummary.body, "branch", "smoke project source defaults");
  const baseBranch = stringFieldFromResponse(projectSummary.body, "baseBranch", "smoke project source defaults");
  const issue = stringFieldFromResponse(projectSummary.body, "issue", "smoke project source defaults");
  if (
    repo !== SMOKE_SOURCE_DEFAULTS.repo ||
    branch !== SMOKE_SOURCE_DEFAULTS.branch ||
    baseBranch !== SMOKE_SOURCE_DEFAULTS.baseBranch ||
    issue !== SMOKE_SOURCE_DEFAULTS.issue
  ) {
    throw smokeCheckError(
      "SMOKE_SOURCE_DEFAULTS_DRIFT",
      `project ${tenant}/${project} source defaults did not round-trip`,
      {
        scope: "source-defaults",
        tenant,
        project,
        expected: SMOKE_SOURCE_DEFAULTS,
        actual: { repo, branch, baseBranch, issue },
      },
    );
  }

  return { repo, branch, baseBranch, issue };
}

function verifySmokeRunSourceDefaults(source: unknown, expected: HarnessSmokeSourceDefaults): HarnessSmokeSourceDefaultsResult {
  const metadata = recordFieldFromResponse(source, "metadata", "smoke source-defaulted run");
  const repo = stringFieldFromResponse(metadata, "repo", "smoke source-defaulted run metadata");
  const branch = stringFieldFromResponse(metadata, "branch", "smoke source-defaulted run metadata");
  const baseBranch = stringFieldFromResponse(metadata, "baseBranch", "smoke source-defaulted run metadata");
  const issue = stringFieldFromResponse(metadata, "issue", "smoke source-defaulted run metadata");
  const issueUrl = typeof metadata.issueUrl === "string" ? metadata.issueUrl : undefined;
  if (repo !== expected.repo || branch !== expected.branch || baseBranch !== expected.baseBranch || issue !== expected.issue) {
    throw smokeCheckError(
      "SMOKE_SOURCE_DEFAULTS_RUN_DRIFT",
      "smoke run did not inherit project source defaults",
      {
        scope: "source-defaults",
        expected,
        actual: { repo, branch, baseBranch, issue },
      },
    );
  }
  return {
    sourceDefaultsChecked: true,
    sourceDefaultsRepo: repo,
    sourceDefaultsBranch: branch,
    sourceDefaultsBaseBranch: baseBranch,
    sourceDefaultsIssue: issue,
    sourceDefaultsIssueUrl: issueUrl,
  };
}

function verifySmokeSourceDefaultsMetadata(
  source: unknown,
  expected: HarnessSmokeSourceDefaultsResult,
  label: string,
): HarnessSmokeSourceDefaults & { issueUrl?: string } {
  const repo = stringFieldFromResponse(source, "repo", label);
  const branch = stringFieldFromResponse(source, "branch", label);
  const baseBranch = stringFieldFromResponse(source, "baseBranch", label);
  const issue = stringFieldFromResponse(source, "issue", label);
  const issueUrl = typeof (source as Record<string, unknown>).issueUrl === "string"
    ? (source as Record<string, string>).issueUrl
    : undefined;
  if (
    repo !== expected.sourceDefaultsRepo ||
    branch !== expected.sourceDefaultsBranch ||
    baseBranch !== expected.sourceDefaultsBaseBranch ||
    issue !== expected.sourceDefaultsIssue ||
    (expected.sourceDefaultsIssueUrl !== undefined && issueUrl !== expected.sourceDefaultsIssueUrl)
  ) {
    throw smokeCheckError(
      "SMOKE_SOURCE_DEFAULTS_HANDOFF_DRIFT",
      `${label} did not preserve source defaults`,
      {
        scope: "handoff",
        expected: {
          repo: expected.sourceDefaultsRepo,
          branch: expected.sourceDefaultsBranch,
          baseBranch: expected.sourceDefaultsBaseBranch,
          issue: expected.sourceDefaultsIssue,
          issueUrl: expected.sourceDefaultsIssueUrl,
        },
        actual: { repo, branch, baseBranch, issue, issueUrl },
      },
    );
  }
  return { repo, branch, baseBranch, issue, issueUrl };
}

async function verifySmokeRunScopedPullRequestDuringActiveRun(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  runId: string,
  sourceDefaults: HarnessSmokeSourceDefaultsResult,
): Promise<{
  runScopedPullRequestDuringActiveRunChecked: true;
  runScopedPullRequestDuringActiveRunId: string;
  runScopedPullRequestDuringActiveRunBranch: string;
  runScopedPullRequestDuringActiveRunCommit: string;
  runScopedPullRequestDuringActiveRunPush: false;
  runScopedPullRequestDuringActiveRunIndex?: number;
  runScopedPullRequestDuringActiveRunUrl?: string;
  runScopedFileWriteDuringActiveRunChecked: true;
  runScopedFileWriteDuringActiveRunBlockedRunId: string;
  runScopedFileWriteDuringActiveRunAllowedRunId: string;
  runScopedFileWriteDuringActiveRunPath: string;
  runScopedFileWriteDuringActiveRunDenied: true;
  agentGitServiceHandoffWorkspaceAttachmentChecked?: true;
  agentGitServiceHandoffWorkspaceAttachmentWorkspaceId?: string;
  agentGitServiceHandoffWorkspaceAttachmentId?: string;
  agentGitServiceHandoffWorkspaceAttachmentUrl?: string;
  agentGitServiceHandoffPackageUrl?: string;
  agentGitServiceHandoffFollowupsUrl?: string;
}> {
  const encodedTenant = encodeURIComponent(tenant);
  const encodedProject = encodeURIComponent(project);
  let activeRunId: string | undefined;

  try {
    const activeRun = await smokeJson(
      `${url}/runs`,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({
          async: true,
          tenant,
          project,
          ...smokeUngatedRunDefaults(),
          goal: "loom smoke holds an isolated workspace during run-scoped PR handoff",
          allowedTools: ["shell.exec", "verify.run"],
          script: [
            {
              message: "hold an active isolated workspace",
              actions: [
                {
                  toolName: "shell.exec",
                  input: { command: "sleep 15; printf active > loom-smoke-active-run.txt" },
                },
              ],
            },
            { message: "finish active workspace holder", finish: true },
          ],
          verify: ["test -f loom-smoke-active-run.txt"],
          skills: ["smoke", "coding"],
          requester: { clientId: "loom-smoke-run-scoped-pr-active" },
        }),
      },
      [202],
      "POST smoke active run for run-scoped PR handoff",
    );
    activeRunId = stringFieldFromResponse(activeRun.body, "runId", "smoke active run");
    const activeStatus = stringFieldFromResponse(activeRun.body, "status", "smoke active run");
    if (activeStatus !== "running") {
      throw new Error(`smoke active run status was ${JSON.stringify(activeStatus)}`);
    }

    const fileWritePath = "loom-smoke-run-scoped-file.txt";
    const blockedWrite = await smokeJson(
      `${url}/tenants/${encodedTenant}/runs/${encodeURIComponent(activeRunId)}/files?project=${encodedProject}`,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({
          path: fileWritePath,
          content: "this write must not land while the active run owns the workspace\n",
          clientId: "loom-smoke-run-scoped-file-blocked",
        }),
      },
      [409],
      "POST smoke active run workspace file write",
    );
    const blockedError = stringFieldFromResponse(blockedWrite.body, "error", "smoke active run workspace file write");
    if (!blockedError.includes(activeRunId)) {
      throw smokeCheckError(
        "SMOKE_RUN_SCOPED_FILE_LOCK_MISMATCH",
        "active run file write conflict did not identify the active run",
        { scope: "handoff", tenant, project, activeRunId, error: blockedError },
      );
    }

    const allowedWrite = await smokeJson(
      `${url}/tenants/${encodedTenant}/runs/${encodeURIComponent(runId)}/files?project=${encodedProject}`,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({
          path: fileWritePath,
          content: "run-scoped file write allowed while another isolated run is active\n",
          clientId: "loom-smoke-run-scoped-file-allowed",
        }),
      },
      [200],
      "POST smoke completed run workspace file write during active run",
    );
    const allowedPath = stringFieldFromResponse(allowedWrite.body, "path", "smoke completed run workspace file write");
    if (allowedPath !== fileWritePath) {
      throw smokeCheckError(
        "SMOKE_RUN_SCOPED_FILE_WRITE_PATH_DRIFT",
        "completed run file write during another active run wrote an unexpected path",
        { scope: "handoff", tenant, project, runId, expectedPath: fileWritePath, actualPath: allowedPath },
      );
    }

    const commit = "loomsmoke";
    const created = await smokeJson(
      `${url}/tenants/${encodedTenant}/runs/${encodeURIComponent(runId)}/pull-requests?project=${encodedProject}`,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify({
          title: "Smoke run-scoped handoff while another run is active",
          commit,
          push: false,
          clientId: "loom-smoke-run-scoped-pr",
        }),
      },
      [201],
      "POST smoke run-scoped PR during active run",
    );
    const responseRunId = stringFieldFromResponse(created.body, "runId", "smoke run-scoped PR");
    if (responseRunId !== runId) throw new Error("smoke run-scoped PR targeted the wrong run");
    const branch = stringFieldFromResponse(created.body, "branch", "smoke run-scoped PR");
    const expectedBranch = `${sourceDefaults.sourceDefaultsBranch}/${runId}`;
    if (branch !== expectedBranch) {
      throw smokeCheckError(
        "SMOKE_RUN_SCOPED_PR_BRANCH_DRIFT",
        "run-scoped PR during another active run did not derive a run-unique branch",
        { scope: "handoff", tenant, project, runId, expectedBranch, actualBranch: branch },
      );
    }
    const responseCommit = stringFieldFromResponse(created.body, "commit", "smoke run-scoped PR");
    if (responseCommit !== commit) throw new Error("smoke run-scoped PR commit did not round-trip");
    const push = booleanFieldFromResponse(created.body, "push", "smoke run-scoped PR");
    if (push !== false) throw new Error("smoke run-scoped PR push flag did not round-trip");
    const pullRequestIndex = isRecord(created.body) && typeof created.body.pullRequestIndex === "number"
      ? created.body.pullRequestIndex
      : undefined;
    const pullRequestUrl = isRecord(created.body) && typeof created.body.pullRequestUrl === "string"
      ? created.body.pullRequestUrl
      : undefined;
    const agentGitServiceHandoffAttachment = await verifySmokeAgentGitServiceHandoffWorkspaceAttachment(
      url,
      headers,
      tenant,
      project,
      runId,
    );

    return {
      runScopedPullRequestDuringActiveRunChecked: true,
      runScopedPullRequestDuringActiveRunId: runId,
      runScopedPullRequestDuringActiveRunBranch: branch,
      runScopedPullRequestDuringActiveRunCommit: responseCommit,
      runScopedPullRequestDuringActiveRunPush: false,
      runScopedPullRequestDuringActiveRunIndex: pullRequestIndex,
      runScopedPullRequestDuringActiveRunUrl: pullRequestUrl,
      runScopedFileWriteDuringActiveRunChecked: true,
      runScopedFileWriteDuringActiveRunBlockedRunId: activeRunId,
      runScopedFileWriteDuringActiveRunAllowedRunId: runId,
      runScopedFileWriteDuringActiveRunPath: allowedPath,
      runScopedFileWriteDuringActiveRunDenied: true,
      ...(agentGitServiceHandoffAttachment ?? {}),
    };
  } finally {
    if (activeRunId) {
      await smokeJson(
        `${url}/tenants/${encodedTenant}/runs/${encodeURIComponent(activeRunId)}/cancel?project=${encodedProject}`,
        {
          method: "POST",
          headers: { ...headers, "content-type": "application/json" },
          body: JSON.stringify({
            reason: "release smoke active isolated workspace",
            clientId: "loom-smoke-run-scoped-pr-cleanup",
          }),
        },
        [200, 400, 404],
        "POST smoke active run cleanup",
      ).catch(() => undefined);
    }
  }
}

async function verifySmokeAgentGitServiceHandoffWorkspaceAttachment(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  runId: string,
): Promise<HarnessSmokeAgentGitServiceHandoffAttachmentResult | undefined> {
  const events = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runId)}/events?project=${encodeURIComponent(project)}`,
    { headers },
    [200],
    "GET smoke AGS handoff attachment events",
  );
  if (!Array.isArray(events.body)) throw new Error("smoke AGS handoff attachment events response was not an array");
  const event = events.body.find((item) => {
    if (!isRecord(item) || item.type !== "external_effect") return false;
    const data = item.data;
    return isRecord(data) &&
      data.kind === "agent_git_service_workspace_attachment" &&
      data.controlPlaneProvider === "agent-git-service";
  });
  if (!isRecord(event) || !isRecord(event.data)) return undefined;
  const attachmentUrl = optionalStringFieldFromResponse(event.data, "attachmentUrl");
  const handoffFollowupsUrl = optionalStringFieldFromResponse(event.data, "handoffFollowupsUrl");
  return {
    agentGitServiceHandoffWorkspaceAttachmentChecked: true,
    agentGitServiceHandoffWorkspaceAttachmentWorkspaceId: stringFieldFromResponse(event.data, "workspaceId", "smoke AGS handoff attachment event"),
    agentGitServiceHandoffWorkspaceAttachmentId: stringFieldFromResponse(event.data, "attachmentId", "smoke AGS handoff attachment event"),
    agentGitServiceHandoffPackageUrl: stringFieldFromResponse(event.data, "handoffPackageUrl", "smoke AGS handoff attachment event"),
    ...(attachmentUrl ? { agentGitServiceHandoffWorkspaceAttachmentUrl: attachmentUrl } : {}),
    ...(handoffFollowupsUrl ? { agentGitServiceHandoffFollowupsUrl: handoffFollowupsUrl } : {}),
  };
}

async function verifySmokeHandoffEvidence(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  runId: string,
  sourceDefaults: HarnessSmokeSourceDefaultsResult | undefined,
  checkRunScopedPullRequestDuringActiveRun = false,
): Promise<HarnessSmokeHandoffResult> {
  if (!sourceDefaults) throw new Error("smoke handoff source defaults were not verified");
  const runUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runId)}`;
  const projectQuery = `project=${encodeURIComponent(project)}`;
  const reviewSummary = await smokeJson(
    `${runUrl}/review-summary?${projectQuery}`,
    { headers },
    [200],
    "GET smoke review summary",
  );
  const reviewSummaryRunId = stringFieldFromResponse(reviewSummary.body, "runId", "smoke review summary");
  const reviewSummaryStatus = stringFieldFromResponse(reviewSummary.body, "status", "smoke review summary");
  if (reviewSummaryRunId !== runId) {
    throw new Error(`smoke review summary runId did not match: ${JSON.stringify(reviewSummaryRunId)}`);
  }
  if (reviewSummaryStatus !== "passed") {
    throw new Error(`smoke review summary status was ${JSON.stringify(reviewSummaryStatus)}`);
  }
  const reviewSummaryTimeline = arrayFieldFromResponse(reviewSummary.body, "timeline", "smoke review summary");
  if (!reviewSummaryTimeline.some((entry) => isRecord(entry) && entry.type === "finish")) {
    throw new Error("smoke review summary timeline did not include the finish event");
  }
  verifySmokeProjectContractSnapshot(
    reviewSummary.body,
    "projectContract",
    "projectContractStatus",
    "smoke review summary",
  );
  const reviewMetadata = recordFieldFromResponse(reviewSummary.body, "metadata", "smoke review summary");
  verifySmokeSourceDefaultsMetadata(reviewMetadata, sourceDefaults, "smoke review summary metadata");

  const handoffPackage = await smokeJson(
    `${runUrl}/handoff-package?${projectQuery}`,
    { headers },
    [200],
    "GET smoke handoff package",
  );
  const checkpoint = recordFieldFromResponse(handoffPackage.body, "checkpoint", "smoke handoff package");
  const sourceCheckpointVersion = stringFieldFromResponse(checkpoint, "version", "smoke handoff package checkpoint");
  const handoffPackageRunId = stringFieldFromResponse(handoffPackage.body, "runId", "smoke handoff package");
  if (handoffPackageRunId !== runId) {
    throw new Error(`smoke handoff package runId did not match: ${JSON.stringify(handoffPackageRunId)}`);
  }
  const handoffReviewSummary = recordFieldFromResponse(handoffPackage.body, "reviewSummary", "smoke handoff package");
  const handoffReviewSummaryRunId = stringFieldFromResponse(handoffReviewSummary, "runId", "smoke handoff package review summary");
  const handoffReviewSummaryStatus = stringFieldFromResponse(handoffReviewSummary, "status", "smoke handoff package review summary");
  if (handoffReviewSummaryRunId !== runId || handoffReviewSummaryStatus !== reviewSummaryStatus) {
    throw new Error("smoke handoff package did not embed the matching review summary");
  }
  const handoffReviewMetadata = recordFieldFromResponse(handoffReviewSummary, "metadata", "smoke handoff package review summary");
  verifySmokeSourceDefaultsMetadata(handoffReviewMetadata, sourceDefaults, "smoke handoff package review summary metadata");
  verifySmokeProjectContractSnapshot(
    handoffReviewSummary,
    "projectContract",
    "projectContractStatus",
    "smoke handoff package review summary",
  );
  const auditTrail = arrayFieldFromResponse(handoffPackage.body, "auditTrail", "smoke handoff package");
  if (!auditTrail.some((event) =>
    isRecord(event) &&
    event.type === "run_created" &&
    isRecord(event.data) &&
    event.data.runId === runId
  )) {
    throw new Error("smoke handoff package audit trail did not include run_created");
  }
  const links = recordFieldFromResponse(handoffPackage.body, "links", "smoke handoff package");
  const reviewSummaryLink = stringFieldFromResponse(links, "reviewSummary", "smoke handoff package links");
  const replayLink = stringFieldFromResponse(links, "replay", "smoke handoff package links");
  const workbenchLink = stringFieldFromResponse(links, "workbench", "smoke handoff package links");
  if (
    !reviewSummaryLink.includes(`/tenants/${tenant}/runs/${runId}/review-summary`) ||
    !replayLink.includes(`/tenants/${tenant}/runs/${runId}/replay`) ||
    !workbenchLink.includes(`runId=${encodeURIComponent(runId)}`)
  ) {
    throw new Error("smoke handoff package links did not point at the run evidence");
  }
  const handoffWorkspace = recordFieldFromResponse(handoffPackage.body, "workspace", "smoke handoff package");
  const handoffWorkspaceRepo = stringFieldFromResponse(handoffWorkspace, "repo", "smoke handoff package workspace");
  const handoffWorkspaceBranch = stringFieldFromResponse(handoffWorkspace, "branch", "smoke handoff package workspace");
  const handoff = recordFieldFromResponse(handoffPackage.body, "handoff", "smoke handoff package");
  const handoffIssue = stringFieldFromResponse(handoff, "issue", "smoke handoff package handoff");
  const handoffBranch = stringFieldFromResponse(handoff, "branch", "smoke handoff package handoff");
  const handoffBaseBranch = stringFieldFromResponse(handoff, "baseBranch", "smoke handoff package handoff");
  const handoffIssueUrl = typeof handoff.issueUrl === "string" ? handoff.issueUrl : undefined;
  if (
    handoffWorkspaceRepo !== sourceDefaults.sourceDefaultsRepo ||
    handoffWorkspaceBranch !== sourceDefaults.sourceDefaultsBranch ||
    handoffIssue !== sourceDefaults.sourceDefaultsIssue ||
    handoffBranch !== sourceDefaults.sourceDefaultsBranch ||
    handoffBaseBranch !== sourceDefaults.sourceDefaultsBaseBranch ||
    (sourceDefaults.sourceDefaultsIssueUrl !== undefined && handoffIssueUrl !== sourceDefaults.sourceDefaultsIssueUrl)
  ) {
    throw smokeCheckError(
      "SMOKE_SOURCE_DEFAULTS_HANDOFF_DRIFT",
      "smoke handoff package did not preserve source defaults",
      {
        scope: "handoff",
        expected: sourceDefaults,
        actual: {
          workspaceRepo: handoffWorkspaceRepo,
          workspaceBranch: handoffWorkspaceBranch,
          issue: handoffIssue,
          branch: handoffBranch,
          baseBranch: handoffBaseBranch,
          issueUrl: handoffIssueUrl,
        },
      },
    );
  }

  const followup = await smokeJson(
    `${runUrl}/handoff-runs?${projectQuery}`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        goal: "loom smoke continues from handoff package",
        ...smokeUngatedRunDefaults(),
        script: [{ message: "finish smoke handoff follow-up", finish: true }],
        verify: [],
        skills: ["smoke", "coding"],
        clientId: "loom-smoke-handoff-followup",
        sourceCheckpointVersion,
      }),
    },
    [202],
    "POST smoke handoff follow-up run",
  );
  const handoffFollowupRunId = stringFieldFromResponse(followup.body, "runId", "smoke handoff follow-up run");
  if (handoffFollowupRunId === runId) throw new Error("smoke handoff follow-up reused the source runId");
  const finishedFollowup = await waitForSmokeRunStatus(
    `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(handoffFollowupRunId)}?${projectQuery}`,
    headers,
    "passed",
    "smoke handoff follow-up run",
  );
  const handoffFollowupRunStatus = stringFieldFromResponse(finishedFollowup.body, "status", "smoke handoff follow-up run");
  const followupMetadata = recordFieldFromResponse(finishedFollowup.body, "metadata", "smoke handoff follow-up run");
  const handoffFollowupSourceRunId = stringFieldFromResponse(followupMetadata, "handoffSourceRunId", "smoke handoff follow-up metadata");
  if (handoffFollowupSourceRunId !== runId) {
    throw new Error("smoke handoff follow-up metadata did not point at the source run");
  }
  verifySmokeProjectContractSnapshot(
    followupMetadata,
    "handoffSourceProjectContract",
    "handoffSourceProjectContractStatus",
    "smoke handoff follow-up metadata",
  );
  const handoffFollowupSourceDefaults = verifySmokeSourceDefaultsMetadata(
    followupMetadata,
    sourceDefaults,
    "smoke handoff follow-up metadata",
  );

  const lineage = await smokeJson(
    `${runUrl}/handoff-runs?${projectQuery}`,
    { headers },
    [200],
    "GET smoke handoff follow-up runs",
  );
  const followupRuns = arrayFieldFromResponse(lineage.body, "followupRuns", "smoke handoff follow-up runs");
  if (!followupRuns.some((item) => isRecord(item) && item.runId === handoffFollowupRunId)) {
    throw new Error("smoke handoff follow-up list did not include the created run");
  }
  const lineageCheckpoint = recordFieldFromResponse(lineage.body, "checkpoint", "smoke handoff follow-up runs");
  const lineageFollowups = recordFieldFromResponse(lineageCheckpoint, "followups", "smoke handoff follow-up checkpoint");
  const handoffFollowupCount = numberFieldFromResponse(lineageFollowups, "count", "smoke handoff follow-up checkpoint");
  if (handoffFollowupCount !== 1) {
    throw new Error(`smoke handoff follow-up count was ${handoffFollowupCount}`);
  }
  const runScopedPullRequestDuringActiveRun = checkRunScopedPullRequestDuringActiveRun
    ? await verifySmokeRunScopedPullRequestDuringActiveRun(
      url,
      headers,
      tenant,
      project,
      runId,
      sourceDefaults,
    )
    : undefined;

  const contractPatch = {
    objective: "Preserve the multi-user online sandbox development platform with an auditable harness loop.",
    constraints: [
      "Keep review and deployment gate evidence durable in smoke handoff checks.",
      "Keep VAS learning evidence visible when the MVP evolves.",
    ],
    successCriteria: [
      "Smoke verifies contract patches in review summaries, handoff packages, and replay.",
    ],
  };
  const patchRun = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        goal: "loom smoke records contract patch handoff evidence",
        reviewRequired: true,
        script: [{ message: "finish smoke contract patch run", finish: true }],
        verify: [],
        skills: ["smoke", "coding"],
        requester: { clientId: "loom-smoke-contract-patch" },
      }),
    },
    [201],
    "POST smoke contract patch run",
  );
  const handoffContractPatchRunId = stringFieldFromResponse(patchRun.body, "runId", "smoke contract patch run");
  const patchRunStatus = stringFieldFromResponse(patchRun.body, "status", "smoke contract patch run");
  if (patchRunStatus !== "review_required") {
    throw new Error(`smoke contract patch run status was ${JSON.stringify(patchRunStatus)}`);
  }
  const patchRunUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(handoffContractPatchRunId)}`;
  const patchReview = await smokeJson(
    `${patchRunUrl}/review?${projectQuery}`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        decision: "approved",
        note: "loom smoke records contract patch evidence",
        contractPatch,
        clientId: "loom-smoke-contract-patch-review",
      }),
    },
    [200],
    "POST smoke contract patch review",
  );
  const patchReviewStatus = stringFieldFromResponse(patchReview.body, "status", "smoke contract patch review");
  if (patchReviewStatus !== "passed") {
    throw new Error(`smoke contract patch review status was ${JSON.stringify(patchReviewStatus)}`);
  }

  const patchReviewSummary = await smokeJson(
    `${patchRunUrl}/review-summary?${projectQuery}`,
    { headers },
    [200],
    "GET smoke contract patch review summary",
  );
  const patchReviewSummaryReview = recordFieldFromResponse(patchReviewSummary.body, "review", "smoke contract patch review summary");
  verifySmokeContractPatchEvidence(
    patchReviewSummaryReview,
    "contractPatch",
    contractPatch,
    "smoke contract patch review summary",
  );

  const patchHandoffPackage = await smokeJson(
    `${patchRunUrl}/handoff-package?${projectQuery}`,
    { headers },
    [200],
    "GET smoke contract patch handoff package",
  );
  const patchGateTrail = arrayFieldFromResponse(patchHandoffPackage.body, "gateTrail", "smoke contract patch handoff package");
  const patchGateTrailEntry = patchGateTrail.find((entry): entry is Record<string, unknown> =>
    isRecord(entry) &&
    entry.gate === "review" &&
    entry.status === "approved"
  );
  if (!patchGateTrailEntry) throw new Error("smoke contract patch handoff package did not include an approved review gate");
  verifySmokeContractPatchEvidence(
    patchGateTrailEntry,
    "contractPatch",
    contractPatch,
    "smoke contract patch handoff package gate trail",
  );

  const patchReplay = await smokeJson(
    `${patchRunUrl}/replay?${projectQuery}`,
    { headers },
    [200],
    "GET smoke contract patch replay",
  );
  const patchReplayTimeline = arrayFieldFromResponse(patchReplay.body, "timeline", "smoke contract patch replay");
  const patchReplayEntry = patchReplayTimeline.find((entry): entry is Record<string, unknown> =>
    isRecord(entry) &&
    entry.type === "review_gate" &&
    entry.status === "approved"
  );
  if (!patchReplayEntry) throw new Error("smoke contract patch replay did not include an approved review gate");
  verifySmokeContractPatchEvidence(
    patchReplayEntry,
    "contractPatch",
    contractPatch,
    "smoke contract patch replay",
  );

  return {
    handoffEvidenceChecked: true,
    reviewSummaryRead: true,
    reviewSummaryRunId,
    reviewSummaryStatus: "passed",
    reviewSummaryTimelineChecked: true,
    reviewSummaryContractEvidenceChecked: true,
    handoffPackageRead: true,
    handoffPackageRunId,
    handoffPackageReviewSummaryChecked: true,
    handoffPackageContractEvidenceChecked: true,
    handoffPackageAuditTrailChecked: true,
    handoffPackageLinksChecked: true,
    handoffFollowupCreated: true,
    handoffFollowupRunId,
    handoffFollowupRunStatus: "passed",
    handoffFollowupSourceRunId,
    handoffFollowupSourceContractEvidenceChecked: true,
    handoffSourceDefaultsChecked: true,
    handoffFollowupSourceDefaultsChecked: true,
    handoffFollowupRepo: handoffFollowupSourceDefaults.repo,
    handoffFollowupBranch: handoffFollowupSourceDefaults.branch,
    handoffFollowupBaseBranch: handoffFollowupSourceDefaults.baseBranch,
    handoffFollowupIssue: handoffFollowupSourceDefaults.issue,
    handoffFollowupIssueUrl: handoffFollowupSourceDefaults.issueUrl,
    ...(runScopedPullRequestDuringActiveRun ?? {}),
    handoffFollowupListChecked: true,
    handoffFollowupCount: 1,
    handoffContractPatchEvidenceChecked: true,
    handoffContractPatchRunId,
    handoffContractPatchReviewSummaryChecked: true,
    handoffContractPatchGateTrailChecked: true,
    handoffContractPatchReplayChecked: true,
  };
}

async function verifySmokeActiveRunLease(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  runId: string,
  label: string,
): Promise<SmokeActiveRunLeaseEvidence> {
  const response = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/status`,
    { headers },
    [200],
    `GET ${label} tenant status`,
  );
  const server = recordFieldFromResponse(response.body, "server", `${label} tenant status`);
  const isolation = server.runWorkspaceIsolation;
  if (isolation !== "project" && isolation !== "run") {
    throw smokeCheckError(
      "SMOKE_ACTIVE_RUN_LEASE_ISOLATION_INVALID",
      `${label} tenant status server.runWorkspaceIsolation must be project or run`,
      { scope: "tenant", tenant, project, runId, actual: isolation ?? null },
    );
  }
  const resources = recordFieldFromResponse(response.body, "resources", `${label} tenant status`);
  const activeRunDetails = Array.isArray(resources.activeRunDetails) ? resources.activeRunDetails : [];
  const activeRun = activeRunDetails.find((entry) =>
    isRecord(entry) &&
    entry.tenant === tenant &&
    entry.project === project &&
    entry.runId === runId
  );
  if (!isRecord(activeRun)) {
    const activeRuns = activeRunDetails.filter(isRecord).map((entry) => ({
      tenant: typeof entry.tenant === "string" ? entry.tenant : null,
      project: typeof entry.project === "string" ? entry.project : null,
      runId: typeof entry.runId === "string" ? entry.runId : null,
      workspaceLeaseScope: typeof entry.workspaceLeaseScope === "string" ? entry.workspaceLeaseScope : null,
      workspaceLeaseKey: typeof entry.workspaceLeaseKey === "string" ? entry.workspaceLeaseKey : null,
    }));
    throw smokeCheckError(
      "SMOKE_ACTIVE_RUN_LEASE_MISSING",
      `${label} did not report the pause/resume active run lease`,
      { scope: "tenant", tenant, project, runId, activeRuns },
    );
  }
  const leaseScope = stringFieldFromResponse(activeRun, "workspaceLeaseScope", label);
  if (leaseScope !== "project" && leaseScope !== "run") {
    throw smokeCheckError(
      "SMOKE_ACTIVE_RUN_LEASE_SCOPE_INVALID",
      `${label} reported an invalid workspaceLeaseScope`,
      { scope: "tenant", tenant, project, runId, actual: leaseScope },
    );
  }
  if (leaseScope !== isolation) {
    throw smokeCheckError(
      "SMOKE_ACTIVE_RUN_LEASE_SCOPE_MISMATCH",
      `${label} workspaceLeaseScope did not match tenant runWorkspaceIsolation`,
      { scope: "tenant", tenant, project, runId, expected: isolation, actual: leaseScope },
    );
  }
  const leaseKey = stringFieldFromResponse(activeRun, "workspaceLeaseKey", label);
  const expectedKey = leaseScope === "run" ? `${tenant}/${project}/${runId}` : `${tenant}/${project}`;
  if (leaseKey !== expectedKey) {
    throw smokeCheckError(
      "SMOKE_ACTIVE_RUN_LEASE_KEY_MISMATCH",
      `${label} reported an unexpected workspaceLeaseKey`,
      { scope: "tenant", tenant, project, runId, expected: expectedKey, actual: leaseKey },
    );
  }
  return { runId, scope: leaseScope, key: leaseKey };
}

async function verifySmokeRunControls(
  url: string,
  developerHeaders: Record<string, string>,
  options: HarnessSmokeCliOptions,
  tenant: string,
  project: string,
  peerUrl?: string,
): Promise<HarnessSmokeRunControlsResult> {
  const projectQuery = `project=${encodeURIComponent(project)}`;
  const controlUrl = peerUrl ?? url;
  const crossServerControls = peerUrl !== undefined;
  const viewerToken = smokeViewerToken(options);
  const pauseHeaders = viewerToken ? smokeHeaders(viewerToken) : developerHeaders;

  const pauseRunResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({
        async: true,
        tenant,
        project,
        ...smokeUngatedRunDefaults(),
        goal: "loom smoke pause and resume controls",
        allowedTools: ["shell.exec", "verify.run"],
        script: [
          {
            message: "write first control trace",
            actions: [
              {
                toolName: "shell.exec",
                input: { command: SMOKE_RUN_CONTROL_PAUSE_COMMAND },
              },
            ],
          },
          {
            message: "write second control trace",
            actions: [
              {
                toolName: "shell.exec",
                input: { command: "printf second >> loom-control.txt; node -e \"setTimeout(()=>process.stdout.write('second'),3000)\"" },
              },
            ],
          },
          { message: "finish smoke run controls", finish: true },
        ],
        verify: ["test \"$(cat loom-control.txt)\" = firstsecond"],
        skills: ["smoke", "coding"],
        clientId: "loom-smoke-controls",
      }),
    },
    [202],
    "POST smoke pause/resume run",
  );
  const pauseResumeRunId = stringFieldFromResponse(pauseRunResponse.body, "runId", "smoke pause/resume run");
  const pauseRunUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(pauseResumeRunId)}`;
  const pauseControlRunUrl = `${controlUrl}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(pauseResumeRunId)}`;
  const pauseEventsUrl = `${pauseRunUrl}/events?${projectQuery}`;
  await waitForSmokeRunEvent(
    pauseEventsUrl,
    developerHeaders,
    (event) => isRecord(event) && event.type === "action",
    "smoke pause/resume run action",
  );
  const [activeRunLease, crossServerActiveRunLease] = await Promise.all([
    verifySmokeActiveRunLease(url, developerHeaders, tenant, project, pauseResumeRunId, "smoke active run lease"),
    peerUrl
      ? verifySmokeActiveRunLease(peerUrl, developerHeaders, tenant, project, pauseResumeRunId, "smoke peer active run lease")
      : Promise.resolve(undefined),
  ]);

  const pauseResponse = await smokeJson(
    `${pauseControlRunUrl}/comments?${projectQuery}`,
    {
      method: "POST",
      headers: { ...pauseHeaders, "content-type": "application/json" },
      body: JSON.stringify({ message: "Pause for loom smoke review.", pause: true, clientId: "loom-smoke-pause" }),
    },
    [201],
    "POST smoke pause request",
  );
  const pauseData = recordFieldFromResponse(pauseResponse.body, "data", "smoke pause request");
  const pauseRequested = booleanFieldFromResponse(pauseData, "pauseRequested", "smoke pause request");
  if (!pauseRequested) throw new Error("smoke pause request did not record pauseRequested");
  const pauseRequestRole = typeof pauseData.role === "string" ? pauseData.role : "anonymous";

  const paused = await waitForSmokeRunStatus(
    `${pauseRunUrl}?${projectQuery}`,
    developerHeaders,
    "paused",
    "smoke pause/resume run",
    SMOKE_RUN_CONTROL_PAUSE_TIMEOUT_MS,
  );
  const pausedRunStatus = stringFieldFromResponse(paused.body, "status", "smoke paused run");
  if (pausedRunStatus !== "paused") throw new Error(`smoke paused run status was ${pausedRunStatus}`);

  const resumeResponse = await smokeJson(
    `${pauseRunUrl}/resume?${projectQuery}`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ clientId: "loom-smoke-resume" }),
    },
    [202],
    "POST smoke resume request",
  );
  const resumedStatus = stringFieldFromResponse(resumeResponse.body, "status", "smoke resume request");
  if (resumedStatus !== "running") throw new Error(`smoke resume request returned ${resumedStatus}`);

  const resumed = await waitForSmokeRunStatus(
    `${pauseRunUrl}?${projectQuery}`,
    developerHeaders,
    "passed",
    "smoke resumed run",
    SMOKE_RUN_CONTROL_RESUME_TIMEOUT_MS,
  );
  const resumedRunStatus = stringFieldFromResponse(resumed.body, "status", "smoke resumed run");
  const pauseEvents = await smokeJson(pauseEventsUrl, { headers: developerHeaders }, [200], "GET smoke pause/resume events");
  const pauseEventBody = Array.isArray(pauseEvents.body) ? pauseEvents.body : [];
  const resumeEvent = pauseEventBody.find((event) =>
    isRecord(event) &&
    event.type === "resume" &&
    isRecord(event.data) &&
    event.data.clientId === "loom-smoke-resume"
  );
  if (!isRecord(resumeEvent) || !isRecord(resumeEvent.data)) {
    throw new Error("smoke pause/resume events did not include resume");
  }
  const resumeRequestRole = typeof resumeEvent.data.role === "string" ? resumeEvent.data.role : "developer";
  if (!pauseEventBody.some((event) => isRecord(event) && event.type === "pause")) {
    throw new Error("smoke pause/resume events did not include pause");
  }

  const trace = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/files?path=${encodeURIComponent("loom-control.txt")}`,
    { headers: developerHeaders },
    [200],
    "GET smoke pause/resume trace",
  );
  const pauseResumeTraceContent = stringFieldFromResponse(trace.body, "content", "smoke pause/resume trace");
  if (pauseResumeTraceContent !== "firstsecond") {
    throw new Error(`smoke pause/resume trace was ${JSON.stringify(pauseResumeTraceContent)}`);
  }

  let crossServerIdempotentCreateRunId: string | undefined;
  let crossServerIdempotentCreateClientRequestId: string | undefined;
  let crossServerIdempotentCreateReplayChecked: true | undefined;
  let crossServerIdempotentCreateRunStatus: "cancelled" | undefined;
  if (peerUrl) {
    crossServerIdempotentCreateClientRequestId = `loom-smoke-idempotent-${Date.now()}`;
    const idempotentPayload = {
      async: true,
      tenant,
      project,
      ...smokeUngatedRunDefaults(),
      clientRequestId: crossServerIdempotentCreateClientRequestId,
      goal: "loom smoke cross-server idempotent create",
      allowedTools: ["shell.exec", "verify.run"],
      script: [
        {
          message: "hold idempotent smoke run",
          actions: [
            {
              toolName: "shell.exec",
              input: { command: "node -e \"setTimeout(()=>process.stdout.write('idempotent'),10000)\"" },
            },
          ],
        },
        { message: "finish idempotent smoke run", finish: true },
      ],
      verify: [],
      skills: ["smoke", "coding"],
      clientId: "loom-smoke-idempotent-create",
    };
    const [primaryCreate, peerCreate] = await Promise.all([
      smokeJson(
        `${url}/runs`,
        {
          method: "POST",
          headers: { ...developerHeaders, "content-type": "application/json" },
          body: JSON.stringify(idempotentPayload),
        },
        [202],
        "POST smoke idempotent create primary",
      ),
      smokeJson(
        `${peerUrl}/runs`,
        {
          method: "POST",
          headers: { ...developerHeaders, "content-type": "application/json" },
          body: JSON.stringify(idempotentPayload),
        },
        [202],
        "POST smoke idempotent create peer",
      ),
    ]);
    const primaryRunId = stringFieldFromResponse(primaryCreate.body, "runId", "smoke idempotent create primary");
    const peerRunId = stringFieldFromResponse(peerCreate.body, "runId", "smoke idempotent create peer");
    const primaryStatus = stringFieldFromResponse(primaryCreate.body, "status", "smoke idempotent create primary");
    const peerStatus = stringFieldFromResponse(peerCreate.body, "status", "smoke idempotent create peer");
    if (primaryRunId !== peerRunId) throw new Error("smoke idempotent create returned different run ids across servers");
    if (primaryStatus !== "running" || peerStatus !== "running") {
      throw new Error(`smoke idempotent create statuses were ${primaryStatus}/${peerStatus}`);
    }
    const primaryReplay = isRecord(primaryCreate.body) && primaryCreate.body.idempotentReplay === true;
    const peerReplay = isRecord(peerCreate.body) && peerCreate.body.idempotentReplay === true;
    if (!primaryReplay && !peerReplay) throw new Error("smoke idempotent create did not report an idempotent replay");
    crossServerIdempotentCreateRunId = primaryRunId;
    crossServerIdempotentCreateReplayChecked = true;
    const idempotentRunUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(crossServerIdempotentCreateRunId)}`;
    await smokeJson(
      `${peerUrl}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(crossServerIdempotentCreateRunId)}/cancel?${projectQuery}`,
      {
        method: "POST",
        headers: { ...developerHeaders, "content-type": "application/json" },
        body: JSON.stringify({ reason: "loom smoke idempotent cleanup", clientId: "loom-smoke-idempotent-cancel" }),
      },
      [200, 202],
      "POST smoke idempotent create cleanup",
    );
    await waitForSmokeRunStatus(`${idempotentRunUrl}?${projectQuery}`, developerHeaders, "cancelled", "smoke idempotent create cleanup");
    crossServerIdempotentCreateRunStatus = "cancelled";
  }

  const cancelRunResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({
        async: true,
        tenant,
        project,
        ...smokeUngatedRunDefaults(),
        goal: "loom smoke cancel control",
        allowedTools: ["shell.exec", "verify.run"],
        script: [
          {
            message: "start cancellable control action",
            actions: [
              {
                toolName: "shell.exec",
                input: { command: "node -e \"setTimeout(()=>process.stdout.write('late'),5000)\"" },
              },
            ],
          },
          { message: "finish cancelled run", finish: true },
        ],
        verify: [],
        skills: ["smoke", "coding"],
        clientId: "loom-smoke-cancel-run",
      }),
    },
    [202],
    "POST smoke cancellable run",
  );
  const cancelRunId = stringFieldFromResponse(cancelRunResponse.body, "runId", "smoke cancellable run");
  const cancelRunUrl = `${url}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(cancelRunId)}`;
  const cancelControlRunUrl = `${controlUrl}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(cancelRunId)}`;
  const cancelEventsUrl = `${cancelRunUrl}/events?${projectQuery}`;
  await waitForSmokeRunEvent(
    cancelEventsUrl,
    developerHeaders,
    (event) => isRecord(event) && event.type === "action",
    "smoke cancellable run action",
  );
  const cancelResponse = await smokeJson(
    `${cancelControlRunUrl}/cancel?${projectQuery}`,
    {
      method: "POST",
      headers: { ...developerHeaders, "content-type": "application/json" },
      body: JSON.stringify({ reason: "loom smoke cancel", clientId: "loom-smoke-cancel" }),
    },
    peerUrl ? [200, 202] : [200],
    "POST smoke cancel run",
  );
  const cancelResponseStatus = stringFieldFromResponse(cancelResponse.body, "status", "smoke cancel run");
  const crossServerCancelRequested = peerUrl
    ? booleanFieldFromResponse(cancelResponse.body, "cancelRequested", "smoke peer cancel run")
    : undefined;
  if (peerUrl && !crossServerCancelRequested) throw new Error("smoke peer cancel run did not record cancelRequested");
  if (!peerUrl && cancelResponseStatus !== "cancelled") throw new Error(`smoke cancel run returned ${cancelResponseStatus}`);
  await waitForSmokeRunStatus(`${cancelRunUrl}?${projectQuery}`, developerHeaders, "cancelled", "smoke cancelled run");
  const cancelRunStatus = "cancelled";
  const replay = await smokeJson(`${cancelRunUrl}/replay?${projectQuery}`, { headers: developerHeaders }, [200], "GET smoke cancelled run replay");
  const replayTimeline = arrayFieldFromResponse(replay.body, "timeline", "smoke cancelled run replay");
  if (!replayTimeline.some((entry) => isRecord(entry) && entry.type === "cancel")) {
    throw new Error("smoke cancelled run replay did not include cancel");
  }

  const audit = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/audit?${projectQuery}`,
    { headers: developerHeaders },
    [200],
    "GET smoke run control audit",
  );
  const auditBody = Array.isArray(audit.body) ? audit.body : [];
  const sawResumeAudit = auditBody.some((event) =>
    isRecord(event) &&
    event.type === "run_resumed" &&
    isRecord(event.data) &&
    event.data.runId === pauseResumeRunId
  );
  const sawCancelAudit = auditBody.some((event) =>
    isRecord(event) &&
    event.type === "run_cancelled" &&
    isRecord(event.data) &&
    event.data.runId === cancelRunId
  );
  if (!sawResumeAudit || !sawCancelAudit) {
    throw new Error("smoke run control audit did not include resume and cancel events");
  }

  return {
    runControlsChecked: true,
    pauseResumeChecked: true,
    pauseResumeRunId,
    activeRunLeaseChecked: true,
    activeRunLeaseRunId: activeRunLease.runId,
    activeRunLeaseScope: activeRunLease.scope,
    activeRunLeaseKey: activeRunLease.key,
    pauseRequested: true,
    pauseRequestRole,
    pausedRunStatus: "paused",
    resumeRequested: true,
    resumeRequestRole: resumeRequestRole === "admin" ? "admin" : "developer",
    resumedRunStatus: "passed",
    pauseResumeTraceContent,
    cancelChecked: true,
    cancelRunId,
    cancelRunStatus: "cancelled",
    cancelReplayChecked: true,
    runControlsPeerUrl: peerUrl,
    crossServerPauseChecked: crossServerControls ? true : undefined,
    crossServerActiveRunLeaseChecked: crossServerActiveRunLease ? true : undefined,
    crossServerActiveRunLeaseRunId: crossServerActiveRunLease?.runId,
    crossServerActiveRunLeaseScope: crossServerActiveRunLease?.scope,
    crossServerActiveRunLeaseKey: crossServerActiveRunLease?.key,
    crossServerPauseRunId: crossServerControls ? pauseResumeRunId : undefined,
    crossServerPauseRequested: crossServerControls ? true : undefined,
    crossServerPauseRunStatus: crossServerControls ? "paused" : undefined,
    crossServerCancelChecked: crossServerControls ? true : undefined,
    crossServerCancelRunId: crossServerControls ? cancelRunId : undefined,
    crossServerCancelRequested: crossServerControls ? true : undefined,
    crossServerCancelRunStatus: crossServerControls ? cancelRunStatus : undefined,
    crossServerIdempotentCreateChecked: crossServerControls ? true : undefined,
    crossServerIdempotentCreateRunId,
    crossServerIdempotentCreateClientRequestId,
    crossServerIdempotentCreateReplayChecked,
    crossServerIdempotentCreateRunStatus,
    runControlAuditChecked: true,
  };
}

async function verifySmokePresence(
  presenceUrl: string,
  headers: Record<string, string>,
  expected: HarnessSmokePresenceExpectation[],
  label: string,
): Promise<number> {
  for (const entry of expected) {
    const response = await smokeJson(
      presenceUrl,
      {
        method: "POST",
        headers: { ...headers, "content-type": "application/json" },
        body: JSON.stringify(entry),
      },
      [200],
      `POST smoke ${label}`,
    );
    const clientId = stringFieldFromResponse(response.body, "clientId", `smoke ${label}`);
    const responseLabel = stringFieldFromResponse(response.body, "label", `smoke ${label}`);
    const focus = stringFieldFromResponse(response.body, "focus", `smoke ${label}`);
    if (clientId !== entry.clientId || responseLabel !== entry.label || focus !== entry.focus) {
      throw new Error(`smoke ${label} heartbeat did not echo the expected collaborator`);
    }
  }

  const response = await smokeJson(presenceUrl, { headers }, [200], `GET smoke ${label}`);
  if (!Array.isArray(response.body)) throw new Error(`smoke ${label} response was not an array`);
  const entries: unknown[] = response.body;
  const collaboratorCount = expected.filter((entry) =>
    entries.some((item) =>
      isRecord(item) &&
      item.clientId === entry.clientId &&
      item.label === entry.label &&
      item.focus === entry.focus
    )
  ).length;
  if (collaboratorCount !== expected.length) {
    throw new Error(`smoke ${label} did not include all heartbeat collaborators`);
  }
  return collaboratorCount;
}

async function verifySmokeVasLiteProject(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  template: ProjectTemplateName,
): Promise<HarnessSmokeVasResult> {
  if (template !== "vas-lite") throw new Error("--check-vas requires --template vas-lite");
  const vasBaseUrl = `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/vas`;
  const casesResponse = await smokeJson(`${vasBaseUrl}/cases`, { headers }, [200], "GET smoke VAS cases");
  const vasTemplate = stringFieldFromResponse(casesResponse.body, "template", "smoke VAS cases");
  if (vasTemplate !== "vas-lite") throw new Error(`smoke VAS cases reported template ${JSON.stringify(vasTemplate)}`);
  const cases = arrayFieldFromResponse(casesResponse.body, "cases", "smoke VAS cases");
  const bootstrap = cases.find((item) => isRecord(item) && item.id === "bootstrap");
  if (!isRecord(bootstrap)) throw new Error("smoke VAS cases did not include bootstrap");
  const bootstrapStatus = stringFieldFromResponse(bootstrap, "status", "smoke VAS bootstrap case");

  const queueResponse = await smokeJson(`${vasBaseUrl}/review-queue`, { headers }, [200], "GET smoke VAS review queue");
  const queueTemplate = stringFieldFromResponse(queueResponse.body, "template", "smoke VAS review queue");
  if (queueTemplate !== "vas-lite") throw new Error(`smoke VAS review queue reported template ${JSON.stringify(queueTemplate)}`);
  const queueCases = arrayFieldFromResponse(queueResponse.body, "cases", "smoke VAS review queue");
  if (!queueCases.some((item) => isRecord(item) && item.id === "bootstrap")) {
    throw new Error("smoke VAS review queue did not include bootstrap");
  }

  const reviewPackageResponse = await smokeJson(`${vasBaseUrl}/cases/bootstrap/review-package`, { headers }, [200], "GET smoke VAS review package");
  const reviewPackageTemplate = stringFieldFromResponse(reviewPackageResponse.body, "template", "smoke VAS review package");
  if (reviewPackageTemplate !== "vas-lite") throw new Error(`smoke VAS review package reported template ${JSON.stringify(reviewPackageTemplate)}`);
  const reviewPackageCaseId = stringFieldFromResponse(reviewPackageResponse.body, "caseId", "smoke VAS review package");
  if (reviewPackageCaseId !== "bootstrap") {
    throw new Error(`smoke VAS review package reported case ${JSON.stringify(reviewPackageCaseId)}`);
  }

  const reviewRunResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        preset: "vas-lite-review",
        presetInput: { caseId: "bootstrap" },
        reviewRequired: false,
        requester: { clientId: "loom-smoke" },
      }),
    },
    [201],
    "POST smoke VAS review run",
  );
  const reviewRunId = stringFieldFromResponse(reviewRunResponse.body, "runId", "smoke VAS review run");
  const reviewRunStatus = stringFieldFromResponse(reviewRunResponse.body, "status", "smoke VAS review run");
  if (reviewRunStatus !== "passed") throw new Error(`smoke VAS review run finished with status ${reviewRunStatus}`);
  const reviewRunMetadata = recordFieldFromResponse(reviewRunResponse.body, "metadata", "smoke VAS review run");
  const reviewRunPreset = stringFieldFromResponse(reviewRunMetadata, "runPreset", "smoke VAS review run metadata");
  if (reviewRunPreset !== "vas-lite-review") {
    throw new Error(`smoke VAS review run reported preset ${JSON.stringify(reviewRunPreset)}`);
  }
  const reviewRunPresetInput = recordFieldFromResponse(reviewRunMetadata, "runPresetInput", "smoke VAS review run metadata");
  const reviewRunCaseId = stringFieldFromResponse(reviewRunPresetInput, "caseId", "smoke VAS review run preset input");
  if (reviewRunCaseId !== "bootstrap") {
    throw new Error(`smoke VAS review run reported case ${JSON.stringify(reviewRunCaseId)}`);
  }

  const artifactsResponse = await smokeJson(`${vasBaseUrl}/cases/bootstrap/artifacts`, { headers }, [200], "GET smoke VAS artifacts");
  const artifactsTemplate = stringFieldFromResponse(artifactsResponse.body, "template", "smoke VAS artifacts");
  if (artifactsTemplate !== "vas-lite") throw new Error(`smoke VAS artifacts reported template ${JSON.stringify(artifactsTemplate)}`);
  const artifactsCaseId = stringFieldFromResponse(artifactsResponse.body, "caseId", "smoke VAS artifacts");
  if (artifactsCaseId !== "bootstrap") throw new Error(`smoke VAS artifacts reported case ${JSON.stringify(artifactsCaseId)}`);
  const reportPath = stringFieldFromResponse(artifactsResponse.body, "reportPath", "smoke VAS artifacts");
  const contextPath = stringFieldFromResponse(artifactsResponse.body, "contextPath", "smoke VAS artifacts");
  const report = stringFieldFromResponse(artifactsResponse.body, "report", "smoke VAS artifacts");
  if (!report.includes("VAS Lite Review") || !report.includes("preset=vas-lite-review")) {
    throw new Error("smoke VAS report did not include review preset evidence");
  }
  const context = recordFieldFromResponse(artifactsResponse.body, "context", "smoke VAS artifacts");
  const contextCaseId = stringFieldFromResponse(context, "caseId", "smoke VAS artifacts context");
  if (contextCaseId !== "bootstrap") throw new Error(`smoke VAS context reported case ${JSON.stringify(contextCaseId)}`);
  const reviewGateResult = await verifySmokeVasReviewGate(url, headers, tenant, project);

  return {
    vasReadinessChecked: true,
    vasTemplate: "vas-lite",
    vasBootstrapCaseId: "bootstrap",
    vasBootstrapCaseFound: true,
    vasBootstrapCaseStatus: bootstrapStatus,
    vasReviewQueueRead: true,
    vasReviewQueueCaseCount: queueCases.length,
    vasReviewPackageRead: true,
    vasReviewPackageCaseId: "bootstrap",
    vasReviewRunExecuted: true,
    vasReviewRunId: reviewRunId,
    vasReviewRunStatus: "passed",
    vasReviewRunPreset: "vas-lite-review",
    vasReviewRunCaseId: "bootstrap",
    vasReviewArtifactsRead: true,
    vasReviewReportPath: reportPath,
    vasReviewContextPath: contextPath,
    vasReviewContextCaseId: "bootstrap",
    ...reviewGateResult,
  };
}

async function verifySmokeVasReviewGate(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
): Promise<HarnessSmokeVasReviewGateResult> {
  const caseId = "loom-smoke-gate";
  const learningText = "Loom smoke review gates preserve approved learning updates";
  const vasBaseUrl = `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/vas`;
  await smokeJson(
    `${vasBaseUrl}/cases`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        caseId,
        title: "Loom smoke review gate",
        source: { kind: "manual", url: "loom://smoke-review-gate", range: { start: 0, end: 1 } },
        clientId: "loom-smoke",
      }),
    },
    [201, 409],
    "POST smoke VAS review gate case",
  );

  const gateRunResponse = await smokeJson(
    `${url}/runs`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        tenant,
        project,
        preset: "vas-lite-review",
        presetInput: { caseId },
        reviewRequired: true,
        requester: { clientId: "loom-smoke" },
      }),
    },
    [201],
    "POST smoke VAS review-gated run",
  );
  const gateRunId = stringFieldFromResponse(gateRunResponse.body, "runId", "smoke VAS review-gated run");
  const gateRunStatus = stringFieldFromResponse(gateRunResponse.body, "status", "smoke VAS review-gated run");
  if (gateRunStatus !== "review_required") {
    throw new Error(`smoke VAS review-gated run finished with status ${gateRunStatus}`);
  }
  const gateReview = recordFieldFromResponse(gateRunResponse.body, "review", "smoke VAS review-gated run");
  const gateReviewStatus = stringFieldFromResponse(gateReview, "status", "smoke VAS review-gated run review");
  if (gateReviewStatus !== "pending") {
    throw new Error(`smoke VAS review-gated run review status was ${JSON.stringify(gateReviewStatus)}`);
  }

  const reviewResponse = await smokeJson(
    `${vasBaseUrl}/cases/${encodeURIComponent(caseId)}/review`,
    {
      method: "POST",
      headers: { ...headers, "content-type": "application/json" },
      body: JSON.stringify({
        decision: "approved",
        note: "loom smoke approved the review gate",
        corrections: ["Keep review-gated VAS runs behind human approval"],
        learnings: [learningText],
        runId: gateRunId,
        clientId: "loom-smoke",
      }),
    },
    [200],
    "POST smoke VAS case review",
  );
  const reviewedCaseId = stringFieldFromResponse(reviewResponse.body, "id", "smoke VAS case review");
  if (reviewedCaseId !== caseId) throw new Error(`smoke VAS case review reported case ${JSON.stringify(reviewedCaseId)}`);
  const reviewedStatus = stringFieldFromResponse(reviewResponse.body, "status", "smoke VAS case review");
  if (reviewedStatus !== "reviewed") throw new Error(`smoke VAS case review status was ${JSON.stringify(reviewedStatus)}`);

  const learningsResponse = await smokeJson(`${vasBaseUrl}/learnings`, { headers }, [200], "GET smoke VAS learnings");
  const learnings = arrayFieldFromResponse(learningsResponse.body, "learnings", "smoke VAS learnings");
  const learningRecorded = learnings.some((item) =>
    isRecord(item) &&
    item.caseId === caseId &&
    item.text === learningText &&
    item.reviewDecision === "approved" &&
    item.runId === gateRunId
  );
  if (!learningRecorded) throw new Error("smoke VAS learnings did not include the approved review learning");

  const learnedPatterns = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/projects/${encodeURIComponent(project)}/files?path=${encodeURIComponent("vocabulary/learned-patterns.md")}`,
    { headers },
    [200],
    "GET smoke VAS learned patterns",
  );
  const learnedPatternsContent = stringFieldFromResponse(learnedPatterns.body, "content", "smoke VAS learned patterns");
  if (!learnedPatternsContent.includes(learningText) || !learnedPatternsContent.includes(`run=${gateRunId}`)) {
    throw new Error("smoke VAS learned patterns did not include the approved review learning");
  }
  const agentGitServiceWikiMemory = await verifySmokeAgentGitServiceWikiMemoryProjection(
    url,
    headers,
    tenant,
    project,
    caseId,
  );

  return {
    vasReviewGateChecked: true,
    vasReviewGateCaseId: caseId,
    vasReviewGateRunId: gateRunId,
    vasReviewGateRunStatus: "review_required",
    vasReviewGateDecision: "approved",
    vasReviewGateCaseStatus: "reviewed",
    vasReviewLearningRecorded: true,
    vasReviewLearningText: learningText,
    vasReviewLearnedPatternsRead: true,
    ...(agentGitServiceWikiMemory ?? {}),
  };
}

async function verifySmokeAgentGitServiceWikiMemoryProjection(
  url: string,
  headers: Record<string, string>,
  tenant: string,
  project: string,
  caseId: string,
): Promise<HarnessSmokeAgentGitServiceWikiMemoryResult | undefined> {
  const audit = await smokeJson(
    `${url}/tenants/${encodeURIComponent(tenant)}/audit?project=${encodeURIComponent(project)}`,
    { headers },
    [200],
    "GET smoke AGS wiki memory audit",
  );
  if (!Array.isArray(audit.body)) throw new Error("smoke AGS wiki memory audit response was not an array");
  const event = audit.body.find((item) => {
    if (!isRecord(item) || item.type !== "agent_git_service_wiki_memory_updated") return false;
    const data = item.data;
    return isRecord(data) &&
      data.provider === "agent-git-service" &&
      data.project === project &&
      data.caseId === caseId;
  });
  if (!isRecord(event) || !isRecord(event.data)) return undefined;
  const sha = optionalStringFieldFromResponse(event.data, "sha");
  const memoryUrl = optionalStringFieldFromResponse(event.data, "url");
  return {
    agentGitServiceWikiMemoryChecked: true,
    agentGitServiceWikiMemoryPage: stringFieldFromResponse(event.data, "page", "smoke AGS wiki memory audit"),
    agentGitServiceWikiMemoryLearningCount: numberFieldFromResponse(event.data, "learningCount", "smoke AGS wiki memory audit"),
    ...(sha ? { agentGitServiceWikiMemorySha: sha } : {}),
    ...(memoryUrl ? { agentGitServiceWikiMemoryUrl: memoryUrl } : {}),
  };
}

async function waitForSmokeWorkspaceSessionEvents(
  eventsUrl: string,
  headers: Record<string, string>,
  output: string,
): Promise<unknown[]> {
  const deadline = Date.now() + SMOKE_POLL_TIMEOUT_MS;
  let lastError = "";
  while (Date.now() < deadline) {
    try {
      const response = await smokeJson(eventsUrl, { headers }, [200], "GET smoke workspace session events");
      if (!Array.isArray(response.body)) {
        throw new Error("smoke workspace session events response was not an array");
      }
      const sawOutput = response.body.some((event) =>
        isRecord(event) && event.type === "stdout" && typeof event.data === "string" && event.data.includes(output)
      );
      const sawExit = response.body.some((event) => isRecord(event) && event.type === "exit" && event.exitCode === 0);
      if (sawOutput && sawExit) return response.body;
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);
    }
    await sleep(100);
  }
  throw new Error(lastError || "smoke workspace session did not produce output and exit before timeout");
}

async function waitForSmokeRunStatus(
  runUrl: string,
  headers: Record<string, string>,
  expectedStatus: string,
  label: string,
  timeoutMs = SMOKE_POLL_TIMEOUT_MS,
): Promise<{ body: unknown }> {
  const deadline = Date.now() + timeoutMs;
  let lastStatus = "";
  let lastError = "";
  while (Date.now() < deadline) {
    try {
      const response = await smokeJson(runUrl, { headers }, [200], `GET ${label}`);
      const status = stringFieldFromResponse(response.body, "status", label);
      if (status === expectedStatus) return { body: response.body };
      lastStatus = status;
      if (status === "failed" || status === "error" || status === "cancelled") {
        throw new Error(`${label} finished with status ${status}`);
      }
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);
    }
    await sleep(100);
  }
  throw new Error(lastError || `${label} did not reach ${expectedStatus} before timeout; last status ${lastStatus || "<unknown>"}`);
}

async function waitForSmokeRunEvent(
  eventsUrl: string,
  headers: Record<string, string>,
  predicate: (event: unknown) => boolean,
  label: string,
): Promise<unknown[]> {
  const deadline = Date.now() + SMOKE_POLL_TIMEOUT_MS;
  let lastError = "";
  while (Date.now() < deadline) {
    try {
      const response = await smokeJson(eventsUrl, { headers }, [200], `GET ${label} events`);
      if (!Array.isArray(response.body)) throw new Error(`${label} events response was not an array`);
      if (response.body.some(predicate)) return response.body;
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);
    }
    await sleep(100);
  }
  throw new Error(lastError || `${label} event did not appear before timeout`);
}

async function verifySmokeTenantIsolation(
  url: string,
  headers: Record<string, string>,
  isolationTenant: string,
): Promise<true> {
  const response = await smokeJson(
    `${url}/tenants/${encodeURIComponent(isolationTenant)}/status`,
    { headers },
    [401, 403],
    "GET isolation tenant status",
  );
  if (response.status === 401 || response.status === 403) return true;
  throw new Error(`isolation tenant ${isolationTenant} was readable with the smoke token`);
}

function verifySmokeOnlineSandboxGoldenPath(
  profile: HarnessSmokeProfileName,
  checks: Record<string, boolean>,
  extraCapabilities: string[] = [],
): HarnessSmokeOnlineSandboxGoldenPathResult {
  const requiredCapabilities = [...SMOKE_ONLINE_SANDBOX_GOLDEN_PATH_CAPABILITIES, ...extraCapabilities];
  const missingCapabilities = requiredCapabilities.filter((capability) => !checks[capability]);
  if (missingCapabilities.length) {
    throw smokeCheckError(
      "SMOKE_ONLINE_SANDBOX_GOLDEN_PATH_MISSING",
      `smoke profile ${profile} did not complete the online sandbox golden path`,
      {
        profile,
        missingCapabilities,
        requiredCapabilities,
      },
    );
  }
  return {
    onlineSandboxGoldenPathChecked: true,
    onlineSandboxGoldenPathProfile: profile,
    onlineSandboxGoldenPathCapabilities: requiredCapabilities,
  };
}

async function verifySmokeServerProfile(
  url: string,
  profile: HarnessSmokeProfileName,
  headers: Record<string, string>,
): Promise<{
  profile: HarnessSmokeProfileName;
  allowedTools: string[];
  readinessOk: boolean;
  readinessMissing: string[];
  goldenPathOk: boolean;
  goldenPathCapabilities: string[];
  goldenPathMissingCapabilities: string[];
  runWorkspaceIsolation: string;
  controlPlaneProvider: string;
  controlPlaneBoundary: string[];
  controlPlaneApiBasePath?: string;
  controlPlaneDiscoveryEndpoints: string[];
  controlPlaneNativeCapabilities: string[];
  controlPlaneAdoptionStages: string[];
  controlPlaneGatedAdoptionStages: string[];
  controlPlaneTenantDefaultCutoverGated: boolean;
  concurrencyAdmissionChecked: true;
  concurrencyAdmissionSchemaVersion: string;
  concurrencyAdmissionRunWorkspaceIsolation: string;
  concurrencyAdmissionActiveRunClaimScope: string;
  concurrencyAdmissionQueueBlockedReasons: string[];
  concurrencyAdmissionRunControlCrossServer: boolean;
  controlPlaneDiscoveryChecked?: true;
  controlPlaneDiscoveryProvider?: string;
  controlPlaneDiscoveryOk?: boolean;
  controlPlaneDiscoveryBaseUrlConfigured?: boolean;
  controlPlaneDiscoveryEndpointCount?: number;
  controlPlaneDiscoveryOkEndpointCount?: number;
  controlPlaneDiscoveryMissingEndpoints?: string[];
  controlPlaneDiscoveryTokenMode?: string;
  controlPlaneDiscoveryTenantCount?: number;
  controlPlaneDiscoveryTenantOkCount?: number;
  controlPlaneDiscoveryMissingTenants?: string[];
  controlPlaneWorkspaceBranchLeaseChecked?: true;
  controlPlaneWorkspaceBranchLeaseProvider?: string;
  controlPlaneWorkspaceBranchLeaseIsolation?: string;
  controlPlaneWorkspaceBranchLeaseBranchDerivation?: string;
  controlPlaneWorkspaceBranchLeaseActiveRunLeaseEvidence?: boolean;
  agentGitServiceProjectAgentsChecked?: true;
  agentGitServiceProjectAgentsProvider?: string;
  agentGitServiceProjectAgentsOk?: boolean;
  agentGitServiceProjectAgentsTenantCount?: number;
  agentGitServiceProjectAgentsProjectCount?: number;
  agentGitServiceProjectAgentsProvisionedProjectCount?: number;
  agentGitServiceProjectAgentsSecretRootConfigured?: boolean;
  agentGitServiceProjectAgentsSecretStoredProjectCount?: number;
  agentGitServiceProjectAgentsMissingProjects?: string[];
  agentGitServiceProjectAgentsMissingSecretProjects?: string[];
  visionLockTarget: string;
  visionLockMvpIsScopeReduction: boolean;
  visionLockCapabilities: string[];
}> {
  const response = await smokeJson(`${url}/status`, { headers }, [200], "GET server status");
  const server = recordFieldFromResponse(response.body, "server", "server status");
  const actual = typeof server.profile === "string" ? server.profile : undefined;
  if (actual !== profile) {
    throw smokeCheckError(
      "SMOKE_SERVER_PROFILE_MISMATCH",
      `server profile ${actual ?? "<unset>"} does not match requested smoke profile ${profile}`,
      { scope: "server", expectedProfile: profile, actualProfile: actual ?? null },
    );
  }
  const policy = recordFieldFromResponse(response.body, "policy", "server status");
  const allowedTools = requireSmokeStringArray(
    arrayFieldFromResponse(policy, "allowedTools", "server status policy"),
    "server status policy allowedTools must be strings",
    "SMOKE_SERVER_TOOLS_INVALID",
    { scope: "server", profile, field: "policy.allowedTools" },
  );
  requireOnlineSandboxTools(`server profile ${profile}`, allowedTools, "SMOKE_SERVER_TOOLS_MISSING", {
    scope: "server",
    profile,
  });
  const readiness = recordFieldFromResponse(response.body, "readiness", "server status");
  const readinessProfile = typeof readiness.profile === "string" ? readiness.profile : undefined;
  if (readinessProfile !== profile) {
    throw smokeCheckError(
      "SMOKE_SERVER_READINESS_PROFILE_MISMATCH",
      `server readiness profile ${readinessProfile ?? "<unset>"} does not match requested smoke profile ${profile}`,
      { scope: "server", expectedProfile: profile, actualProfile: readinessProfile ?? null },
    );
  }
  const readinessOk = booleanFieldFromResponse(readiness, "ok", "server status readiness");
  const readinessMissing = requireSmokeStringArray(
    arrayFieldFromResponse(readiness, "missing", "server status readiness"),
    "server status readiness missing must be strings",
    "SMOKE_SERVER_READINESS_INVALID",
    { scope: "server", profile, field: "readiness.missing" },
  );
  const agentGitServiceProjectAgents = smokeAgentGitServiceProjectAgentsStatus(readiness);
  const controlPlaneDiscovery = smokeControlPlaneDiscoveryStatus(readiness, "server", profile);
  if (!readinessOk) {
    throw smokeCheckError(
      "SMOKE_SERVER_READINESS_MISSING",
      `server profile ${profile} missing readiness: ${readinessMissing.join(", ")}`,
      { scope: "server", profile, missing: readinessMissing, ...(agentGitServiceProjectAgents ?? {}), ...(controlPlaneDiscovery ?? {}) },
    );
  }
  const goldenPath = verifySmokeStatusGoldenPath("server", profile, readiness);
  const controlPlane = verifySmokeControlPlaneStatus(profile, server);
  const controlPlaneAdoptionStages = controlPlane.adoptionStages.map((stage) => stage.name);
  const controlPlaneGatedAdoptionStages = controlPlane.adoptionStages
    .filter((stage) => stage.state === "gated")
    .map((stage) => stage.name);
  const runWorkspaceIsolation = runWorkspaceIsolationFieldFromResponse(
    server,
    "server",
    profile,
    "server status",
  );
  const concurrencyAdmission = smokeConcurrencyAdmissionStatus(
    server,
    "server",
    profile,
    runWorkspaceIsolation,
  );
  if (profile === "platform-readiness" && runWorkspaceIsolation !== "run") {
    throw smokeCheckError(
      "SMOKE_SERVER_RUN_WORKSPACE_ISOLATION_REQUIRED",
      `server profile ${profile} requires run workspace isolation`,
      { scope: "server", profile, expected: "run", actual: runWorkspaceIsolation },
    );
  }
  const workspaceBranchLease = profile === "platform-readiness"
    ? verifySmokeControlPlaneWorkspaceBranchLeaseStatus(profile, readiness)
    : undefined;
  const visionLock = recordFieldFromResponse(response.body, "visionLock", "server status");
  const visionLockTarget = stringFieldFromResponse(visionLock, "target", "server status visionLock");
  const missingTargetMarkers = SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS.filter((marker) => !visionLockTarget.includes(marker));
  if (missingTargetMarkers.length) {
    throw smokeCheckError(
      "SMOKE_VISION_LOCK_TARGET_MISMATCH",
      `server profile ${profile} reported an unexpected vision lock target`,
      {
        scope: "server",
        profile,
        actualTarget: visionLockTarget,
        missingTargetMarkers,
        requiredTargetMarkers: SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS,
      },
    );
  }
  const visionLockMvpIsScopeReduction = booleanFieldFromResponse(visionLock, "mvpIsScopeReduction", "server status visionLock");
  if (visionLockMvpIsScopeReduction !== false) {
    throw smokeCheckError(
      "SMOKE_VISION_LOCK_SCOPE_REDUCTION",
      `server profile ${profile} reported MVP as a scope reduction`,
      {
        scope: "server",
        profile,
        mvpIsScopeReduction: visionLockMvpIsScopeReduction,
      },
    );
  }
  const visionLockCapabilities = arrayFieldFromResponse(visionLock, "capabilities", "server status visionLock");
  const visionLockCapabilityNames = requireSmokeStringArray(
    visionLockCapabilities,
    "server status visionLock capabilities must be strings",
    "SMOKE_VISION_LOCK_CAPABILITIES_INVALID",
    { scope: "server", profile, field: "visionLock.capabilities" },
  );
  const missingVisionCapabilities = SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES.filter((capability) => !visionLockCapabilityNames.includes(capability));
  if (missingVisionCapabilities.length) {
    throw smokeCheckError(
      "SMOKE_VISION_LOCK_CAPABILITIES_MISSING",
      `server profile ${profile} missing vision lock capabilities: ${missingVisionCapabilities.join(", ")}`,
      {
        scope: "server",
        profile,
        missingCapabilities: missingVisionCapabilities,
        requiredCapabilities: SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES,
      },
    );
  }
  return {
    profile,
    allowedTools,
    readinessOk,
    readinessMissing,
    goldenPathOk: goldenPath.ok,
    goldenPathCapabilities: goldenPath.capabilities,
    goldenPathMissingCapabilities: goldenPath.missingCapabilities,
    runWorkspaceIsolation,
    controlPlaneProvider: controlPlane.provider,
    controlPlaneBoundary: controlPlane.boundary,
    controlPlaneApiBasePath: controlPlane.apiBasePath,
    controlPlaneDiscoveryEndpoints: controlPlane.discoveryEndpoints,
    controlPlaneNativeCapabilities: controlPlane.nativeCapabilities,
    controlPlaneAdoptionStages,
    controlPlaneGatedAdoptionStages,
    controlPlaneTenantDefaultCutoverGated: controlPlane.adoptionStages.some((stage) =>
      stage.name === "tenant-default-cutover" && stage.state === "gated"
    ),
    ...concurrencyAdmission,
    ...(controlPlaneDiscovery ?? {}),
    controlPlaneWorkspaceBranchLeaseChecked: workspaceBranchLease ? true : undefined,
    controlPlaneWorkspaceBranchLeaseProvider: workspaceBranchLease?.provider,
    controlPlaneWorkspaceBranchLeaseIsolation: workspaceBranchLease?.runWorkspaceIsolation,
    controlPlaneWorkspaceBranchLeaseBranchDerivation: workspaceBranchLease?.branchDerivation,
    controlPlaneWorkspaceBranchLeaseActiveRunLeaseEvidence: workspaceBranchLease?.activeRunLeaseEvidence,
    ...(agentGitServiceProjectAgents ?? {}),
    visionLockTarget,
    visionLockMvpIsScopeReduction,
    visionLockCapabilities: visionLockCapabilityNames,
  };
}

async function verifySmokeTenantProfileTools(
  url: string,
  tenant: string,
  profile: HarnessSmokeProfileName,
  headers: Record<string, string>,
): Promise<{
  allowedTools: string[];
  readinessProfile: HarnessSmokeProfileName;
  readinessOk: boolean;
  readinessMissing: string[];
  goldenPathOk: boolean;
  goldenPathCapabilities: string[];
  goldenPathMissingCapabilities: string[];
  runWorkspaceIsolation?: string;
  controlPlaneProvider: string;
  controlPlaneBoundary: string[];
  controlPlaneAdoptionStages: string[];
  controlPlaneGatedAdoptionStages: string[];
  controlPlaneTenantDefaultCutoverGated: boolean;
  concurrencyAdmissionChecked: true;
  concurrencyAdmissionSchemaVersion: string;
  concurrencyAdmissionRunWorkspaceIsolation: string;
  concurrencyAdmissionActiveRunClaimScope: string;
  concurrencyAdmissionQueueBlockedReasons: string[];
  concurrencyAdmissionRunControlCrossServer: boolean;
  controlPlaneDiscoveryChecked?: true;
  controlPlaneDiscoveryProvider?: string;
  controlPlaneDiscoveryOk?: boolean;
  controlPlaneDiscoveryBaseUrlConfigured?: boolean;
  controlPlaneDiscoveryEndpointCount?: number;
  controlPlaneDiscoveryOkEndpointCount?: number;
  controlPlaneDiscoveryMissingEndpoints?: string[];
  controlPlaneDiscoveryTokenMode?: string;
  controlPlaneDiscoveryTenantCount?: number;
  controlPlaneDiscoveryTenantOkCount?: number;
  controlPlaneDiscoveryMissingTenants?: string[];
  visionLockTarget: string;
  visionLockMvpIsScopeReduction: boolean;
  visionLockCapabilities: string[];
}> {
  const response = await smokeJson(`${url}/tenants/${encodeURIComponent(tenant)}/status`, { headers }, [200], "GET tenant status");
  const policy = recordFieldFromResponse(response.body, "policy", "tenant status");
  const allowedTools = requireSmokeStringArray(
    arrayFieldFromResponse(policy, "allowedTools", "tenant status policy"),
    "tenant status policy allowedTools must be strings",
    "SMOKE_TENANT_TOOLS_INVALID",
    { scope: "tenant", tenant, profile, field: "policy.allowedTools" },
  );
  requireOnlineSandboxTools(`tenant ${tenant} profile ${profile}`, allowedTools, "SMOKE_TENANT_TOOLS_MISSING", {
    scope: "tenant",
    tenant,
    profile,
  });
  if (!isRecord(response.body) || !isRecord(response.body.readiness)) {
    throw smokeCheckError(
      "SMOKE_TENANT_READINESS_MISSING",
      "tenant status did not include readiness",
      { scope: "tenant", tenant, profile, missing: ["readiness"] },
    );
  }
  const readiness = response.body.readiness;
  const readinessProfile = typeof readiness.profile === "string" ? readiness.profile : undefined;
  if (readinessProfile !== profile) {
    throw smokeCheckError(
      "SMOKE_TENANT_READINESS_PROFILE_MISMATCH",
      `tenant ${tenant} readiness profile ${readinessProfile ?? "<unset>"} does not match requested smoke profile ${profile}`,
      { scope: "tenant", tenant, expectedProfile: profile, actualProfile: readinessProfile ?? null },
    );
  }
  const readinessOk = booleanFieldFromResponse(readiness, "ok", "tenant status readiness");
  const readinessMissing = requireSmokeStringArray(
    arrayFieldFromResponse(readiness, "missing", "tenant status readiness"),
    "tenant status readiness missing must be strings",
    "SMOKE_TENANT_READINESS_INVALID",
    { scope: "tenant", tenant, profile, field: "readiness.missing" },
  );
  const controlPlaneDiscovery = smokeControlPlaneDiscoveryStatus(readiness, "tenant", profile, tenant);
  if (!readinessOk) {
    throw smokeCheckError(
      "SMOKE_TENANT_READINESS_MISSING",
      `tenant ${tenant} profile ${profile} missing readiness: ${readinessMissing.join(", ")}`,
      { scope: "tenant", tenant, profile, missing: readinessMissing, ...(controlPlaneDiscovery ?? {}) },
    );
  }
  const goldenPath = verifySmokeStatusGoldenPath("tenant", profile, readiness, tenant);
  const tenantServer = isRecord(response.body.server) ? response.body.server : undefined;
  if (!tenantServer) {
    throw smokeCheckError(
      "SMOKE_TENANT_SERVER_MISSING",
      "tenant status did not include server metadata",
      { scope: "tenant", tenant, profile, missing: ["server"] },
    );
  }
  const controlPlane = verifySmokeControlPlaneStatus(profile, tenantServer, "tenant", tenant);
  const controlPlaneAdoptionStages = controlPlane.adoptionStages.map((stage) => stage.name);
  const controlPlaneGatedAdoptionStages = controlPlane.adoptionStages
    .filter((stage) => stage.state === "gated")
    .map((stage) => stage.name);
  const runWorkspaceIsolation = tenantServer
    ? runWorkspaceIsolationFieldFromResponse(
      tenantServer,
      "tenant",
      profile,
      "tenant status",
      tenant,
    )
    : undefined;
  const concurrencyAdmission = smokeConcurrencyAdmissionStatus(
    tenantServer,
    "tenant",
    profile,
    runWorkspaceIsolation,
    tenant,
  );
  if (profile === "platform-readiness" && runWorkspaceIsolation !== "run") {
    throw smokeCheckError(
      "SMOKE_TENANT_RUN_WORKSPACE_ISOLATION_REQUIRED",
      `tenant ${tenant} profile ${profile} requires run workspace isolation`,
      { scope: "tenant", tenant, profile, expected: "run", actual: runWorkspaceIsolation ?? null },
    );
  }
  if (!isRecord(response.body) || !isRecord(response.body.visionLock)) {
    throw smokeCheckError(
      "SMOKE_TENANT_VISION_LOCK_MISSING",
      "tenant status did not include visionLock",
      { scope: "tenant", tenant, profile, missing: ["visionLock"] },
    );
  }
  const visionLock = response.body.visionLock;
  const visionLockTarget = stringFieldFromResponse(visionLock, "target", "tenant status visionLock");
  const missingTargetMarkers = SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS.filter((marker) => !visionLockTarget.includes(marker));
  if (missingTargetMarkers.length) {
    throw smokeCheckError(
      "SMOKE_TENANT_VISION_LOCK_TARGET_MISMATCH",
      `tenant ${tenant} profile ${profile} reported an unexpected vision lock target`,
      {
        scope: "tenant",
        tenant,
        profile,
        actualTarget: visionLockTarget,
        missingTargetMarkers,
        requiredTargetMarkers: SMOKE_REQUIRED_VISION_LOCK_TARGET_MARKERS,
      },
    );
  }
  const visionLockMvpIsScopeReduction = booleanFieldFromResponse(visionLock, "mvpIsScopeReduction", "tenant status visionLock");
  if (visionLockMvpIsScopeReduction !== false) {
    throw smokeCheckError(
      "SMOKE_TENANT_VISION_LOCK_SCOPE_REDUCTION",
      `tenant ${tenant} profile ${profile} reported MVP as a scope reduction`,
      {
        scope: "tenant",
        tenant,
        profile,
        mvpIsScopeReduction: visionLockMvpIsScopeReduction,
      },
    );
  }
  const visionLockCapabilityNames = requireSmokeStringArray(
    arrayFieldFromResponse(visionLock, "capabilities", "tenant status visionLock"),
    "tenant status visionLock capabilities must be strings",
    "SMOKE_TENANT_VISION_LOCK_CAPABILITIES_INVALID",
    { scope: "tenant", tenant, profile, field: "visionLock.capabilities" },
  );
  const missingVisionCapabilities = SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES.filter((capability) => !visionLockCapabilityNames.includes(capability));
  if (missingVisionCapabilities.length) {
    throw smokeCheckError(
      "SMOKE_TENANT_VISION_LOCK_CAPABILITIES_MISSING",
      `tenant ${tenant} profile ${profile} missing vision lock capabilities: ${missingVisionCapabilities.join(", ")}`,
      {
        scope: "tenant",
        tenant,
        profile,
        missingCapabilities: missingVisionCapabilities,
        requiredCapabilities: SMOKE_REQUIRED_VISION_LOCK_CAPABILITIES,
      },
    );
  }
  return {
    allowedTools,
    readinessProfile,
    readinessOk,
    readinessMissing,
    goldenPathOk: goldenPath.ok,
    goldenPathCapabilities: goldenPath.capabilities,
    goldenPathMissingCapabilities: goldenPath.missingCapabilities,
    runWorkspaceIsolation,
    controlPlaneProvider: controlPlane.provider,
    controlPlaneBoundary: controlPlane.boundary,
    controlPlaneAdoptionStages,
    controlPlaneGatedAdoptionStages,
    controlPlaneTenantDefaultCutoverGated: controlPlane.adoptionStages.some((stage) =>
      stage.name === "tenant-default-cutover" && stage.state === "gated"
    ),
    ...concurrencyAdmission,
    ...(controlPlaneDiscovery ?? {}),
    visionLockTarget,
    visionLockMvpIsScopeReduction,
    visionLockCapabilities: visionLockCapabilityNames,
  };
}

function smokeConcurrencyAdmissionStatus(
  server: Record<string, unknown>,
  scope: "server" | "tenant",
  profile: string | undefined,
  expectedRunWorkspaceIsolation: string | undefined,
  tenant?: string,
): {
  concurrencyAdmissionChecked: true;
  concurrencyAdmissionSchemaVersion: string;
  concurrencyAdmissionRunWorkspaceIsolation: string;
  concurrencyAdmissionActiveRunClaimScope: string;
  concurrencyAdmissionQueueBlockedReasons: string[];
  concurrencyAdmissionRunControlCrossServer: boolean;
} {
  const label = scope === "tenant" ? `tenant ${tenant} status` : "server status";
  const details = tenant ? { scope, tenant, profile } : { scope, profile };
  const admission = recordFieldFromResponse(server, "concurrencyAdmission", label);
  const schemaVersion = stringFieldFromResponse(admission, "schemaVersion", `${label} concurrencyAdmission`);
  if (schemaVersion !== SMOKE_CONCURRENCY_ADMISSION_SCHEMA_VERSION) {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_SCHEMA_MISMATCH" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_SCHEMA_MISMATCH",
      `${label} reported an unexpected concurrencyAdmission schemaVersion`,
      { ...details, expected: SMOKE_CONCURRENCY_ADMISSION_SCHEMA_VERSION, actual: schemaVersion },
    );
  }
  const runWorkspaceIsolation = stringFieldFromResponse(admission, "runWorkspaceIsolation", `${label} concurrencyAdmission`);
  if (runWorkspaceIsolation !== "project" && runWorkspaceIsolation !== "run") {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_ISOLATION_INVALID" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_ISOLATION_INVALID",
      `${label} reported an invalid concurrencyAdmission runWorkspaceIsolation`,
      { ...details, actual: runWorkspaceIsolation },
    );
  }
  if (expectedRunWorkspaceIsolation !== undefined && runWorkspaceIsolation !== expectedRunWorkspaceIsolation) {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_ISOLATION_MISMATCH" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_ISOLATION_MISMATCH",
      `${label} concurrencyAdmission runWorkspaceIsolation did not match server.runWorkspaceIsolation`,
      { ...details, expected: expectedRunWorkspaceIsolation, actual: runWorkspaceIsolation },
    );
  }
  const activeRun = recordFieldFromResponse(admission, "activeRun", `${label} concurrencyAdmission`);
  const activeRunClaimScope = stringFieldFromResponse(activeRun, "claimScope", `${label} concurrencyAdmission activeRun`);
  if (activeRunClaimScope !== runWorkspaceIsolation) {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_CLAIM_SCOPE_MISMATCH" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_CLAIM_SCOPE_MISMATCH",
      `${label} concurrencyAdmission activeRun claimScope did not match runWorkspaceIsolation`,
      { ...details, expected: runWorkspaceIsolation, actual: activeRunClaimScope },
    );
  }
  const queueing = recordFieldFromResponse(admission, "queueing", `${label} concurrencyAdmission`);
  const blockedReasons = requireSmokeStringArray(
    arrayFieldFromResponse(queueing, "blockedReasons", `${label} concurrencyAdmission queueing`),
    `${label} concurrencyAdmission queueing blockedReasons must be strings`,
    scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_BLOCKERS_INVALID" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_BLOCKERS_INVALID",
    { ...details, field: "server.concurrencyAdmission.queueing.blockedReasons" },
  );
  const missingBlockedReasons = SMOKE_CONCURRENCY_ADMISSION_BLOCKED_REASONS.filter((reason) => !blockedReasons.includes(reason));
  if (missingBlockedReasons.length) {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_BLOCKERS_MISSING" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_BLOCKERS_MISSING",
      `${label} concurrencyAdmission missing queued-run blockers: ${missingBlockedReasons.join(", ")}`,
      { ...details, missingBlockedReasons, blockedReasons },
    );
  }
  const runControl = recordFieldFromResponse(admission, "runControl", `${label} concurrencyAdmission`);
  const runControlCrossServer = booleanFieldFromResponse(runControl, "crossServer", `${label} concurrencyAdmission runControl`);
  if (!runControlCrossServer) {
    throw smokeCheckError(
      scope === "tenant" ? "SMOKE_TENANT_CONCURRENCY_ADMISSION_RUN_CONTROL_NOT_CROSS_SERVER" : "SMOKE_SERVER_CONCURRENCY_ADMISSION_RUN_CONTROL_NOT_CROSS_SERVER",
      `${label} concurrencyAdmission runControl must be cross-server`,
      { ...details },
    );
  }
  return {
    concurrencyAdmissionChecked: true,
    concurrencyAdmissionSchemaVersion: schemaVersion,
    concurrencyAdmissionRunWorkspaceIsolation: runWorkspaceIsolation,
    concurrencyAdmissionActiveRunClaimScope: activeRunClaimScope,
    concurrencyAdmissionQueueBlockedReasons: blockedReasons,
    concurrencyAdmissionRunControlCrossServer: runControlCrossServer,
  };
}

function verifySmokeStatusGoldenPath(
  scope: "server" | "tenant" | "auth-roles",
  profile: string | undefined,
  readiness: Record<string, unknown>,
  tenant?: string,
): { ok: boolean; capabilities: string[]; missingCapabilities: string[] } {
  const detailsBase = scope === "auth-roles"
    ? { scope, tenant, profile: profile ?? null }
    : tenant
      ? { scope, tenant, profile }
      : { scope, profile };
  const codePrefix = scope === "server"
    ? "SMOKE_SERVER_GOLDEN_PATH"
    : scope === "tenant"
      ? "SMOKE_TENANT_GOLDEN_PATH"
      : "SMOKE_AUTH_VIEWER_GOLDEN_PATH";
  const label = scope === "auth-roles"
    ? "smoke viewer tenant status"
    : tenant
      ? `tenant ${tenant} profile ${profile}`
      : `server profile ${profile}`;
  if (!isRecord(readiness.goldenPath)) {
    throw smokeCheckError(
      `${codePrefix}_MISSING`,
      `${label} did not report readiness golden path`,
      { ...detailsBase, missing: ["readiness.goldenPath"] },
    );
  }
  const goldenPath = readiness.goldenPath;
  const required = booleanFieldFromResponse(goldenPath, "required", "readiness goldenPath");
  const ok = booleanFieldFromResponse(goldenPath, "ok", "readiness goldenPath");
  const capabilities = requireSmokeStringArray(
    arrayFieldFromResponse(goldenPath, "capabilities", "readiness goldenPath"),
    "readiness goldenPath capabilities must be strings",
    `${codePrefix}_INVALID`,
    { ...detailsBase, field: "readiness.goldenPath.capabilities" },
  );
  const reportedMissingCapabilities = requireSmokeStringArray(
    arrayFieldFromResponse(goldenPath, "missingCapabilities", "readiness goldenPath"),
    "readiness goldenPath missingCapabilities must be strings",
    `${codePrefix}_INVALID`,
    { ...detailsBase, field: "readiness.goldenPath.missingCapabilities" },
  );
  const missingRequiredCapabilities = SMOKE_ONLINE_SANDBOX_GOLDEN_PATH_CAPABILITIES.filter(
    (capability) => !capabilities.includes(capability),
  );
  const missingCapabilities = Array.from(new Set([
    ...missingRequiredCapabilities,
    ...reportedMissingCapabilities,
    ...(required ? [] : ["profile-readiness"]),
    ...(ok || missingRequiredCapabilities.length || reportedMissingCapabilities.length ? [] : ["profile-readiness"]),
  ]));
  if (!required || !ok || missingCapabilities.length) {
    throw smokeCheckError(
      `${codePrefix}_MISSING`,
      `${label} missing golden path capabilities: ${missingCapabilities.join(", ") || "profile-readiness"}`,
      {
        ...detailsBase,
        required,
        ok,
        missingCapabilities: missingCapabilities.length ? missingCapabilities : ["profile-readiness"],
        requiredCapabilities: SMOKE_ONLINE_SANDBOX_GOLDEN_PATH_CAPABILITIES,
      },
    );
  }
  return { ok, capabilities, missingCapabilities };
}

function verifySmokeControlPlaneWorkspaceBranchLeaseStatus(
  profile: HarnessSmokeProfileName,
  readiness: Record<string, unknown>,
): {
  provider: string;
  runWorkspaceIsolation: string;
  branchDerivation: string;
  activeRunLeaseEvidence: boolean;
} {
  const checks = recordFieldFromResponse(readiness, "checks", "server status readiness");
  const check = recordFieldFromResponse(checks, "controlPlaneWorkspaceBranchLease", "server status readiness checks");
  const required = booleanFieldFromResponse(check, "required", "server status controlPlaneWorkspaceBranchLease");
  const ok = booleanFieldFromResponse(check, "ok", "server status controlPlaneWorkspaceBranchLease");
  const provider = stringFieldFromResponse(check, "provider", "server status controlPlaneWorkspaceBranchLease");
  const runWorkspaceIsolation = stringFieldFromResponse(check, "runWorkspaceIsolation", "server status controlPlaneWorkspaceBranchLease");
  const branchDerivation = stringFieldFromResponse(check, "branchDerivation", "server status controlPlaneWorkspaceBranchLease");
  const activeRunLeaseEvidence = booleanFieldFromResponse(check, "activeRunLeaseEvidence", "server status controlPlaneWorkspaceBranchLease");
  const invalid = [
    required ? undefined : "required",
    ok ? undefined : "ok",
    runWorkspaceIsolation === "run" ? undefined : "runWorkspaceIsolation",
    branchDerivation === "run-suffixed" ? undefined : "branchDerivation",
    activeRunLeaseEvidence ? undefined : "activeRunLeaseEvidence",
  ].filter((field): field is string => Boolean(field));
  if (invalid.length) {
    throw smokeCheckError(
      "SMOKE_CONTROL_PLANE_WORKSPACE_BRANCH_LEASE_MISSING",
      `server profile ${profile} missing control-plane workspace branch lease readiness`,
      {
        scope: "server",
        profile,
        provider,
        invalid,
        runWorkspaceIsolation,
        branchDerivation,
        activeRunLeaseEvidence,
      },
    );
  }
  return { provider, runWorkspaceIsolation, branchDerivation, activeRunLeaseEvidence };
}

