function writeHarnessPlatformConcurrencyAudit(options: HarnessPlatformConcurrencyAuditCliOptions): HarnessPlatformConcurrencyAuditResult {
  const cutoverReportPath = resolve(options.cutoverReport);
  const smokeReportPath = resolve(options.smokeReport);
  const cutover = readJsonFile(cutoverReportPath);
  const smoke = readJsonFile(smokeReportPath);
  const cutoverRecord = isRecord(cutover) ? cutover : undefined;
  const smokeRecord = isRecord(smoke) ? smoke : undefined;
  const expectedProvider = options.controlPlaneProvider === undefined
    ? undefined
    : parseControlPlaneProviderFlag(options.controlPlaneProvider, "--control-plane-provider");
  const controlPlaneProvider = expectedProvider ?? platformConcurrencyProvider(cutoverRecord, smokeRecord);
  const requireAgentGitService = options.requireAgentGitService === true || expectedProvider === "agent-git-service";
  const gates = {
    cutoverConcurrencyOk: platformConcurrencyCutoverOk(cutoverRecord),
    smokeConcurrencyOk: platformConcurrencySmokeOk(smokeRecord),
    runScopedWorkspaces: platformConcurrencyRunScoped(cutoverRecord, smokeRecord),
    workspaceBranchLeaseOk: platformConcurrencyWorkspaceBranchLeaseOk(smokeRecord, controlPlaneProvider),
    multiAgentSmokeOk: platformConcurrencyMultiAgentSmokeOk(smokeRecord),
    agentGitServiceCutoverOk: requireAgentGitService
      ? platformConcurrencyAgentGitServiceCutoverOk(cutoverRecord, smokeRecord, controlPlaneProvider)
      : true,
    agentGitServiceNativeProjectionOk: requireAgentGitService
      ? platformConcurrencyAgentGitServiceNativeProjectionOk(smokeRecord, controlPlaneProvider)
      : true,
  };
  const missing = platformConcurrencyAuditMissing({
    cutoverRecord,
    smokeRecord,
    controlPlaneProvider,
    requireAgentGitService,
    gates,
  });
  return {
    schemaVersion: "platform-concurrency-audit/v1",
    ok: missing.length === 0,
    tokenFree: true,
    controlPlaneProvider,
    requireAgentGitService,
    gates,
    strategy: {
      workspaceLeaseScope: platformConcurrencyWorkspaceLeaseScope(cutoverRecord, smokeRecord),
      activeRunClaimScope: platformStringField(smokeRecord, "serverConcurrencyAdmissionActiveRunClaimScope") ??
        platformStringField(cutoverRecord, "serverConcurrencyAdmissionActiveRunClaimScope"),
      branchDerivation: platformStringField(smokeRecord, "controlPlaneWorkspaceBranchLeaseBranchDerivation"),
      agentGitServiceRole: controlPlaneProvider === "agent-git-service" ? "provider-adapter" : "not-required",
    },
    reports: {
      cutoverReportPath,
      smokeReportPath,
    },
    missing,
    nextActions: platformConcurrencyAuditNextActions(missing, requireAgentGitService),
  };
}

function platformConcurrencyProvider(
  cutover: Record<string, unknown> | undefined,
  smoke: Record<string, unknown> | undefined,
): string | undefined {
  return platformStringField(cutover, "controlPlaneProvider") ??
    platformStringField(smoke, "tenantControlPlaneProvider") ??
    platformStringField(smoke, "serverControlPlaneProvider");
}

function platformConcurrencyCutoverOk(cutover: Record<string, unknown> | undefined): boolean {
  if (!cutover) return false;
  return cutover.ok === true &&
    cutover.serverConcurrencyAdmissionOk === true &&
    cutover.tenantConcurrencyAdmissionOk === true &&
    platformStringField(cutover, "serverConcurrencyAdmissionSchemaVersion") === PLATFORM_CONCURRENCY_ADMISSION_SCHEMA_VERSION &&
    platformStringField(cutover, "tenantConcurrencyAdmissionSchemaVersion") === PLATFORM_CONCURRENCY_ADMISSION_SCHEMA_VERSION &&
    platformStringField(cutover, "serverConcurrencyAdmissionActiveRunClaimScope") ===
      platformStringField(cutover, "serverConcurrencyAdmissionRunWorkspaceIsolation") &&
    platformStringField(cutover, "tenantConcurrencyAdmissionActiveRunClaimScope") ===
      platformStringField(cutover, "tenantConcurrencyAdmissionRunWorkspaceIsolation") &&
    platformStringArray(cutover, "serverConcurrencyAdmissionMissing").length === 0 &&
    platformStringArray(cutover, "tenantConcurrencyAdmissionMissing").length === 0 &&
    cutover.serverConcurrencyAdmissionRunControlCrossServer === true &&
    cutover.tenantConcurrencyAdmissionRunControlCrossServer === true &&
    platformHasBlockedReasons(platformStringArray(cutover, "serverConcurrencyAdmissionQueueBlockedReasons")) &&
    platformHasBlockedReasons(platformStringArray(cutover, "tenantConcurrencyAdmissionQueueBlockedReasons"));
}

function platformConcurrencySmokeOk(smoke: Record<string, unknown> | undefined): boolean {
  if (!smoke) return false;
  return smoke.ok === true &&
    smoke.status === "passed" &&
    smoke.serverConcurrencyAdmissionChecked === true &&
    smoke.tenantConcurrencyAdmissionChecked === true &&
    platformStringField(smoke, "serverConcurrencyAdmissionSchemaVersion") === PLATFORM_CONCURRENCY_ADMISSION_SCHEMA_VERSION &&
    platformStringField(smoke, "tenantConcurrencyAdmissionSchemaVersion") === PLATFORM_CONCURRENCY_ADMISSION_SCHEMA_VERSION &&
    platformStringField(smoke, "serverConcurrencyAdmissionActiveRunClaimScope") ===
      platformStringField(smoke, "serverConcurrencyAdmissionRunWorkspaceIsolation") &&
    platformStringField(smoke, "tenantConcurrencyAdmissionActiveRunClaimScope") ===
      platformStringField(smoke, "tenantConcurrencyAdmissionRunWorkspaceIsolation") &&
    smoke.serverConcurrencyAdmissionRunControlCrossServer === true &&
    platformHasBlockedReasons(platformStringArray(smoke, "serverConcurrencyAdmissionQueueBlockedReasons"));
}

function platformConcurrencyRunScoped(
  cutover: Record<string, unknown> | undefined,
  smoke: Record<string, unknown> | undefined,
): boolean {
  return platformStringField(cutover, "serverConcurrencyAdmissionRunWorkspaceIsolation") === "run" &&
    platformStringField(cutover, "tenantConcurrencyAdmissionRunWorkspaceIsolation") === "run" &&
    platformStringField(smoke, "serverConcurrencyAdmissionRunWorkspaceIsolation") === "run" &&
    platformStringField(smoke, "tenantConcurrencyAdmissionRunWorkspaceIsolation") === "run";
}

function platformConcurrencyWorkspaceBranchLeaseOk(
  smoke: Record<string, unknown> | undefined,
  provider: string | undefined,
): boolean {
  if (!smoke) return false;
  const leaseProvider = platformStringField(smoke, "controlPlaneWorkspaceBranchLeaseProvider");
  return smoke.controlPlaneWorkspaceBranchLeaseChecked === true &&
    (provider === undefined || leaseProvider === provider) &&
    platformStringField(smoke, "controlPlaneWorkspaceBranchLeaseIsolation") === "run" &&
    platformStringField(smoke, "controlPlaneWorkspaceBranchLeaseBranchDerivation") === "run-suffixed" &&
    smoke.controlPlaneWorkspaceBranchLeaseActiveRunLeaseEvidence === true;
}

function platformConcurrencyMultiAgentSmokeOk(smoke: Record<string, unknown> | undefined): boolean {
  if (!smoke) return false;
  return smoke.multiAgentConcurrencyChecked === true &&
    platformStringField(smoke, "multiAgentConcurrencyIsolation") === "run" &&
    smoke.multiAgentConcurrencyActiveRunLeaseChecked === true &&
    smoke.multiAgentConcurrencyRunScopedFileWriteChecked === true &&
    smoke.multiAgentConcurrencyRunScopedPrHandoffChecked === true;
}

function platformConcurrencyAgentGitServiceCutoverOk(
  cutover: Record<string, unknown> | undefined,
  smoke: Record<string, unknown> | undefined,
  provider: string | undefined,
): boolean {
  if (provider !== "agent-git-service" || !cutover || !smoke) return false;
  const agentGitService = isRecord(cutover.agentGitService) ? cutover.agentGitService : undefined;
  return agentGitService?.checked === true &&
    agentGitService.ready === true &&
    smoke.agentGitServiceCutoverChecked === true &&
    smoke.agentGitServiceCutoverReceiptSecretAbsent === true &&
    smoke.agentGitServiceCutoverWorkspaceTokenChecked === true;
}

function platformConcurrencyAgentGitServiceNativeProjectionOk(
  smoke: Record<string, unknown> | undefined,
  provider: string | undefined,
): boolean {
  return provider === "agent-git-service" && smoke?.agentGitServiceNativeProjectionChecked === true;
}

function platformConcurrencyWorkspaceLeaseScope(
  cutover: Record<string, unknown> | undefined,
  smoke: Record<string, unknown> | undefined,
): "project" | "run" | "unknown" {
  const scope = platformStringField(smoke, "serverConcurrencyAdmissionRunWorkspaceIsolation") ??
    platformStringField(cutover, "serverConcurrencyAdmissionRunWorkspaceIsolation");
  return scope === "project" || scope === "run" ? scope : "unknown";
}

function platformConcurrencyAuditMissing(options: {
  cutoverRecord: Record<string, unknown> | undefined;
  smokeRecord: Record<string, unknown> | undefined;
  controlPlaneProvider?: string;
  requireAgentGitService: boolean;
  gates: HarnessPlatformConcurrencyAuditResult["gates"];
}): string[] {
  return [
    ...(options.cutoverRecord ? [] : ["reports.cutoverReport"]),
    ...(options.smokeRecord ? [] : ["reports.smokeReport"]),
    ...(options.requireAgentGitService && options.controlPlaneProvider !== "agent-git-service"
      ? ["controlPlaneProvider.agent-git-service"]
      : []),
    ...(options.gates.cutoverConcurrencyOk ? [] : ["cutover.concurrencyAdmission"]),
    ...(options.gates.smokeConcurrencyOk ? [] : ["smoke.concurrencyAdmission"]),
    ...(options.gates.runScopedWorkspaces ? [] : ["runWorkspaceIsolation.run"]),
    ...(options.gates.workspaceBranchLeaseOk ? [] : ["controlPlaneWorkspaceBranchLease.run"]),
    ...(options.gates.multiAgentSmokeOk ? [] : ["smoke.multiAgentConcurrencyChecked"]),
    ...(options.gates.agentGitServiceCutoverOk ? [] : ["agentGitService.cutover"]),
    ...(options.gates.agentGitServiceNativeProjectionOk ? [] : ["agentGitService.nativeProjection"]),
  ];
}

function platformConcurrencyAuditNextActions(missing: string[], requireAgentGitService: boolean): string[] {
  const actions: string[] = [];
  if (missing.includes("reports.cutoverReport") || missing.includes("reports.smokeReport")) {
    actions.push("Run loom harness cutover-report and loom harness smoke --profile platform-readiness, then rerun platform-concurrency-audit.");
  }
  if (missing.includes("cutover.concurrencyAdmission") || missing.includes("smoke.concurrencyAdmission")) {
    actions.push("Run loom harness doctor --profile platform-readiness and fix concurrencyAdmission before cutover.");
  }
  if (missing.includes("runWorkspaceIsolation.run")) {
    actions.push("Start serve with --executor-worktree-cwd <path-template> so runWorkspaceIsolation is run.");
  }
  if (missing.includes("controlPlaneWorkspaceBranchLease.run")) {
    actions.push("Enable --allow-tool git.pr and --control-plane-pr with run-scoped worktrees so workspace branch leases are ready.");
  }
  if (missing.includes("smoke.multiAgentConcurrencyChecked")) {
    actions.push("Run loom harness smoke --profile platform-readiness after run-scoped workspace isolation is active.");
  }
  if (requireAgentGitService && (missing.includes("agentGitService.cutover") || missing.includes("controlPlaneProvider.agent-git-service"))) {
    actions.push("Run loom harness apply-agent-git-service-provisioning-plan, then smoke with --control-plane-provider agent-git-service --check-agent-git-service-cutover.");
  }
  if (requireAgentGitService && missing.includes("agentGitService.nativeProjection")) {
    actions.push("Run loom harness smoke --profile platform-readiness with AGS handoff and VAS wiki-memory checks enabled, then rerun platform-concurrency-audit.");
  }
  return actions;
}

function platformHasBlockedReasons(values: string[]): boolean {
  return PLATFORM_CONCURRENCY_ADMISSION_BLOCKED_REASONS.every((reason) => values.includes(reason));
}

function platformStringField(value: Record<string, unknown> | undefined, field: string): string | undefined {
  return value && typeof value[field] === "string" ? value[field] : undefined;
}

function platformStringArray(value: Record<string, unknown> | undefined, field: string): string[] {
  return value && Array.isArray(value[field]) ? stringsOnly(value[field]) : [];
}

async function readHarnessCutoverReportViaHarness(options: HarnessCutoverReportCliOptions): Promise<HarnessCutoverReport> {
  const baseUrl = normalizeHttpBaseUrl(options.url, "--url");
  const tenant = parseSafeNameFlag(options.tenant, "--tenant");
  const expectedProvider = options.controlPlaneProvider === undefined
    ? undefined
    : parseControlPlaneProviderFlag(options.controlPlaneProvider, "--control-plane-provider");
  const tenantToken = cliTokenValue(options.token, options.tokenEnv, "--token-env");
  const adminToken = cliTokenValue(options.adminToken, options.adminTokenEnv, "--admin-token-env");
  const serverStatus = await smokeJson(
    `${baseUrl}/status`,
    { headers: smokeHeaders(adminToken ?? tenantToken) },
    [200],
    "cutover report server status",
  );
  const tenantStatus = await smokeJson(
    `${baseUrl}/tenants/${encodeURIComponent(tenant)}/status`,
    { headers: smokeHeaders(tenantToken ?? adminToken) },
    [200],
    "cutover report tenant status",
  );
  const serverReadiness = cutoverReadinessFromStatus(serverStatus.body);
  const tenantReadiness = cutoverReadinessFromStatus(tenantStatus.body);
  const serverVisionLock = cutoverVisionLockFromStatus(serverStatus.body);
  const tenantVisionLock = cutoverVisionLockFromStatus(tenantStatus.body);
  const serverConcurrencyAdmission = cutoverConcurrencyAdmissionFromStatus(serverStatus.body);
  const tenantConcurrencyAdmission = cutoverConcurrencyAdmissionFromStatus(tenantStatus.body);
  const serverControlPlaneDiscovery = cutoverControlPlaneDiscoveryFromStatus(serverStatus.body);
  const tenantControlPlaneDiscovery = cutoverControlPlaneDiscoveryFromStatus(tenantStatus.body);
  const serverProvider = cutoverControlPlaneProviderFromStatus(serverStatus.body);
  const tenantProvider = cutoverControlPlaneProviderFromStatus(tenantStatus.body);
  const provider = tenantProvider ?? serverProvider ?? expectedProvider;
  const missing = new Set<string>();

  if (!serverReadiness.ok) missing.add("serverReadiness");
  if (!tenantReadiness.ok) missing.add("tenantReadiness");
  if (serverReadiness.goldenPathOk === false || serverReadiness.goldenPathMissingCapabilities.length) missing.add("serverGoldenPath");
  if (tenantReadiness.goldenPathOk === false || tenantReadiness.goldenPathMissingCapabilities.length) missing.add("tenantGoldenPath");
  if (!serverVisionLock.ok) missing.add("serverVisionLock");
  if (!tenantVisionLock.ok) missing.add("tenantVisionLock");
  if (!serverConcurrencyAdmission.ok) missing.add("serverConcurrencyAdmission");
  if (!tenantConcurrencyAdmission.ok) missing.add("tenantConcurrencyAdmission");
  if (expectedProvider && provider !== expectedProvider) missing.add("controlPlaneProvider");

  let agentGitService: HarnessCutoverAgentGitServiceReport | undefined;
  if ((expectedProvider ?? provider) === "agent-git-service") {
    if (!adminToken) {
      missing.add("agentGitServiceProvisioningPlan");
      agentGitService = emptyCutoverAgentGitServiceReport(false);
    } else {
      const plan = await smokeJson(
        `${baseUrl}/tenants/${encodeURIComponent(tenant)}/control-plane/agent-git-service/provisioning-plan`,
        { headers: { authorization: `Bearer ${adminToken}` } },
        [200],
        "cutover report agent-git-service provisioning plan",
      );
      agentGitService = cutoverAgentGitServiceReportFromPlan(plan.body);
      if (!agentGitService.ready) missing.add("agentGitServiceProjectAgents");
    }
  }

  const missingList = [...missing];
  const agentGitServiceProvisioningCommands = (expectedProvider ?? provider) === "agent-git-service"
    ? cutoverAgentGitServiceProvisioningCommands(options, { baseUrl, tenant })
    : undefined;
  const smokeCommand = cutoverSmokeCommand(options, {
    baseUrl,
    tenant,
    provider: expectedProvider ?? provider,
  });
  return {
    ok: missingList.length === 0,
    tenant,
    controlPlaneProvider: provider,
    expectedControlPlaneProvider: expectedProvider,
    providerMatchesExpected: expectedProvider === undefined ? undefined : provider === expectedProvider,
    serverProfile: cutoverServerProfileFromStatus(serverStatus.body),
    serverReadinessOk: serverReadiness.ok,
    serverReadinessMissing: serverReadiness.missing,
    serverGoldenPathOk: serverReadiness.goldenPathOk,
    serverGoldenPathMissingCapabilities: serverReadiness.goldenPathMissingCapabilities,
    serverVisionLockOk: serverVisionLock.ok,
    serverVisionLockTarget: serverVisionLock.target,
    serverVisionLockMvpIsScopeReduction: serverVisionLock.mvpIsScopeReduction,
    serverVisionLockMissingCapabilities: serverVisionLock.missingCapabilities,
    serverConcurrencyAdmissionOk: serverConcurrencyAdmission.ok,
    serverConcurrencyAdmissionSchemaVersion: serverConcurrencyAdmission.schemaVersion,
    serverConcurrencyAdmissionRunWorkspaceIsolation: serverConcurrencyAdmission.runWorkspaceIsolation,
    serverConcurrencyAdmissionActiveRunClaimScope: serverConcurrencyAdmission.activeRunClaimScope,
    serverConcurrencyAdmissionQueueBlockedReasons: serverConcurrencyAdmission.queueBlockedReasons,
    serverConcurrencyAdmissionRunControlCrossServer: serverConcurrencyAdmission.runControlCrossServer,
    serverConcurrencyAdmissionMissing: serverConcurrencyAdmission.missing,
    serverControlPlaneDiscoveryOk: serverControlPlaneDiscovery.ok,
    serverControlPlaneDiscoveryTokenMode: serverControlPlaneDiscovery.tokenMode,
    serverControlPlaneDiscoveryTenantCount: serverControlPlaneDiscovery.tenantCount,
    serverControlPlaneDiscoveryTenantOkCount: serverControlPlaneDiscovery.tenantOkCount,
    serverControlPlaneDiscoveryMissingTenants: serverControlPlaneDiscovery.missingTenants,
    tenantReadinessProfile: tenantReadiness.profile,
    tenantReadinessOk: tenantReadiness.ok,
    tenantReadinessMissing: tenantReadiness.missing,
    tenantGoldenPathOk: tenantReadiness.goldenPathOk,
    tenantGoldenPathMissingCapabilities: tenantReadiness.goldenPathMissingCapabilities,
    tenantVisionLockOk: tenantVisionLock.ok,
    tenantVisionLockTarget: tenantVisionLock.target,
    tenantVisionLockMvpIsScopeReduction: tenantVisionLock.mvpIsScopeReduction,
    tenantVisionLockMissingCapabilities: tenantVisionLock.missingCapabilities,
    tenantConcurrencyAdmissionOk: tenantConcurrencyAdmission.ok,
    tenantConcurrencyAdmissionSchemaVersion: tenantConcurrencyAdmission.schemaVersion,
    tenantConcurrencyAdmissionRunWorkspaceIsolation: tenantConcurrencyAdmission.runWorkspaceIsolation,
    tenantConcurrencyAdmissionActiveRunClaimScope: tenantConcurrencyAdmission.activeRunClaimScope,
    tenantConcurrencyAdmissionQueueBlockedReasons: tenantConcurrencyAdmission.queueBlockedReasons,
    tenantConcurrencyAdmissionRunControlCrossServer: tenantConcurrencyAdmission.runControlCrossServer,
    tenantConcurrencyAdmissionMissing: tenantConcurrencyAdmission.missing,
    tenantControlPlaneDiscoveryOk: tenantControlPlaneDiscovery.ok,
    tenantControlPlaneDiscoveryTokenMode: tenantControlPlaneDiscovery.tokenMode,
    tenantControlPlaneDiscoveryTenantCount: tenantControlPlaneDiscovery.tenantCount,
    tenantControlPlaneDiscoveryTenantOkCount: tenantControlPlaneDiscovery.tenantOkCount,
    tenantControlPlaneDiscoveryMissingTenants: tenantControlPlaneDiscovery.missingTenants,
    missing: missingList,
    nextActions: cutoverReportNextActions({
      tenant,
      adminTokenEnv: options.adminTokenEnv,
      missing: missingList,
      agentGitServiceChecked: agentGitService?.checked ?? false,
      agentGitServiceReady: agentGitService?.ready ?? false,
      provider: expectedProvider ?? provider,
    }),
    ...(agentGitServiceProvisioningCommands
      ? {
          agentGitServiceProvisioningCommandsReady: agentGitServiceProvisioningCommands.ready,
          agentGitServiceProvisioningCommandsMissingInputs: agentGitServiceProvisioningCommands.missingInputs,
        }
      : {}),
    ...(agentGitServiceProvisioningCommands?.planArgs
      ? { agentGitServiceProvisioningPlanCommandArgs: agentGitServiceProvisioningCommands.planArgs }
      : {}),
    ...(agentGitServiceProvisioningCommands?.dryRunArgs
      ? { agentGitServiceProvisioningPlanDryRunCommandArgs: agentGitServiceProvisioningCommands.dryRunArgs }
      : {}),
    ...(agentGitServiceProvisioningCommands?.applyArgs
      ? { agentGitServiceProvisioningPlanApplyCommandArgs: agentGitServiceProvisioningCommands.applyArgs }
      : {}),
    smokeCommandReady: smokeCommand.ready,
    smokeCommandMissingInputs: smokeCommand.missingInputs,
    ...(smokeCommand.args ? { smokeCommandArgs: smokeCommand.args } : {}),
    agentGitService,
  };
}

function cutoverAgentGitServiceProvisioningCommands(
  options: HarnessCutoverReportCliOptions,
  context: { baseUrl: string; tenant: string },
): {
  ready: boolean;
  missingInputs: string[];
  planArgs?: string[];
  dryRunArgs?: string[];
  applyArgs?: string[];
} {
  const adminTokenEnv = options.adminTokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.adminTokenEnv, "--admin-token-env");
  if (!adminTokenEnv) return { ready: false, missingInputs: ["adminTokenEnv"] };

  const baseArgs = [
    "--url",
    context.baseUrl,
    "--tenant",
    context.tenant,
    "--admin-token-env",
    adminTokenEnv,
  ];
  return {
    ready: true,
    missingInputs: [],
    planArgs: [
      "loom",
      "harness",
      "agent-git-service-provisioning-plan",
      ...baseArgs,
    ],
    dryRunArgs: [
      "loom",
      "harness",
      "apply-agent-git-service-provisioning-plan",
      ...baseArgs,
      "--dry-run",
    ],
    applyArgs: [
      "loom",
      "harness",
      "apply-agent-git-service-provisioning-plan",
      ...baseArgs,
    ],
  };
}

function cutoverReadinessFromStatus(value: unknown): {
  profile?: string;
  ok: boolean;
  missing: string[];
  goldenPathOk?: boolean;
  goldenPathMissingCapabilities: string[];
} {
  const readiness = isRecord(value) && isRecord(value.readiness) ? value.readiness : undefined;
  const goldenPath = readiness && isRecord(readiness.goldenPath) ? readiness.goldenPath : undefined;
  const goldenPathCapabilities = goldenPath && Array.isArray(goldenPath.capabilities)
    ? stringsOnly(goldenPath.capabilities)
    : [];
  const reportedGoldenPathMissing = goldenPath && Array.isArray(goldenPath.missingCapabilities)
    ? stringsOnly(goldenPath.missingCapabilities)
    : [];
  const missingRequiredGoldenPathCapabilities = ONLINE_SANDBOX_GOLDEN_PATH_CAPABILITIES.filter(
    (capability) => !goldenPathCapabilities.includes(capability),
  );
  const goldenPathRequired = goldenPath && typeof goldenPath.required === "boolean" ? goldenPath.required : undefined;
  const goldenPathOk = goldenPath && typeof goldenPath.ok === "boolean" ? goldenPath.ok : undefined;
  return {
    profile: readiness && typeof readiness.profile === "string" ? readiness.profile : undefined,
    ok: readiness && typeof readiness.ok === "boolean" ? readiness.ok : false,
    missing: readiness && Array.isArray(readiness.missing) ? stringsOnly(readiness.missing) : ["readiness"],
    goldenPathOk,
    goldenPathMissingCapabilities: Array.from(new Set([
      ...missingRequiredGoldenPathCapabilities,
      ...reportedGoldenPathMissing,
      ...(goldenPathRequired === false ? ["profile-readiness"] : []),
      ...(goldenPathOk === false && !missingRequiredGoldenPathCapabilities.length && !reportedGoldenPathMissing.length
        ? ["profile-readiness"]
        : []),
    ])),
  };
}

function cutoverVisionLockFromStatus(value: unknown): {
  ok: boolean;
  target?: string;
  mvpIsScopeReduction?: boolean;
  missingCapabilities: string[];
} {
  const visionLock = isRecord(value) && isRecord(value.visionLock) ? value.visionLock : undefined;
  const target = visionLock && typeof visionLock.target === "string" ? visionLock.target : undefined;
  const mvpIsScopeReduction = visionLock && typeof visionLock.mvpIsScopeReduction === "boolean"
    ? visionLock.mvpIsScopeReduction
    : undefined;
  const capabilities = visionLock && Array.isArray(visionLock.capabilities) ? stringsOnly(visionLock.capabilities) : [];
  const missingCapabilities = HARNESS_VISION_LOCK.capabilities.filter((capability) => !capabilities.includes(capability));
  return {
    ok: target === HARNESS_VISION_LOCK.target && mvpIsScopeReduction === false && missingCapabilities.length === 0,
    target,
    mvpIsScopeReduction,
    missingCapabilities,
  };
}

function cutoverConcurrencyAdmissionFromStatus(value: unknown): {
  ok: boolean;
  schemaVersion?: string;
  runWorkspaceIsolation?: string;
  activeRunClaimScope?: string;
  queueBlockedReasons: string[];
  runControlCrossServer?: boolean;
  missing: string[];
} {
  const server = isRecord(value) && isRecord(value.server) ? value.server : undefined;
  const admission = server && isRecord(server.concurrencyAdmission) ? server.concurrencyAdmission : undefined;
  if (!admission) {
    return {
      ok: false,
      queueBlockedReasons: [],
      missing: ["concurrencyAdmission"],
    };
  }

  const missing: string[] = [];
  const schemaVersion = typeof admission.schemaVersion === "string" ? admission.schemaVersion : undefined;
  if (schemaVersion !== SMOKE_CONCURRENCY_ADMISSION_SCHEMA_VERSION) missing.push("schemaVersion");

  const statusRunWorkspaceIsolation = server && typeof server.runWorkspaceIsolation === "string"
    ? server.runWorkspaceIsolation
    : undefined;
  const runWorkspaceIsolation = typeof admission.runWorkspaceIsolation === "string"
    ? admission.runWorkspaceIsolation
    : undefined;
  if (runWorkspaceIsolation !== "project" && runWorkspaceIsolation !== "run") {
    missing.push("runWorkspaceIsolation");
  } else if (statusRunWorkspaceIsolation && runWorkspaceIsolation !== statusRunWorkspaceIsolation) {
    missing.push("runWorkspaceIsolation");
  }

  const activeRun = isRecord(admission.activeRun) ? admission.activeRun : undefined;
  const activeRunClaimScope = activeRun && typeof activeRun.claimScope === "string"
    ? activeRun.claimScope
    : undefined;
  if (runWorkspaceIsolation === "project" || runWorkspaceIsolation === "run") {
    if (activeRunClaimScope !== runWorkspaceIsolation) missing.push("activeRun.claimScope");
  } else if (activeRunClaimScope !== "project" && activeRunClaimScope !== "run") {
    missing.push("activeRun.claimScope");
  }

  const queueing = isRecord(admission.queueing) ? admission.queueing : undefined;
  const queueBlockedReasons = queueing && Array.isArray(queueing.blockedReasons)
    ? stringsOnly(queueing.blockedReasons)
    : [];
  const missingBlockedReasons = SMOKE_CONCURRENCY_ADMISSION_BLOCKED_REASONS.filter((reason) =>
    !queueBlockedReasons.includes(reason)
  );
  if (missingBlockedReasons.length) missing.push("queueing.blockedReasons");

  const runControl = isRecord(admission.runControl) ? admission.runControl : undefined;
  const runControlCrossServer = runControl && typeof runControl.crossServer === "boolean"
    ? runControl.crossServer
    : undefined;
  if (runControlCrossServer !== true) missing.push("runControl.crossServer");

  return {
    ok: missing.length === 0,
    schemaVersion,
    runWorkspaceIsolation,
    activeRunClaimScope,
    queueBlockedReasons,
    runControlCrossServer,
    missing,
  };
}

function cutoverControlPlaneDiscoveryFromStatus(value: unknown): {
  ok?: boolean;
  tokenMode?: string;
  tenantCount?: number;
  tenantOkCount?: number;
  missingTenants?: string[];
} {
  const readiness = isRecord(value) && isRecord(value.readiness) ? value.readiness : undefined;
  const checks = readiness && isRecord(readiness.checks) ? readiness.checks : undefined;
  const discovery = checks && isRecord(checks.controlPlaneDiscovery) ? checks.controlPlaneDiscovery : undefined;
  if (!discovery) return {};
  return {
    ok: typeof discovery.ok === "boolean" ? discovery.ok : undefined,
    tokenMode: typeof discovery.tokenMode === "string" ? discovery.tokenMode : undefined,
    tenantCount: typeof discovery.tenantCount === "number" ? discovery.tenantCount : undefined,
    tenantOkCount: typeof discovery.tenantOkCount === "number" ? discovery.tenantOkCount : undefined,
    missingTenants: Array.isArray(discovery.missingTenants) ? stringsOnly(discovery.missingTenants) : undefined,
  };
}

function cutoverServerProfileFromStatus(value: unknown): string | undefined {
  const server = isRecord(value) && isRecord(value.server) ? value.server : undefined;
  return server && typeof server.profile === "string" ? server.profile : undefined;
}

function cutoverControlPlaneProviderFromStatus(value: unknown): string | undefined {
  const server = isRecord(value) && isRecord(value.server) ? value.server : undefined;
  const controlPlane = server && isRecord(server.controlPlane) ? server.controlPlane : undefined;
  return controlPlane && typeof controlPlane.provider === "string" ? controlPlane.provider : undefined;
}

function emptyCutoverAgentGitServiceReport(checked: boolean): HarnessCutoverAgentGitServiceReport {
  return {
    checked,
    ready: false,
    projectCount: 0,
    readyProjectCount: 0,
    missingProjectCount: 0,
    missingSecretProjectCount: 0,
    missingProjects: [],
    projectMissing: {},
    provisionCommandArgsByProject: {},
  };
}

function cutoverAgentGitServiceReportFromPlan(value: unknown): HarnessCutoverAgentGitServiceReport {
  const plan = isRecord(value) ? value : {};
  const projects = Array.isArray(plan.projects) ? plan.projects.filter(isRecord) : [];
  const projectMissing: Record<string, string[]> = {};
  const provisionCommandArgsByProject: Record<string, string[]> = {};
  const missingProjects: string[] = [];
  for (const project of projects) {
    if (typeof project.project !== "string") continue;
    const missing = Array.isArray(project.missing) ? stringsOnly(project.missing) : [];
    if (project.ready !== true) {
      missingProjects.push(project.project);
      projectMissing[project.project] = missing;
    }
    if (Array.isArray(project.provisionCommandArgs)) {
      provisionCommandArgsByProject[project.project] = stringsOnly(project.provisionCommandArgs);
    }
  }
  const missingProjectCount = cutoverNumberField(plan, "missingProjectCount", missingProjects.length);
  const missingSecretProjectCount = cutoverNumberField(plan, "missingSecretProjectCount", 0);
  return {
    checked: true,
    ready: missingProjects.length === 0 && missingProjectCount === 0 && missingSecretProjectCount === 0,
    projectCount: cutoverNumberField(plan, "projectCount", projects.length),
    readyProjectCount: cutoverNumberField(plan, "readyProjectCount", projects.length - missingProjects.length),
    missingProjectCount,
    missingSecretProjectCount,
    missingProjects,
    projectMissing,
    provisionCommandArgsByProject,
  };
}

function cutoverNumberField(value: Record<string, unknown>, field: string, fallback: number): number {
  return typeof value[field] === "number" ? value[field] : fallback;
}

function cutoverReportNextActions(options: {
  tenant: string;
  adminTokenEnv?: string;
  missing: string[];
  agentGitServiceChecked: boolean;
  agentGitServiceReady: boolean;
  provider?: string;
}): string[] {
  const actions: string[] = [];
  if (options.missing.some((item) =>
    item === "serverReadiness" ||
    item === "tenantReadiness" ||
    item === "serverGoldenPath" ||
    item === "tenantGoldenPath" ||
    item === "serverVisionLock" ||
    item === "tenantVisionLock" ||
    item === "serverConcurrencyAdmission" ||
    item === "tenantConcurrencyAdmission"
  )) {
    actions.push("loom harness doctor --profile platform-readiness");
  }
  if (options.provider === "agent-git-service" && (!options.agentGitServiceChecked || !options.agentGitServiceReady)) {
    const adminTokenEnv = options.adminTokenEnv ?? "<admin-token-env>";
    actions.push(
      `loom harness apply-agent-git-service-provisioning-plan --url <harness-url> --tenant ${options.tenant} --admin-token-env ${adminTokenEnv} --dry-run`,
    );
    actions.push(
      `loom harness apply-agent-git-service-provisioning-plan --url <harness-url> --tenant ${options.tenant} --admin-token-env ${adminTokenEnv}`,
    );
    actions.push("loom harness smoke --profile platform-readiness --control-plane-provider agent-git-service");
  } else if (options.missing.length > 0) {
    actions.push("loom harness smoke --profile platform-readiness");
  }
  return actions;
}

function cutoverSmokeCommand(
  options: HarnessCutoverReportCliOptions,
  context: { baseUrl: string; tenant: string; provider?: string },
): { ready: boolean; missingInputs: string[]; args?: string[] } {
  const missingInputs: string[] = [];
  const project = options.project === undefined ? undefined : parseSafeNameFlag(options.project, "--project");
  const isolationTenant = options.isolationTenant === undefined
    ? undefined
    : parseSafeNameFlag(options.isolationTenant, "--isolation-tenant");
  const template = parseProjectTemplateFlag(options.template ?? "vas-lite", "--template");
  const tokenEnv = options.tokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.tokenEnv, "--token-env");
  const viewerTokenEnv = options.viewerTokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.viewerTokenEnv, "--viewer-token-env");
  const adminTokenEnv = options.adminTokenEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.adminTokenEnv, "--admin-token-env");
  const webhookSecretEnv = options.controlPlaneWebhookSecretEnv === undefined
    ? undefined
    : parseEnvNameFlag(options.controlPlaneWebhookSecretEnv, "--control-plane-webhook-secret-env");

  if (!project) missingInputs.push("project");
  if (!isolationTenant) missingInputs.push("isolationTenant");
  if (!tokenEnv) missingInputs.push("tokenEnv");
  if (!viewerTokenEnv) missingInputs.push("viewerTokenEnv");
  if (!adminTokenEnv) missingInputs.push("adminTokenEnv");
  if (!webhookSecretEnv) missingInputs.push("controlPlaneWebhookSecretEnv");
  if (missingInputs.length) return { ready: false, missingInputs };

  const args = [
    "loom",
    "harness",
    "smoke",
    "--url",
    context.baseUrl,
    "--tenant",
    context.tenant,
    "--project",
    project as string,
    "--template",
    template,
    "--token-env",
    tokenEnv as string,
    "--viewer-token-env",
    viewerTokenEnv as string,
    "--admin-token-env",
    adminTokenEnv as string,
    "--isolation-tenant",
    isolationTenant as string,
    "--profile",
    "platform-readiness",
  ];
  if (context.provider) {
    args.push("--control-plane-provider", context.provider);
  }
  args.push("--control-plane-webhook-secret-env", webhookSecretEnv as string);
  args.push("--report", "reports/smoke.json");
  return { ready: true, missingInputs: [], args };
}

function parseEnvNameFlag(value: string, flag: string): string {
  const name = value.trim();
  if (/^[A-Za-z_][A-Za-z0-9_]*$/.test(name)) return name;
  console.error(`${flag} must be an environment variable name`);
  process.exit(2);
}

function stringsOnly(values: unknown[]): string[] {
  return values.filter((value): value is string => typeof value === "string");
}

function harnessApiUrl(baseUrl: string, path: string): string {
  const url = new URL(baseUrl);
  url.pathname = `${url.pathname.replace(/\/$/, "")}${path}`;
  url.search = "";
  url.hash = "";
  return url.toString();
}

function agentGitServiceProvisionCliBody(options: HarnessAgentGitServiceProvisionCliOptions): Record<string, unknown> {
  const identityRole = options.identityRole === undefined ? undefined : parseTenantRoleFlag(options.identityRole, "--identity-role");
  if (options.identityActor !== undefined && identityRole === undefined) {
    throw new Error("--identity-actor requires --identity-role.");
  }
  return compactObject({
    repo: options.repo,
    permission: options.permission === undefined ? undefined : parseAgentGitServicePermissionFlag(options.permission, "--permission"),
    agentPrefixLogin: options.agentPrefixLogin === undefined ? undefined : parseSafeNameFlag(options.agentPrefixLogin, "--agent-prefix-login"),
    defaultRepoName: options.defaultRepoName === undefined ? undefined : parseSafeNameFlag(options.defaultRepoName, "--default-repo-name"),
    tokenEnvName: options.tokenEnvName,
    controlPlaneIdentity: identityRole === undefined
      ? undefined
      : compactObject({
          actor: options.identityActor,
          role: identityRole,
        }),
    storeAgentToken: options.storeAgentToken ? true : undefined,
    force: options.force ? true : undefined,
    clientId: options.clientId,
  });
}

function agentGitServiceProvisioningPlanApplyCliBody(options: HarnessAgentGitServiceProvisioningPlanApplyCliOptions): Record<string, unknown> {
  return compactObject({
    projects: options.projects === undefined ? undefined : parseSafeNameCsvFlag(options.projects, "--projects"),
    dryRun: options.dryRun ? true : undefined,
    eligibleOnly: options.eligibleOnly ? true : undefined,
    clientId: options.clientId,
  });
}

function parseAgentGitServicePermissionFlag(value: string, flag: string): "read" | "write" | "admin" {
  if (value === "read" || value === "write" || value === "admin") return value;
  console.error(`${flag} must be one of: read, write, admin.`);
  process.exit(2);
}

function parseTenantRoleFlag(value: string, flag: string): "viewer" | "developer" | "admin" {
  if (value === "viewer" || value === "developer" || value === "admin") return value;
  console.error(`${flag} must be one of: viewer, developer, admin.`);
  process.exit(2);
}

function smokeToken(options: HarnessSmokeCliOptions): string | undefined {
  return smokeTokenValue(options.token, options.tokenEnv, "--token-env");
}

function smokeViewerToken(options: HarnessSmokeCliOptions): string | undefined {
  return smokeTokenValue(options.viewerToken, options.viewerTokenEnv, "--viewer-token-env");
}

function smokeAdminToken(options: HarnessSmokeCliOptions): string | undefined {
  return smokeTokenValue(options.adminToken, options.adminTokenEnv, "--admin-token-env");
}

function smokeControlPlaneWebhookSecret(options: HarnessSmokeCliOptions): string | undefined {
  const envName = options.controlPlaneWebhookSecretEnv ?? options.giteaWebhookSecretEnv;
  if (!envName) return undefined;
  const flag = options.controlPlaneWebhookSecretEnv ? "--control-plane-webhook-secret-env" : "--gitea-webhook-secret-env";
  return smokeTokenValue(undefined, envName, flag);
}

function smokeTokenValue(token: string | undefined, tokenEnv: string | undefined, tokenEnvFlag: string): string | undefined {
  return cliTokenValue(token, tokenEnv, tokenEnvFlag);
}

function cliTokenValue(token: string | undefined, tokenEnv: string | undefined, tokenEnvFlag: string): string | undefined {
  if (tokenEnv) {
    if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(tokenEnv)) {
      throw new Error(`${tokenEnvFlag} must be an environment variable name`);
    }
    const value = process.env[tokenEnv];
    if (!value) throw new Error(`${tokenEnvFlag} ${tokenEnv} is not set`);
    return value;
  }
  return token;
}

function smokeHeaders(token: string | undefined): Record<string, string> {
  return token ? { authorization: `Bearer ${token}` } : {};
}

function hmacSha256(secret: string, body: string): string {
  return createHmac("sha256", secret).update(body).digest("hex");
}

async function smokeJson(
  url: string,
  init: RequestInit,
  expectedStatuses: number[],
  label: string,
): Promise<{ status: number; body: unknown }> {
  const response = await fetch(url, init);
  const text = await response.text();
  const body = text ? parseJsonResponse(text, label) : {};
  if (!expectedStatuses.includes(response.status)) {
    throw new Error(`${label} failed with ${response.status}: ${boundedErrorText(text)}`);
  }
  return { status: response.status, body };
}

async function smokeText(
  url: string,
  init: RequestInit,
  expectedStatuses: number[],
  label: string,
): Promise<{ status: number; text: string }> {
  const response = await fetch(url, init);
  const text = await response.text();
  if (!expectedStatuses.includes(response.status)) {
    throw new Error(`${label} failed with ${response.status}: ${boundedErrorText(text)}`);
  }
  return { status: response.status, text };
}

function parseJsonResponse(text: string, label: string): unknown {
  try {
    return JSON.parse(text);
  } catch {
    throw new Error(`${label} returned non-JSON response: ${boundedErrorText(text)}`);
  }
}

function stringFieldFromResponse(value: unknown, field: string, label: string): string {
  if (isRecord(value) && typeof value[field] === "string") return value[field];
  throw new Error(`${label} did not include ${field}`);
}

function optionalStringFieldFromResponse(value: unknown, field: string): string | undefined {
  if (isRecord(value) && typeof value[field] === "string") return value[field];
  return undefined;
}

function numberFieldFromResponse(value: unknown, field: string, label: string): number {
  if (isRecord(value) && typeof value[field] === "number") return value[field];
  throw new Error(`${label} did not include ${field}`);
}

function booleanFieldFromResponse(value: unknown, field: string, label: string): boolean {
  if (isRecord(value) && typeof value[field] === "boolean") return value[field];
  throw new Error(`${label} did not include ${field}`);
}

function arrayFieldFromResponse(value: unknown, field: string, label: string): unknown[] {
  if (isRecord(value) && Array.isArray(value[field])) return value[field];
  throw new Error(`${label} did not include ${field}`);
}

function recordFieldFromResponse(value: unknown, field: string, label: string): Record<string, unknown> {
  if (isRecord(value) && isRecord(value[field])) return value[field];
  throw new Error(`${label} did not include ${field}`);
}

function workspaceContextKindFromResponse(value: unknown): string {
  if (!isRecord(value) || value.route !== "project") {
    throw new Error("smoke workspace context did not describe the project route");
  }
  const executor = value.executor;
  if (isRecord(executor) && typeof executor.kind === "string") return executor.kind;
  throw new Error("smoke workspace context did not include executor.kind");
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function normalizeHttpBaseUrl(value: string, flag: string): string {
  try {
    const url = new URL(value);
    if (url.protocol !== "http:" && url.protocol !== "https:") throw new Error("bad protocol");
    url.pathname = url.pathname.replace(/\/+$/, "");
    url.search = "";
    url.hash = "";
    return url.toString().replace(/\/+$/, "");
  } catch {
    console.error(`${flag} must be an http or https URL.`);
    process.exit(2);
  }
}

function parseProjectTemplateFlag(value: string, flag: string): ProjectTemplateName {
  if (value === "empty" || value === "vas-lite") return value;
  console.error(`${flag} must be one of: empty, vas-lite.`);
  process.exit(2);
}

function parseServeProfileFlag(value: string | undefined): HarnessServeProfileName | undefined {
  return parseOnlineProfileFlag(value, "--profile");
}

function parseSmokeProfileFlag(value: string | undefined): HarnessSmokeProfileName | undefined {
  return parseOnlineProfileFlag(value, "--profile");
}

function parseOnlineProfileFlag(value: string | undefined, flag: string): HarnessOnlineProfileName | undefined {
  if (value === undefined || value === "") return undefined;
  if (value === "online-sandbox" || value === "platform-readiness") return value;
  console.error(`${flag} must be one of: online-sandbox, platform-readiness.`);
  process.exit(2);
}

function parseControlPlaneProviderFlag(value: string, flag: string): ControlPlaneProviderName {
  const provider = value.trim();
  if (isServeControlPlaneProvider(provider)) return provider;
  const supported = SERVE_CONTROL_PLANE_PROVIDERS.join(", ");
  const catalogEntry = controlPlaneProviderCatalogEntry(provider);
  if (catalogEntry) {
    console.error(
      `${flag} serve-enabled providers: ${supported}. ${provider} is a ${catalogEntry.status} control-plane provider blocked by: ${catalogEntry.blockedBy.join(", ")}.`,
    );
  } else {
    console.error(`${flag} serve-enabled providers: ${supported}. Unknown control-plane provider: ${provider}.`);
  }
  process.exit(2);
}

function parseOperatorCockpitQueueBackendFlag(value: string | undefined, flag: string): OperatorCockpitQueueBackendName {
  const backend = (value ?? "filesystem").trim();
  if (backend === "filesystem" || backend === "agent-git-service") return backend;
  console.error(`${flag} must be one of: filesystem, agent-git-service.`);
  process.exit(2);
}

function isServeControlPlaneProvider(value: string): value is ControlPlaneProviderName {
  return (SERVE_CONTROL_PLANE_PROVIDERS as readonly string[]).includes(value);
}

function backupMigrationTargetProviderFor(sourceProvider: ControlPlaneProviderName): ControlPlaneProviderName {
  return SERVE_CONTROL_PLANE_PROVIDERS.find((provider) => provider !== sourceProvider) ?? sourceProvider;
}

function parseSafeNameFlag(value: string, flag: string): string {
  const name = value.trim();
  if (/^[A-Za-z0-9][A-Za-z0-9_.-]{0,62}$/.test(name)) return name;
  console.error(`${flag} must match [A-Za-z0-9][A-Za-z0-9_.-]{0,62}`);
  process.exit(2);
}

function parseSafeNameCsvFlag(value: string, flag: string): string[] {
  const names = value.split(",").map((item) => item.trim()).filter(Boolean);
  if (!names.length) {
    console.error(`${flag} must include at least one project name.`);
    process.exit(2);
  }
  return names.map((name) => parseSafeNameFlag(name, flag));
}

function boundedErrorText(value: string): string {
  const text = value.replace(/\s+/g, " ").trim();
  if (!text) return "<empty>";
  return text.length > 300 ? `${text.slice(0, 297)}...` : text;
}

function smokeCheckError(code: string, message: string, details: Record<string, unknown>): Error {
  return new Error(`${code}: ${message}; details=${JSON.stringify(details)}`);
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function collect(value: string, previous: string[]): string[] {
  previous.push(value);
  return previous;
}

function allowedHttpTools(extraTools: string[], allowShell: boolean): string[] {
  const tools = new Set(["file.read", "file.write", "git.diff", "git.commit", "verify.run", ...extraTools]);
  if (allowShell) tools.add("shell.exec");
  return [...tools];
}

function serveFlagValidationDoctorCheck(options: HarnessServeCliOptions): HarnessDoctorCheck {
  const issues = serveFlagValidationIssues(options);
  return compactDoctorCheck({
    required: true,
    ok: issues.length === 0,
    invalidFlags: issues.length ? issues : undefined,
  });
}

interface ServeFlagValidationIssue {
  flag: string;
  message: string;
}

function requireServeFlagValidation(options: HarnessServeCliOptions): void {
  const [issue] = serveFlagValidationIssues(options);
  if (!issue) return;
  console.error(issue.message);
  process.exit(2);
}

function serveFlagValidationIssues(options: HarnessServeCliOptions): ServeFlagValidationIssue[] {
  const issues = [
    portFlagIssue(options.port),
    positiveIntFlagIssue(options.workspaceCommandTimeoutMs, "--workspace-command-timeout-ms"),
    positiveIntFlagIssue(options.maxWorkspaceSessions, "--max-workspace-sessions"),
    options.maxTenantWorkspaceSessions === undefined
      ? undefined
      : positiveIntFlagIssue(options.maxTenantWorkspaceSessions, "--max-tenant-workspace-sessions"),
    options.maxTenantActiveRuns === undefined
      ? undefined
      : positiveIntFlagIssue(options.maxTenantActiveRuns, "--max-tenant-active-runs"),
    positiveIntFlagIssue(options.workspaceSessionIdleTimeoutMs, "--workspace-session-idle-timeout-ms"),
    positiveIntFlagIssue(options.runLeaseTtlMs, "--run-lease-ttl-ms"),
    operatorCockpitQueueBackendFlagIssue(options.operatorCockpitQueueBackend, "--operator-cockpit-queue-backend"),
    operatorCockpitQueueAgentGitServiceRepoFlagIssue(options.operatorCockpitQueueAgsRepo),
    operatorCockpitQueueAgentGitServicePathFlagIssue(options.operatorCockpitQueueAgsPath),
  ];
  if (options.executor === "docker" || options.executor === "coder") {
    issues.push(
      options.executorCpus === undefined ? undefined : positiveNumberFlagIssue(options.executorCpus, "--executor-cpus"),
      options.executorPidsLimit === undefined ? undefined : positiveIntFlagIssue(options.executorPidsLimit, "--executor-pids-limit"),
    );
  }
  return issues.filter((issue): issue is ServeFlagValidationIssue => Boolean(issue));
}

function portFlagIssue(value: string): ServeFlagValidationIssue | undefined {
  const parsed = Number(value);
  if (Number.isInteger(parsed) && parsed >= 0 && parsed <= 65_535) return undefined;
  return { flag: "--port", message: "--port must be an integer between 0 and 65535" };
}

function positiveIntFlagIssue(value: string, flag: string): ServeFlagValidationIssue | undefined {
  const parsed = Number(value);
  if (Number.isInteger(parsed) && parsed >= 1) return undefined;
  return { flag, message: `${flag} must be a positive integer.` };
}

function positiveNumberFlagIssue(value: string, flag: string): ServeFlagValidationIssue | undefined {
  const parsed = Number(value);
  if (Number.isFinite(parsed) && parsed > 0) return undefined;
  return { flag, message: `${flag} must be a positive number.` };
}

function operatorCockpitQueueBackendFlagIssue(value: string | undefined, flag: string): ServeFlagValidationIssue | undefined {
  const backend = (value ?? "filesystem").trim();
  if (backend === "filesystem" || backend === "agent-git-service") return undefined;
  return { flag, message: `${flag} must be one of: filesystem, agent-git-service.` };
}

function operatorCockpitQueueAgentGitServiceRepoFlagIssue(value: string | undefined): ServeFlagValidationIssue | undefined {
  if (value === undefined) return undefined;
  try {
    normalizeAgentGitServiceOperatorCockpitQueueRepo(value);
    return undefined;
  } catch {
    return {
      flag: "--operator-cockpit-queue-ags-repo",
      message: "--operator-cockpit-queue-ags-repo must be a safe owner/repo value.",
    };
  }
}

function operatorCockpitQueueAgentGitServicePathFlagIssue(value: string | undefined): ServeFlagValidationIssue | undefined {
  if (value === undefined) return undefined;
  try {
    normalizeAgentGitServiceOperatorCockpitQueuePath(value);
    return undefined;
  } catch {
    return {
      flag: "--operator-cockpit-queue-ags-path",
      message: "--operator-cockpit-queue-ags-path must be a safe relative slash-separated path.",
    };
  }
}

interface ServeExecutorSafetyOptions {
  executor: string;
  workspaceRoot: string;
  host: string;
  allowShell: boolean;
  allowTool: string[];
  allowUnsafeLocalExecutor: boolean;
  tenantToken?: string[];
  tenantKey?: string[];
  tenantKeyEnv?: string[];
}

function requireSafeServeExecutor(options: ServeExecutorSafetyOptions): void {
  const reasons = unsafeLocalExecutorReasons(options);
  if (!reasons.length) return;
  console.error(
    `--executor local is not isolated for shared HTTP use (${reasons.join("; ")}). ` +
      "Use --executor docker, --executor coder, or pass --allow-unsafe-local-executor for single-user local development.",
  );
  process.exit(2);
}

function unsafeLocalExecutorReasons(options: ServeExecutorSafetyOptions, policyTenantAuthConfigured?: boolean): string[] {
  if (options.executor !== "local" || options.allowUnsafeLocalExecutor) return [];
  const hasPolicyTenantAuth = policyTenantAuthConfigured ??
    Object.values(readPolicyTenantApiKeysForDoctor(options.workspaceRoot)).some((keys) => keys.length > 0);
  return [
    !isLoopbackHost(options.host) ? `host ${options.host} is not loopback` : undefined,
    options.allowShell || options.allowTool.includes("shell.exec") ? "shell.exec is allowed" : undefined,
    options.tenantToken?.length || options.tenantKey?.length || options.tenantKeyEnv?.length || hasPolicyTenantAuth
      ? "tenant authentication is configured"
      : undefined,
  ].filter((reason): reason is string => Boolean(reason));
}

function executorConfigurationDoctorCheck(options: Pick<ExecutorCliOptions, "executor" | "executorImage" | "executorWorkspace">): HarnessDoctorCheck {
  const issues = executorConfigurationIssues(options);
  return compactDoctorCheck({
    required: true,
    ok: issues.length === 0,
    executorKind: options.executor,
    imageConfigured: options.executor === "docker" ? Boolean(options.executorImage?.trim()) : undefined,
    workspaceConfigured: options.executor === "coder" ? Boolean(options.executorWorkspace?.trim()) : undefined,
    missingFlags: issues.length ? issues.map((issue) => issue.flag) : undefined,
  });
}

interface ExecutorConfigurationIssue {
  flag: string;
  message: string;
}

function executorConfigurationIssues(options: Pick<ExecutorCliOptions, "executor" | "executorImage" | "executorWorkspace">): ExecutorConfigurationIssue[] {
  if (options.executor === "local") return [];
  if (options.executor === "docker") {
    return options.executorImage?.trim()
      ? []
      : [{ flag: "--executor-image", message: "--executor-image is required when --executor docker is used." }];
  }
  if (options.executor === "coder") {
    return options.executorWorkspace?.trim()
      ? []
      : [{ flag: "--executor-workspace", message: "--executor-workspace is required when --executor coder is used." }];
  }
  return [{ flag: "--executor", message: "--executor must be one of: local, docker, coder" }];
}

function requireExecutorConfiguration(options: Pick<ExecutorCliOptions, "executor" | "executorImage" | "executorWorkspace">): void {
  const [issue] = executorConfigurationIssues(options);
  if (!issue) return;
  console.error(issue.message);
  process.exit(2);
}

function isLoopbackHost(host: string): boolean {
  const value = host.trim().toLowerCase();
  return value === "localhost" || value === "::1" || value === "[::1]" || /^127(?:\.\d{1,3}){3}$/.test(value);
}

function parseTenantTokens(values: string[]): Record<string, string> {
  const tokens: Record<string, string> = {};
  for (const value of values) {
    const index = value.indexOf("=");
    if (index <= 0 || index === value.length - 1) {
      console.error("--tenant-token must be formatted as tenant=token");
      process.exit(2);
    }
    tokens[parseTenantFlagName(value.slice(0, index))] = value.slice(index + 1);
  }
  return tokens;
}

function parseTenantApiKeys(values: string[]): Record<string, TenantApiKey[]> {
  const keys: Record<string, TenantApiKey[]> = {};
  for (const value of values) {
    const tenantSeparator = value.indexOf("=");
    if (tenantSeparator <= 0 || tenantSeparator === value.length - 1) {
      console.error("--tenant-key must be formatted as tenant=token:actor:role");
      process.exit(2);
    }
    const tenant = parseTenantFlagName(value.slice(0, tenantSeparator));
    const spec = value.slice(tenantSeparator + 1);
    const parts = spec.split(":");
    if (parts.length !== 3 || parts.some((part) => !part.trim())) {
      console.error("--tenant-key must be formatted as tenant=token:actor:role");
      process.exit(2);
    }
    const [token, actor, role] = parts;
    if (role !== "admin" && role !== "developer" && role !== "viewer") {
      console.error("--tenant-key role must be one of: admin, developer, viewer");
      process.exit(2);
    }
    keys[tenant] = [...(keys[tenant] ?? []), { token, actor, role }];
  }
  return keys;
}

function parseTenantApiKeysFromServeOptions(options: Pick<HarnessServeCliOptions, "tenantKey" | "tenantKeyEnv">): Record<string, TenantApiKey[]> {
  return mergeTenantApiKeysForDoctor(
    parseTenantApiKeys(options.tenantKey ?? []),
    parseTenantApiKeyEnvs(options.tenantKeyEnv ?? []),
  );
}

function parseTenantApiKeyEnvs(values: string[]): Record<string, TenantApiKey[]> {
  const keys: Record<string, TenantApiKey[]> = {};
  for (const value of values) {
    const tenantSeparator = value.indexOf("=");
    if (tenantSeparator <= 0 || tenantSeparator === value.length - 1) {
      console.error("--tenant-key-env must be formatted as tenant=env:actor:role");
      process.exit(2);
    }
    const tenant = parseTenantFlagName(value.slice(0, tenantSeparator));
    const spec = value.slice(tenantSeparator + 1);
    const parts = spec.split(":");
    if (parts.length !== 3 || parts.some((part) => !part.trim())) {
      console.error("--tenant-key-env must be formatted as tenant=env:actor:role");
      process.exit(2);
    }
    const [envName, actor, role] = parts;
    if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(envName)) {
      console.error("--tenant-key-env env must be an environment variable name");
      process.exit(2);
    }
    if (role !== "admin" && role !== "developer" && role !== "viewer") {
      console.error("--tenant-key-env role must be one of: admin, developer, viewer");
      process.exit(2);
    }
    const token = process.env[envName];
    if (token?.trim()) {
      keys[tenant] = [...(keys[tenant] ?? []), { token, actor, role }];
    }
  }
  return keys;
}

function parseTenantModelKeyEnvs(values: string[]): Record<string, string> {
  const envs: Record<string, string> = {};
  for (const value of values) {
    const index = value.indexOf("=");
    if (index <= 0 || index === value.length - 1) {
      console.error("--tenant-model-key must be formatted as tenant=env");
      process.exit(2);
    }
    const envName = value.slice(index + 1);
    if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(envName)) {
      console.error("--tenant-model-key env must be an environment variable name");
      process.exit(2);
    }
    envs[parseTenantFlagName(value.slice(0, index))] = envName;
  }
  return envs;
}

function parseTenantGiteaTokenEnvs(values: string[]): Record<string, string> {
  const envs: Record<string, string> = {};
  for (const value of values) {
    const index = value.indexOf("=");
    if (index <= 0 || index === value.length - 1) {
      console.error("--tenant-gitea-token-env must be formatted as tenant=env");
      process.exit(2);
    }
    const envName = value.slice(index + 1);
    if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(envName)) {
      console.error("--tenant-gitea-token-env env must be an environment variable name");
      process.exit(2);
    }
    envs[parseTenantFlagName(value.slice(0, index))] = envName;
  }
  return envs;
}

function parseTenantFlagName(value: string): string {
  try {
    return assertTenantName(value);
  } catch (error) {
    console.error(error instanceof Error ? error.message : "tenant name is not safe");
    process.exit(2);
  }
}

function parseProjectFlagName(value: string, flag: string): string {
  const project = value.trim();
  if (!isProjectDirectoryNameForDoctor(project)) {
    console.error(`${flag} must contain only letters, numbers, dot, underscore, or dash, and must not be reserved.`);
    process.exit(2);
  }
  return project;
}

function parseModelNameFlag(value: string, flag: string): string {
  const model = value.trim();
  if (!model || model.includes("\0") || model.length > 200) {
    console.error(`${flag} must be a non-empty model name.`);
    process.exit(2);
  }
  return model;
}

function parseModelProtocolFlag(value: string, flag: string): ModelAgentProtocol {
  if (value === "json" || value === "tool-call") return value;
  console.error(`${flag} must be one of: json, tool-call.`);
  process.exit(2);
}

function parsePositiveIntFlag(value: string, flag: string): number {
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < 1) {
    console.error(`${flag} must be a positive integer.`);
    process.exit(2);
  }
  return parsed;
}

function parsePositiveNumberFlag(value: string, flag: string): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    console.error(`${flag} must be a positive number.`);
    process.exit(2);
  }
  return parsed;
}

function parseHarnessRunSourceOptions(options: { repo?: string; branch?: string; baseBranch: string; issue?: string }): { repo?: string; branch?: string; baseBranch: string; issue?: string } {
  return {
    repo: optionalCliRepo(options.repo),
    branch: options.branch ? cliGitRef(options.branch, "--branch") : undefined,
    baseBranch: cliGitRef(options.baseBranch, "--base-branch"),
    issue: options.issue ? cliIssueRef(options.issue, "--issue") : undefined,
  };
}

function optionalCliRepo(value: string | undefined): string | undefined {
  const repo = value?.trim();
  if (!repo) return undefined;
  if (repo.includes("\0") || repo.startsWith("-")) {
    console.error("--repo is not safe.");
    process.exit(2);
  }
  return repo;
}

function cliGitRef(value: string, flag: string): string {
  try {
    return safeGitRef(value, flag);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(message);
    process.exit(2);
  }
}

function cliIssueRef(value: string, flag: string): string {
  const issue = value.trim();
  try {
    parseGiteaIssueRef(issue);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(`${flag} ${message}`);
    process.exit(2);
  }
  return issue;
}

function parseAgentGitServiceStagingIssueFlag(value: string): ReturnType<typeof parseAgentGitServiceIssueRef> {
  const issue = value.trim();
  try {
    return parseAgentGitServiceIssueRef(issue);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(`--issue ${message}`);
    process.exit(2);
  }
}

function parseAgentGitServiceStagingRepoFlag(
  value: string,
  flag: string,
): ReturnType<typeof parseAgentGitServiceRepoRef> {
  const repo = value.trim();
  try {
    return parseAgentGitServiceRepoRef(repo);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(`${flag} ${message}`);
    process.exit(2);
  }
}

function parseAgentGitServiceWikiPageFlag(value: string): string {
  const page = value.trim();
  if (!page || page.includes("\0") || page.startsWith("/") || page.split("/").some((part) => part === "." || part === "..")) {
    console.error("--wiki-page must be a non-empty relative wiki page path.");
    process.exit(2);
  }
  return page;
}

function parseAgentGitServiceWorkspaceIdFlag(value: string): string {
  const workspaceId = value.trim();
  if (!workspaceId || workspaceId.includes("\0") || workspaceId.length > 200) {
    console.error("--workspace-id must be a non-empty AGS workspace id.");
    process.exit(2);
  }
  return workspaceId;
}

function parseAgentGitServiceWikiNoteFlag(value: string): string {
  const note = value.trim();
  if (!note || note.includes("\0") || note.length > 1000) {
    console.error("--wiki-note must be non-empty text up to 1000 characters.");
    process.exit(2);
  }
  return note;
}

interface IssueReporterOptions {
  controlPlaneProvider?: ControlPlaneProviderName;
  controlPlanePr?: boolean;
  controlPlaneMerge?: boolean;
  controlPlaneComment?: boolean;
  controlPlaneCommentSync?: boolean;
  giteaComment: boolean;
  giteaCommentSync?: boolean;
  giteaPr?: boolean;
  giteaMerge?: boolean;
  giteaUrl: string;
  giteaTokenEnv: string;
  tenantGiteaTokenEnvs?: Record<string, string>;
}

interface ControlPlaneEnvValidationOptions extends IssueReporterOptions {
  controlPlaneWebhookSecretEnv?: string;
  giteaWebhookSecretEnv?: string;
}

interface PullRequestReporterResult {
  index?: number;
  url?: string;
}

type ControlPlaneReporterFeature = "comment" | "comment-sync" | "pr" | "merge";

function validateControlPlaneTokenEnvs(options: IssueReporterOptions, flag: string): void {
  for (const [tenant, envName] of missingTenantGiteaTokenEnvEntries(options)) {
    console.error(`${flag} requires tenant ${tenant} ${controlPlaneTokenLabel(options)} env ${envName} to be set.`);
    process.exit(2);
  }
  if (!Object.keys(options.tenantGiteaTokenEnvs ?? {}).length && missingSharedGiteaTokenEnvName(options)) {
    console.error(`${controlPlaneTokenEnvFlag(options)} ${options.giteaTokenEnv} is required when ${flag} is used.`);
    process.exit(2);
  }
}

function controlPlaneReporterFlag(options: IssueReporterOptions, feature: ControlPlaneReporterFeature): string {
  switch (feature) {
    case "comment":
      return options.controlPlaneComment ? "--control-plane-comment" : "--gitea-comment";
    case "comment-sync":
      return options.controlPlaneCommentSync ? "--control-plane-comment-sync" : "--gitea-comment-sync";
    case "pr":
      return options.controlPlanePr ? "--control-plane-pr" : "--gitea-pr";
    case "merge":
      return options.controlPlaneMerge ? "--control-plane-merge" : "--gitea-merge";
  }
}

function controlPlaneTokenEnvFlag(options: IssueReporterOptions): string {
  return usesProviderNeutralControlPlaneTokenWording(options) ? "--control-plane-token-env" : "--gitea-token-env";
}

function controlPlaneTokenLabel(options: IssueReporterOptions): string {
  return usesProviderNeutralControlPlaneTokenWording(options) ? "control-plane token" : "Gitea token";
}

function usesProviderNeutralControlPlaneTokenWording(options: IssueReporterOptions): boolean {
  return Boolean(
    options.controlPlaneProvider === "agent-git-service" ||
    options.controlPlanePr ||
    options.controlPlaneMerge ||
    options.controlPlaneComment ||
    options.controlPlaneCommentSync,
  );
}

function controlPlaneEnvValidationDoctorCheck(options: ControlPlaneEnvValidationOptions): HarnessDoctorCheck {
  const enabledFlags = controlPlaneEnvValidationFlags(options);
  const missingEnvNames = controlPlaneMissingEnvNames(options);
  const tokenEvidence = controlPlaneTokenEnvEvidence(options);
  return compactDoctorCheck({
    required: true,
    ok: missingEnvNames.length === 0,
    enabledFlags: enabledFlags.length ? enabledFlags : undefined,
    tokenMode: missingEnvNames.length === 0 ? tokenEvidence.mode : undefined,
    tokenEnv: missingEnvNames.length === 0 ? tokenEvidence.tokenEnv : undefined,
    tenantTokenEnvNames: missingEnvNames.length === 0 ? tokenEvidence.tenantTokenEnvNames : undefined,
    missingEnvNames: missingEnvNames.length ? missingEnvNames : undefined,
  });
}

function controlPlaneTokenEnvEvidence(options: IssueReporterOptions): {
  mode?: "shared" | "tenant-scoped";
  tokenEnv?: string;
  tenantTokenEnvNames?: string[];
} {
  if (!requiresGiteaToken(options)) return {};
  const tenantTokenEnvNames = Object.values(options.tenantGiteaTokenEnvs ?? {}).sort((a, b) => a.localeCompare(b));
  if (tenantTokenEnvNames.length > 0) {
    return {
      mode: "tenant-scoped",
      tenantTokenEnvNames,
    };
  }
  return {
    mode: "shared",
    tokenEnv: options.giteaTokenEnv,
  };
}

function controlPlaneEnvValidationFlags(options: ControlPlaneEnvValidationOptions): string[] {
  return [
    options.controlPlanePr ? "--control-plane-pr" : options.giteaPr ? "--gitea-pr" : undefined,
    options.controlPlaneComment ? "--control-plane-comment" : options.giteaComment ? "--gitea-comment" : undefined,
    options.controlPlaneCommentSync ? "--control-plane-comment-sync" : options.giteaCommentSync ? "--gitea-comment-sync" : undefined,
    options.controlPlaneMerge ? "--control-plane-merge" : options.giteaMerge ? "--gitea-merge" : undefined,
    options.controlPlaneWebhookSecretEnv ? "--control-plane-webhook-secret-env" : options.giteaWebhookSecretEnv ? "--gitea-webhook-secret-env" : undefined,
  ].filter((flag): flag is string => Boolean(flag));
}

function controlPlaneMissingEnvNames(options: ControlPlaneEnvValidationOptions): string[] {
  const missing = [
    ...missingGiteaTokenEnvNames(options),
    missingGiteaWebhookSecretEnvName(options.giteaWebhookSecretEnv),
  ].filter((envName): envName is string => Boolean(envName));
  return [...new Set(missing)];
}

function missingGiteaTokenEnvNames(options: IssueReporterOptions): string[] {
  if (!requiresGiteaToken(options)) return [];
  const tenantMissing = missingTenantGiteaTokenEnvEntries(options).map(([, envName]) => envName);
  if (tenantMissing.length) return tenantMissing;
  const sharedMissing = missingSharedGiteaTokenEnvName(options);
  return sharedMissing ? [sharedMissing] : [];
}

function requiresGiteaToken(options: IssueReporterOptions): boolean {
  return Boolean(options.giteaPr || options.giteaComment || options.giteaCommentSync || options.giteaMerge);
}

function missingTenantGiteaTokenEnvEntries(options: IssueReporterOptions): Array<[string, string]> {
  return Object.entries(options.tenantGiteaTokenEnvs ?? {}).filter(([, envName]) => !process.env[envName]);
}

function missingSharedGiteaTokenEnvName(options: IssueReporterOptions): string | undefined {
  if (Object.keys(options.tenantGiteaTokenEnvs ?? {}).length > 0) return undefined;
  return process.env[options.giteaTokenEnv] ? undefined : options.giteaTokenEnv;
}

function missingGiteaWebhookSecretEnvName(envName?: string): string | undefined {
  if (!envName) return undefined;
  return process.env[envName] ? undefined : envName;
}

function controlPlaneAgentIdentityFromGiteaTokens(options: IssueReporterOptions): ControlPlaneAgentIdentityConfig | undefined {
  const tenants = Object.keys(options.tenantGiteaTokenEnvs ?? {}).sort((a, b) => a.localeCompare(b));
  if (tenants.length > 0) return { mode: "tenant-scoped", tenants };
  if (process.env[options.giteaTokenEnv]) return { mode: "shared" };
  return undefined;
}

function giteaTokenForTenant(options: IssueReporterOptions, tenant: string | undefined, flag: string): string {
  const tenantEnv = tenant ? options.tenantGiteaTokenEnvs?.[tenant] : undefined;
  const envName = tenantEnv ?? options.giteaTokenEnv;
  const token = process.env[envName];
  if (!token) {
    throw new Error(`${flag} requires ${tenantEnv ? `tenant ${tenant} ${controlPlaneTokenLabel(options)} env ${envName}` : `${controlPlaneTokenEnvFlag(options)} ${envName}`} to be set.`);
  }
  return token;
}

function controlPlaneTenantTokensFromEnv(envs: Record<string, string> | undefined): Record<string, string> | undefined {
  const tokens = Object.fromEntries(
    Object.entries(envs ?? {}).flatMap(([tenant, envName]) => {
      const token = process.env[envName];
      return token ? [[tenant, token]] : [];
    }),
  );
  return Object.keys(tokens).length ? tokens : undefined;
}

function issueReporterControlPlaneProvider(options: IssueReporterOptions): ControlPlaneProvider {
  const providerName = options.controlPlaneProvider ?? "gitea-forgejo";
  const provider = controlPlaneProviderAdapter(providerName);
  if (!provider) throw new Error(`unsupported control-plane provider: ${providerName}`);
  return provider;
}

function controlPlaneGitTransportDoctorEvidence(provider: ControlPlaneProviderName, baseUrl: string): { sampleRepo?: string; sampleRemoteUrl?: string } {
  if (!baseUrl.trim()) return {};
  try {
    return {
      sampleRepo: CONTROL_PLANE_GIT_TRANSPORT_SAMPLE_REPO,
      sampleRemoteUrl: serveControlPlaneProviderAdapter(provider).gitRemoteUrl(baseUrl, CONTROL_PLANE_GIT_TRANSPORT_SAMPLE_REPO),
    };
  } catch {
    return { sampleRepo: CONTROL_PLANE_GIT_TRANSPORT_SAMPLE_REPO };
  }
}

function serveControlPlaneProviderAdapter(provider: ControlPlaneProviderName): ControlPlaneProvider {
  const adapter = controlPlaneProviderAdapter(provider);
  if (!adapter) throw new Error(`unsupported control-plane provider: ${provider}`);
  return adapter;
}

function parseIssueRefForControlPlane(options: IssueReporterOptions, issue: string): { owner: string; repo: string; index: number } {
  return (options.controlPlaneProvider ?? "gitea-forgejo") === "agent-git-service"
    ? parseAgentGitServiceIssueRef(issue)
    : parseGiteaIssueRef(issue);
}

function maybeIssueReporter(options: IssueReporterOptions): ((summary: RunSummary) => Promise<void>) | undefined {
  if (!options.giteaComment) return undefined;
  const flag = controlPlaneReporterFlag(options, "comment");
  validateControlPlaneTokenEnvs(options, flag);
  const provider = issueReporterControlPlaneProvider(options);
  return (summary: RunSummary) => {
    if (!summary.metadata?.issue) return Promise.resolve();
    return provider.createIssueComment({
      baseUrl: options.giteaUrl,
      token: giteaTokenForTenant(options, summary.metadata.tenant, flag),
      issue: summary.metadata.issue,
      summary,
    });
  };
}

function maybeIssueCommentReader(options: IssueReporterOptions): ((issue: string, context: IssueCommentReaderContext) => Promise<ControlPlaneIssueComment[]>) | undefined {
  if (!options.giteaCommentSync) return undefined;
  const flag = controlPlaneReporterFlag(options, "comment-sync");
  validateControlPlaneTokenEnvs(options, flag);
  const provider = issueReporterControlPlaneProvider(options);
  return (issue: string, context: IssueCommentReaderContext) => provider.listIssueComments({
    baseUrl: options.giteaUrl,
    token: giteaTokenForTenant(options, context.tenant, flag),
    issue,
    limit: 100,
  });
}

function maybeGiteaWebhookSecret(envName?: string): string | undefined {
  if (!envName) return undefined;
  if (missingGiteaWebhookSecretEnvName(envName)) {
    console.error(`--gitea-webhook-secret-env ${envName} is set but the env var is empty.`);
    process.exit(2);
  }
  return process.env[envName];
}

function maybePullRequestReporter(options: IssueReporterOptions): ((summary: RunSummary) => Promise<PullRequestReporterResult | void>) | undefined {
  if (!options.giteaPr) return undefined;
  const flag = controlPlaneReporterFlag(options, "pr");
  validateControlPlaneTokenEnvs(options, flag);
  const provider = issueReporterControlPlaneProvider(options);
  return async (summary: RunSummary) => {
    if (!summary.metadata?.issue || !summary.metadata.branch) return undefined;
    const issue = parseIssueRefForControlPlane(options, summary.metadata.issue);
    const pullRequest = await provider.createPullRequest({
      baseUrl: options.giteaUrl,
      token: giteaTokenForTenant(options, summary.metadata.tenant, flag),
      repo: `${issue.owner}/${issue.repo}`,
      head: summary.metadata.branch,
      base: prBaseBranch(summary.metadata.baseBranch),
      title: `Loom run ${summary.runId}: ${summary.goal}`,
      body: pullRequestBody(summary),
    });
    return { index: pullRequest.index, url: pullRequest.url };
  };
}

function maybeWorkspacePullRequestReporter(options: IssueReporterOptions): ((request: WorkspacePullRequestRequest) => Promise<PullRequestReporterResult | void>) | undefined {
  if (!options.giteaPr) return undefined;
  const flag = controlPlaneReporterFlag(options, "pr");
  validateControlPlaneTokenEnvs(options, flag);
  const provider = issueReporterControlPlaneProvider(options);
  return async (request: WorkspacePullRequestRequest) => {
    const issue = parseIssueRefForControlPlane(options, request.issue);
    const pullRequest = await provider.createPullRequest({
      baseUrl: options.giteaUrl,
      token: giteaTokenForTenant(options, request.tenant, flag),
      repo: `${issue.owner}/${issue.repo}`,
      head: request.branch,
      base: prBaseBranch(request.baseBranch),
      title: request.title,
      body: request.body || workspacePullRequestBody(request),
    });
    return { index: pullRequest.index, url: pullRequest.url };
  };
}

function maybeMergeReporter(options: IssueReporterOptions): ((summary: RunSummary, note?: string) => Promise<void>) | undefined {
  if (!options.giteaMerge) return undefined;
  const flag = controlPlaneReporterFlag(options, "merge");
  validateControlPlaneTokenEnvs(options, flag);
  const provider = issueReporterControlPlaneProvider(options);
  return async (summary: RunSummary, note?: string) => {
    if (!summary.metadata?.issue || !summary.metadata.pullRequestIndex) return;
    const issue = parseIssueRefForControlPlane(options, summary.metadata.issue);
    await provider.mergePullRequest({
      baseUrl: options.giteaUrl,
      token: giteaTokenForTenant(options, summary.metadata.tenant, flag),
      repo: `${issue.owner}/${issue.repo}`,
      index: summary.metadata.pullRequestIndex,
      method: "merge",
      title: `Merge Loom run ${summary.runId}`,
      message: note ?? `Approved Loom run ${summary.runId}.`,
    });
  };
}

async function finalizeSummary(
  summary: RunSummary,
  pullRequestReporter: ((summary: RunSummary) => Promise<PullRequestReporterResult | void>) | undefined,
  issueReporter: ((summary: RunSummary) => Promise<void>) | undefined,
): Promise<RunSummary> {
  const withPullRequest = await reportPullRequest(pullRequestReporter, summary);
  await writeSummary(withPullRequest);
  return reportIssue(issueReporter, withPullRequest);
}

async function reportPullRequest(
  reporter: ((summary: RunSummary) => Promise<PullRequestReporterResult | void>) | undefined,
  summary: RunSummary,
): Promise<RunSummary> {
  if (!reporter) return summary;
  if (summary.status !== "passed" && summary.status !== "review_required" && summary.status !== "deployment_required") return summary;
  try {
    const result = await reporter(summary);
    const withPullRequest = result ? {
      ...summary,
      metadata: {
        ...summary.metadata,
        pullRequestIndex: result.index,
        pullRequestUrl: result.url,
      },
    } : summary;
    return recordExternalEffect(withPullRequest, {
      kind: "pull_request",
      issue: withPullRequest.metadata?.issue,
      issueUrl: withPullRequest.metadata?.issueUrl,
      branch: withPullRequest.metadata?.branch,
      baseBranch: withPullRequest.metadata?.baseBranch,
      pullRequestIndex: withPullRequest.metadata?.pullRequestIndex,
      pullRequestUrl: withPullRequest.metadata?.pullRequestUrl,
      dashboardUrl: withPullRequest.metadata?.dashboardUrl,
      summaryUrl: withPullRequest.metadata?.summaryUrl,
      reviewSummaryUrl: withPullRequest.metadata?.summaryUrl ? runSignalEvidenceUrl(withPullRequest.metadata.summaryUrl, "review-summary") : undefined,
      handoffPackageUrl: withPullRequest.metadata?.summaryUrl ? runSignalEvidenceUrl(withPullRequest.metadata.summaryUrl, "handoff-package") : undefined,
      handoffFollowupsUrl: withPullRequest.metadata?.summaryUrl ? runSignalEvidenceUrl(withPullRequest.metadata.summaryUrl, "handoff-runs") : undefined,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return markRunError(summary, `pull request reporter failed: ${message}`);
  }
}

async function reportIssue(reporter: ((summary: RunSummary) => Promise<void>) | undefined, summary: RunSummary): Promise<RunSummary> {
  if (summary.status === "cancelled" || summary.status === "paused") return summary;
  if (!summary.metadata?.issue || !reporter) return summary;
  try {
    await reporter(summary);
    return recordExternalEffect(summary, {
      kind: "issue_comment",
      issue: summary.metadata.issue,
      issueUrl: summary.metadata.issueUrl,
      dashboardUrl: summary.metadata.dashboardUrl,
      summaryUrl: summary.metadata.summaryUrl,
      reviewSummaryUrl: summary.metadata.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "review-summary") : undefined,
      handoffPackageUrl: summary.metadata.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-package") : undefined,
      handoffFollowupsUrl: summary.metadata.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-runs") : undefined,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return markRunError(summary, `issue reporter failed: ${message}`);
  }
}

async function recordExternalEffect(summary: RunSummary, data: Record<string, unknown>): Promise<RunSummary> {
  const event = await appendRunEvent(summary.runDir, "external_effect", compactObject({
    ...data,
    requester: summary.requester,
  }));
  const observed: RunSummary = { ...summary, eventCount: event.seq };
  await writeSummary(observed);
  return observed;
}

async function markRunError(summary: RunSummary, message: string): Promise<RunSummary> {
  const event = await appendRunEvent(summary.runDir, "error", { message });
  const failed: RunSummary = {
    ...summary,
    status: "error",
    endedAt: new Date().toISOString(),
    eventCount: event.seq,
    error: { message },
  };
  await writeSummary(failed);
  return failed;
}

async function writeSummary(summary: RunSummary): Promise<void> {
  await writeFile(join(summary.runDir, "summary.json"), JSON.stringify(summary, null, 2) + "\n", "utf8");
}

function prBaseBranch(baseBranch?: string): string {
  return (baseBranch ?? "origin/main").replace(/^origin\//, "");
}

function runUrl(publicUrl: string, tenant: string, project: string, runId: string): string {
  const base = publicUrl.replace(/\/+$/, "");
  return `${base}/tenants/${encodeURIComponent(tenant)}/runs/${encodeURIComponent(runId)}?project=${encodeURIComponent(project)}`;
}

function runDashboardUrl(publicUrl: string, tenant: string, project: string, runId: string): string {
  const base = publicUrl.replace(/\/+$/, "");
  const params = new URLSearchParams({ tenant, project, runId });
  return `${base}/?${params.toString()}`;
}

function pullRequestBody(summary: RunSummary): string {
  const requester = formatRunRequesterSummary(summary.requester);
  const lines = [
    `Created by Loom harness run ${summary.runId}.`,
    "",
    `Status: ${summary.status}`,
  ];
  if (requester) lines.push(`Requester: ${requester}`);
  if (summary.metadata?.dashboardUrl) {
    lines.push(`Dashboard: ${summary.metadata.dashboardUrl}`);
  }
  if (summary.metadata?.summaryUrl) {
    lines.push(`Summary: ${summary.metadata.summaryUrl}`);
    const reviewSummaryUrl = runSignalEvidenceUrl(summary.metadata.summaryUrl, "review-summary");
    const handoffPackageUrl = runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-package");
    const handoffFollowupsUrl = runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-runs");
    if (reviewSummaryUrl) lines.push(`Review summary: ${reviewSummaryUrl}`);
    if (handoffPackageUrl) lines.push(`Handoff package: ${handoffPackageUrl}`);
    if (handoffFollowupsUrl) lines.push(`Follow-up runs: ${handoffFollowupsUrl}`);
  }
  if (summary.metadata?.issueUrl) lines.push(`Issue: ${summary.metadata.issueUrl}`);
  else if (summary.metadata?.issue) lines.push(`Issue: ${summary.metadata.issue}`);
  if (summary.verification) {
    lines.push(`Verification: ${summary.verification.ok ? "passed" : "failed"} (exit ${summary.verification.exitCode})`);
    if (summary.verification.commands.length) {
      lines.push(`Verification commands: ${summary.verification.commands.map(inlineCode).join(", ")}`);
    }
  }
  if (summary.evaluation) {
    lines.push(`Evaluation: ${summary.evaluation.ok ? "passed" : "failed"} (exit ${summary.evaluation.exitCode})`);
    if (summary.evaluation.commands.length) {
      lines.push(`Evaluation commands: ${summary.evaluation.commands.map(inlineCode).join(", ")}`);
    }
  }
  if (summary.reviewer) {
    lines.push(`Reviewer: ${summary.reviewer.ok ? "passed" : "flagged"} (exit ${summary.reviewer.exitCode})`);
    if (summary.reviewer.commands.length) {
      lines.push(`Reviewer commands: ${summary.reviewer.commands.map(inlineCode).join(", ")}`);
    }
  }
  if (summary.review?.required) lines.push("Human review is required before merge.");
  if (summary.deployment?.required) lines.push("Deployment approval is required before production.");
  return `${lines.join("\n")}\n`;
}

function workspacePullRequestBody(request: WorkspacePullRequestRequest): string {
  const requester = formatRunRequesterSummary({
    actor: request.actor,
    role: request.role,
    clientId: request.clientId,
  });
  const lines = [
    "Created by Loom workspace handoff.",
    "",
    `Project: ${request.tenant}/${request.project}`,
    requester ? `Requester: ${requester}` : "",
    request.runId ? `Run: ${request.runId}` : "",
    `Branch: ${request.branch}`,
    request.baseBranch ? `Base: ${request.baseBranch}` : "",
    request.commit ? `Commit: ${request.commit}` : "",
    request.issueUrl ? `Issue: ${request.issueUrl}` : `Issue: ${request.issue}`,
  ];
  return `${lines.filter(Boolean).join("\n")}\n`;
}

function inlineCode(value: string): string {
  return `\`${value.replaceAll("`", "\\`")}\``;
}

function runMetadata(metadata: RunMetadata): RunMetadata | undefined {
  const compact = Object.fromEntries(Object.entries(metadata).filter(([, value]) => value !== undefined)) as RunMetadata;
  return Object.keys(compact).length > 0 ? compact : undefined;
}

function compactObject<T extends Record<string, unknown>>(value: T): T {
  return Object.fromEntries(Object.entries(value).filter(([, entry]) => entry !== undefined)) as T;
}

function runSignalFromSummary(summary: RunSummary, fallbackProject: string): RunSignal {
  return compactObject({
    ts: summary.endedAt,
    project: summary.metadata?.project ?? fallbackProject,
    runId: summary.runId,
    runDir: summary.runDir,
    status: summary.status,
    issue: summary.metadata?.issue,
    issueUrl: summary.metadata?.issueUrl,
    dashboardUrl: summary.metadata?.dashboardUrl,
    summaryUrl: summary.metadata?.summaryUrl,
    reviewSummaryUrl: summary.metadata?.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "review-summary") : undefined,
    handoffPackageUrl: summary.metadata?.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-package") : undefined,
    handoffFollowupsUrl: summary.metadata?.summaryUrl ? runSignalEvidenceUrl(summary.metadata.summaryUrl, "handoff-runs") : undefined,
    modelRequestCount: summary.modelUsage?.requestCount,
    modelPromptTokens: summary.modelUsage?.promptTokens,
    modelCompletionTokens: summary.modelUsage?.completionTokens,
    modelTotalTokens: summary.modelUsage?.totalTokens,
    modelCostUsd: summary.modelUsage?.costUsd,
    skills: summary.skills,
    outcome: summary.status === "failed" || summary.status === "error" ? "fail" as const : "pass" as const,
    failureKind: brainSignalFailureKind(summary),
    notes: brainSignalNotes(summary),
  });
}

function runSignalEvidenceUrl(summaryUrl: string, child: "review-summary" | "handoff-package" | "handoff-runs"): string | undefined {
  try {
    const url = new URL(summaryUrl);
    url.pathname = `${url.pathname.replace(/\/+$/, "")}/${child}`;
    return url.toString();
  } catch {
    return undefined;
  }
}

function brainSignalNotes(summary: RunSummary): string {
  const failure = failedGateNote("evaluation", summary.evaluation) ?? failedGateNote("verification", summary.verification);
  const suffix = brainSignalNoteSuffix(summary);
  if (failure) return `harness run ${summary.runId}: ${failure}; ${suffix}`;
  if (summary.error?.message) return `harness run ${summary.runId}: error ${summary.error.message}${brainSignalErrorDiagnostics(summary.error)}; ${suffix}`;
  if (summary.status === "error" || summary.status === "failed" || summary.status === "cancelled") {
    return `harness run ${summary.runId}: status ${summary.status}; ${suffix}`;
  }
  const evidence = brainSignalHandoffEvidence(summary);
  return evidence ? `harness run ${summary.runId}: ${evidence}; ${summary.runDir}` : `harness run ${summary.runId}: ${summary.runDir}`;
}

function brainSignalFailureKind(summary: RunSummary): string | undefined {
  return brainFailureKindForSummary(summary);
}

function failedGateNote(name: string, result: RunSummary["verification"] | RunSummary["evaluation"]): string | undefined {
  if (!result || result.ok) return undefined;
  const commands = result.commands.length ? `: ${result.commands.join("; ")}` : "";
  return `${name} failed exit ${result.exitCode}${commands}`;
}

function brainSignalErrorDiagnostics(error: NonNullable<RunSummary["error"]>): string {
  const parts = [
    error.kind ? `errorKind ${error.kind}` : undefined,
    ...brainSignalErrorDetailParts(error.details),
  ].filter((part): part is string => Boolean(part));
  return parts.length ? `; ${parts.join("; ")}` : "";
}

function brainSignalErrorDetailParts(details: Record<string, unknown> | undefined): string[] {
  if (!details) return [];
  return Object.entries(details).flatMap(([key, value]) => {
    const text = brainSignalDetailValue(value);
    return text ? [`${key}=${text}`] : [];
  });
}

function brainSignalDetailValue(value: unknown): string | undefined {
  if (typeof value === "string") return boundedBrainSignalText(value);
  if (typeof value === "number" || typeof value === "boolean") return String(value);
  return undefined;
}

function boundedBrainSignalText(value: string): string {
  const text = value.replace(/\s+/g, " ").trim();
  return text.length > 160 ? `${text.slice(0, 157)}...` : text;
}

function brainSignalNoteSuffix(summary: RunSummary): string {
  return [brainSignalHandoffEvidence(summary), summary.runDir].filter(Boolean).join("; ");
}

function brainSignalHandoffEvidence(summary: RunSummary): string | undefined {
  const metadata = summary.metadata;
  const parts = [
    reviewerNote(summary.reviewer),
    summary.review?.required ? `review ${summary.review.status}` : undefined,
    summary.deployment?.required ? `deployment ${summary.deployment.status}` : undefined,
    metadata?.pullRequestUrl ? `pullRequest ${metadata.pullRequestUrl}` : undefined,
    metadata?.pullRequestIndex !== undefined && !metadata?.pullRequestUrl ? `pullRequest #${metadata.pullRequestIndex}` : undefined,
    metadata?.branch ? `branch ${metadata.branch}` : undefined,
    metadata?.baseBranch ? `base ${metadata.baseBranch}` : undefined,
    metadata?.issueUrl ? `issue ${metadata.issueUrl}` : metadata?.issue ? `issue ${metadata.issue}` : undefined,
  ].filter((part): part is string => Boolean(part));
  return parts.length ? parts.join("; ") : undefined;
}

function reviewerNote(result: RunSummary["reviewer"]): string | undefined {
  if (!result) return undefined;
  const commands = result.commands.length ? `: ${result.commands.join("; ")}` : "";
  return `reviewer ${result.ok ? "passed" : "flagged"} exit ${result.exitCode}${commands}`;
}

interface ExecutorCliOptions {
  executor: string;
  executorImage?: string;
  executorNetwork?: string;
  executorCpus?: string;
  executorMemory?: string;
  executorPidsLimit?: string;
  executorHomeRoot?: string;
  executorWorkspace?: string;
  executorRemoteCwd: string;
  executorWorktreeCwd?: string;
  executorTemplate?: string;
  executorTemplateParam?: string[];
  executorIdeUrl?: string;
  executorPreviewUrl?: string;
  branch?: string;
  baseBranch: string;
}

function executorFactoryFromOptions(options: ExecutorCliOptions): ((cwd: string, context: HarnessWorkspaceContext) => WorkspaceExecutor) | undefined {
  requireExecutorConfiguration(options);
  if (options.executor === "local") {
    return undefined;
  }

  if (options.executor === "docker") {
    const image = options.executorImage as string;
    const network = options.executorNetwork;
    const cpus = options.executorCpus === undefined
      ? undefined
      : parsePositiveNumberFlag(options.executorCpus, "--executor-cpus");
    const memory = options.executorMemory?.trim() || undefined;
    const pidsLimit = options.executorPidsLimit === undefined
      ? undefined
      : parsePositiveIntFlag(options.executorPidsLimit, "--executor-pids-limit");
    const homeRoot = executorHomeRootFromOptions(options);
    return (cwd: string, context: HarnessWorkspaceContext) => createDockerExecutor({
      cwd,
      home: homeRoot ? dockerHomePath(homeRoot, context) : undefined,
      image,
      network: context.executorLimits?.network ?? network,
      cpus: context.executorLimits?.cpus ?? cpus,
      memory: context.executorLimits?.memory ?? memory,
      pidsLimit: context.executorLimits?.pidsLimit ?? pidsLimit,
    });
  }

  if (options.executor === "coder") {
    const workspaceTemplate = options.executorWorkspace as string;
    const repoCwdTemplate = options.executorRemoteCwd;
    const worktreeCwdTemplate = options.executorWorktreeCwd;
    const ideUrlTemplate = options.executorIdeUrl;
    const previewUrlTemplate = options.executorPreviewUrl;
    const templateParameterTemplates = options.executorTemplateParam ?? [];
    const cpus = options.executorCpus === undefined
      ? undefined
      : parsePositiveNumberFlag(options.executorCpus, "--executor-cpus");
    const memory = options.executorMemory?.trim() || undefined;
    const pidsLimit = options.executorPidsLimit === undefined
      ? undefined
      : parsePositiveIntFlag(options.executorPidsLimit, "--executor-pids-limit");
    return (_cwd: string, context: HarnessWorkspaceContext) =>
      createCoderExecutor({
        workspace: renderExecutorTemplate(workspaceTemplate, context),
        remoteCwd: renderExecutorTemplate(worktreeCwdTemplate ?? repoCwdTemplate, context),
        repoCwd: worktreeCwdTemplate ? renderExecutorTemplate(repoCwdTemplate, context) : undefined,
        template: options.executorTemplate,
        templateParameters: [
          ...templateParameterTemplates,
          ...(context.executorTemplateParameters ?? []),
        ].map((parameter) => renderExecutorTemplate(parameter, context)),
        templateResourceLimits: {
          cpus: context.executorLimits?.cpus ?? cpus,
          memory: context.executorLimits?.memory ?? memory,
          pidsLimit: context.executorLimits?.pidsLimit ?? pidsLimit,
        },
        ideUrl: ideUrlTemplate ? renderExecutorTemplate(ideUrlTemplate, context) : undefined,
        previewUrl: previewUrlTemplate ? renderExecutorTemplate(previewUrlTemplate, context) : undefined,
        repo: context.repo,
        branch: context.branch,
        baseBranch: context.baseBranch ?? options.baseBranch,
      });
  }

  console.error("--executor must be one of: local, docker, coder");
  process.exit(2);
}

function dockerHomePath(homeRoot: string, context: HarnessWorkspaceContext): string {
  const home = join(homeRoot, assertTenantName(context.tenant));
  mkdirSync(home, { recursive: true });
  return home;
}

function executorHomeRootFromOptions(options: Pick<ExecutorCliOptions, "executorHomeRoot">): string | undefined {
  return options.executorHomeRoot?.trim() ? resolve(options.executorHomeRoot.trim()) : undefined;
}

function renderExecutorTemplate(template: string, context: HarnessWorkspaceContext): string {
  const rendered = template
    .replaceAll("{tenant}", context.tenant)
    .replaceAll("{project}", context.project)
    .replaceAll("{runId}", context.runId)
    .replaceAll("{cwdBase}", basename(context.cwd));
  if (/\{[^}]+\}/.test(rendered)) {
    console.error(`unresolved executor template value: ${template}`);
    process.exit(2);
  }
  return rendered;
}
